INSERT INTO `dataproduk` (`COL 1`, `COL 2`, `COL 3`, `COL 4`, `COL 5`, `COL 6`, `COL 7`, `COL 8`, `COL 9`, `COL 10`, `COL 11`, `COL 12`, `COL 13`, `COL 14`, `COL 15`, `COL 16`, `COL 17`) VALUES
('produk_id', 'nama_produk', 'kategori', 'tanaman_target', 'fase_aplikasi', 'hama_penyakit', 'media_tanam', 'dosis_pemakaian', 'keyword', 'deskripsi', 'harga', 'stok', 'satuan', 'gambar', 'status', 'created at', 'jumlah_ulasan'),
('1', 'Herbisida Topzone', 'Herbisida', 'Padi, Jagung, Kelapa Sawit, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kering', 'Dosis umum:\r\n1.5 â€“ 3 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter air per hektar\r\n\r\nGulma ringan:\r\n1.5 liter per hektar\r\n\r\nGulma sedang:\r\n2 liter per hektar\r\n\r\nGulma lebat:\r\n3 liter per hektar\r\n\r\nWaktu aplikasi:\r\nSaat gulma aktif tumbuh dan memiliki daun yang cukup untuk terkena semprotan.', 'herbisida rumput,\r\nobat rumput liar,\r\nobat gulma,\r\npembasmi gulma,\r\nracun rumput,\r\nobat teki,\r\nobat teki-tekian,\r\nobat rumput sawah,\r\nobat rumput jagung,\r\nobat rumput sawit,\r\nobat rumput kopi,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar,\r\nrumput bandel,\r\ngulma kebun,\r\npembersih lahan,\r\npersiapan lahan tanam,\r\nherbisida kontak,\r\nsistem tanpa olah tanah,', 'Topzone 276 SL merupakan herbisida kontak berbahan aktif parakuat diklorida 276 g/L yang digunakan untuk membasmi gulma dan rumput liar pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini efektif digunakan sebagai pembasmi gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan padi, jagung, kelapa sawit, dan kopi.\r\n\r\nGejala yang dapat ditangani antara lain lahan ditumbuhi rumput liar, gulma mengganggu pertumbuhan tanaman, rumput bandel di kebun, serta kebutuhan pembersihan lahan sebelum tanam.\r\n\r\nTopzone 276 SL bekerja cepat pada bagian gulma yang terkena semprotan sehingga cocok digunakan untuk sistem tanpa olah tanah dan persiapan lahan tanam.', 'Rp.80.000', '20', '1liter', '-', 'Tersedia', '03/05/2026 23:10:07', ''),
('2', 'Roundap Herbisida', 'Herbisida', 'Padi, Jagung, Kelapa Sawit, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kosong', 'Dosis semprot:\r\n12 â€“ 15 ml per liter air\r\n\r\nDosis lapangan:\r\n4 â€“ 10 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter per hektar\r\n\r\nGulma ringan:\r\n4 â€“ 6 liter per hektar\r\n\r\nGulma lebat:\r\n8 â€“ 10 liter per hektar', 'obat rumput sampai akar,\r\npembasmi gulma sampai akar,\r\nobat rumput liar,\r\nobat gulma sawah,\r\nobat gulma kebun,\r\nobat teki,\r\nobat rumput bandel,\r\nracun rumput,\r\nherbisida sistemik,\r\nrumput tidak mati,\r\nrumput tumbuh lagi,\r\nmembersihkan lahan,\r\npersiapan tanam,\r\nobat gulma sawit,\r\nobat gulma kopi,\r\nobat gulma jagung,\r\nobat gulma padi,\r\ngulma daun lebar,\r\ngulma daun sempit', 'Roundup merupakan herbisida sistemik berbahan aktif glifosat yang digunakan untuk membasmi gulma hingga ke akar.\r\n\r\nProduk ini efektif digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan pertanian maupun perkebunan.\r\n\r\nCocok digunakan untuk persiapan lahan padi, jagung, kelapa sawit, kopi, serta pembersihan lahan kosong sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain rumput liar yang sulit mati, gulma tumbuh kembali setelah dibersihkan, teki-tekian yang menyebar luas, dan lahan yang dipenuhi gulma.\r\n\r\nRoundup bekerja secara sistemik sehingga diserap melalui daun dan diteruskan hingga ke akar untuk membunuh gulma secara menyeluruh.', 'Rp.90.000', '30', '1liter', '-', 'Tersedia', '03/05/2026 23:16:09', ''),
('3', 'Healthy, Fungisida anti busuk daun dan patek', 'Fungisida', 'Cabai, Tomat, Terong, Padi, Semangka, Melon, Timun, Sayuran', 'Awal Vegetatif, Vegetatif', 'Busuk Daun, Patek, Hawar Daun, Jamur Daun', 'Tanah, Sawah, Lahan Terbuka', 'untuk tanaman cabe, tomat, terong 1-3ml/L dengan volume semprot 500 Liter air /Ha waktu pengaplikasian 2 minggu setelah tanam.', 'fungisida busuk daun,\r\nobat busuk daun,\r\nanti busuk daun,\r\nobat patek,\r\nfungisida patek,\r\nanti patek cabai,\r\nobat bercak daun,\r\nfungisida bercak daun,\r\nobat jamur tanaman,\r\nfungisida jamur daun,\r\nobat daun menghitam,\r\nobat daun bercak coklat,\r\nobat penyakit daun,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida terong,\r\nfungisida padi,\r\nfungisida semangka,\r\nfungisida melon,\r\nfungisida timun,\r\nobat hawar daun,\r\npengendali penyakit jamur,\r\npengendali busuk daun', 'Healthy merupakan fungisida berbahan aktif tembaga dan cymoxanil yang digunakan untuk mengendalikan penyakit busuk daun, patek, bercak daun, hawar daun, dan penyakit akibat jamur pada tanaman cabai, tomat, terong, padi, semangka, melon, timun, dan berbagai jenis sayuran.\r\nProduk ini cocok digunakan sebagai fungisida busuk daun, obat patek cabai, anti busuk daun tomat, pengendali penyakit jamur daun, serta pencegah penyebaran penyakit pada fase awal pertumbuhan tanaman.\r\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menghitam, daun menguning akibat jamur, patek pada buah cabai, busuk daun pada tomat, dan penyakit daun pada tanaman hortikultura.\r\nCocok diaplikasikan mulai dua minggu setelah tanam pada fase vegetatif untuk mencegah dan mengendalikan infeksi jamur.\r\nDosis aplikasi cabai, tomat, dan terong 1 sampai 3 ml per liter air. Dosis aplikasi padi, semangka, melon, timun, dan sayuran 1 sampai 2 ml per liter air.', 'Rp.35.000', '5', '100ml', '-', 'Tersedia', '06/04/2026 14:01:11', ''),
('4', 'Dorum - Deltagro', 'Fungisida', 'Cabai, Kentang, Jagung, Padi', 'Vegetatif, Generatif, Pencegahan Penyakit', 'Antraknosa, Patek, Bercak Coklat, Hawar Daun, Karat Daun, Busuk Daun', 'Sawah, Lahan Terbuka, Tanah', '0,5ml/L dengan penyemprotan volume tinggi. waktu aplikasi sebelum ada gejala serangan penyakit dan diulang 1 minggu sekali', 'fungisida antraknosa,\r\nfungisida patek,\r\nobat patek cabai,\r\nobat antraknosa cabai,\r\nanti patek,\r\nanti antraknosa,\r\nobat bercak coklat,\r\nfungisida bercak coklat,\r\nobat hawar daun,\r\nfungisida hawar daun,\r\nobat karat daun,\r\nfungisida karat daun,\r\nobat busuk daun,\r\nfungisida busuk daun,\r\npenyakit daun jagung,\r\npenyakit daun padi,\r\nbercak daun padi,\r\nbercak daun kentang,\r\njamur tanaman,\r\nobat jamur tanaman,\r\nfungisida sistemik,\r\nzpt tanaman,\r\nperangsang pertumbuhan tanaman', 'Dorum 350 SC merupakan fungisida sistemik berbahan aktif azoksistrobin 350 g/L yang digunakan untuk mengendalikan penyakit jamur pada tanaman cabai, kentang, jagung, dan padi.\r\nProduk ini efektif sebagai fungisida antraknosa, fungisida patek, fungisida bercak coklat, fungisida hawar daun, fungisida karat daun, dan fungisida busuk daun.\r\nDapat digunakan untuk mengatasi penyakit patek pada cabai, bercak coklat pada kentang dan padi, hawar daun pada jagung dan padi, karat daun pada jagung, serta busuk daun akibat infeksi jamur.\r\nSelain sebagai fungisida, Dorum 350 SC memiliki efek zat pengatur tumbuh yang membantu meningkatkan pertumbuhan tanaman, memperbaiki kesehatan tanaman, meningkatkan kualitas hasil panen, dan menambah bobot panen.\r\nAplikasi dilakukan sebelum muncul gejala penyakit sebagai tindakan pencegahan maupun saat gejala awal serangan penyakit muncul. Dosis penggunaan 0.5 ml per liter air dengan interval aplikasi 7 hari.', 'Rp.60.000', '10', '200ml', '-', 'Tersedia', '06/04/2026 21:08:05', ''),
('5', 'Rootone-F - Spesialis peningkat bobot - ZPT Organik', 'Fungisida', 'Bawang Merah, Bawang Putih, Cabai, Jagung, Jeruk, Kacang Panjang, Kedelai, Kelapa Sawit, Kentang, Mangga, Padi, Semangka, Tembakau, Tomat, Apel', 'Vegetatif, Generatif', 'Bercak Ungu, Bercak Daun, Hawar Daun, Embun Tepung, Penyakit Tepung, Karat Daun, Bercak Kering, Antraknosa, Busuk Batang, Hawar Pelepah, Blas, Busuk Buah, Busuk Daun', 'Sawah, Kebun, Tanah, Lahan Terbuka', 'Untuk tanaman berumur 6 bulan: Kurang lebih 50mg/stump\nUntuk tanaman berumur 12 bulan: Kurang lebih 100mg/stump\nUntuk tanaman berumur 18 bulan: Kurang lebih 150mg/stump\nUntuk tanaman berumur 24 bulan: Kurang lebih 200mg/stump\nUntuk tanaman berumur 36 bulan: Kurang lebih 300mg/stump', '', '', 'Rp.56.000', '5', '250ml', '-', 'Tersedia', '06/04/2026 21:17:45', ''),
('6', 'Scoore 250 EC - Fungisida', 'Fungisida', 'Bawang Merah, Bawang Putih, Cabai, Jagung, Jeruk, Kacang Panjang, Kedelai, Kelapa Sawit, Kentang, Mangga, Padi, Semangka, Tembakau, Tomat, Apel', 'Vegetatif, Generatif', 'Bercak Ungu, Bercak Daun, Hawar Daun, Embun Tepung, Penyakit Tepung, Karat Daun, Bercak Kering, Antraknosa, Busuk Batang, Hawar Pelepah, Blas, Busuk Buah, Busuk Daun', 'Sawah, Kebun, Tanah, Lahan Terbuka', 'Dosis Pemakaian Score 250 EC\r\nApel : penyakit tepung Phodopshaera leucotricha (Penyemprotan volume tinggi : 5 â€“ 10 ml/100 l)\r\nBawang merah : penyakit bercak ungu Alternaria porri (Penyemprotan volume tinggi : 0,25 â€“ 0,5 ml/l)\r\nBawang putih : penyakit bercak ungu Alternaria porri (Penyemprotan volume tinggi : 0,4 â€“ 0,8 ml/l)\r\nCabai : penyakit bercak daun Cercospora capsici (Penyemprotan volume tinggi : 0,25 â€“ 0,5 ml/l)\r\nJagung : penyakit hawar daun Helminthosporium turcicum (Penyemprotan volume tinggi : 0,25 â€“ 0,50 ml/l)\r\nJarak Pagar : penyakit embun tepung Oidium sp. (Penyemprotan volume tinggi : 0,75 â€“ 1 ml/l)\r\nJeruk : penyakit tepung Oidium sp. (Penyemprotan volume tinggi : 0,5 â€“ 1 ml/l)\r\nKacang panjang : penyakit bercak daun Cercospora sp., penyakit karat daun Uromyces sp. (Penyemprotan volume tinggi : 0,5 â€“ 1 ml/l)\r\nKedelai : penyakit bercak kering Cercospora sp. (Penyemprotan volume tinggi : 0,25 â€“ 0,50 ml/l)\r\nKelapa sawit : penyakit daun pembibitan Curvularia maculans, Pestalotiopsis palmarum (Penyemprotan volume tinggi : 1 â€“ 1,5 ml/l)\r\nKentang : penyakit bercak kering Alternaria solani (Penyemprotan volume tinggi : 0,75 â€“ 1 l/ha)\r\nMangga : penyakit antraknosa Colletotrichum gloeosporioides, penyakit bercak daun Stigmina mangifarae (Penyemprotan volume tinggi : 0,25 â€“ 0,50 ml/l)\r\nPadi : penyakit busuk batang Helminthosporium sigmoidum, penyakit hawar pelepah Rhizoctonia solani, penyakit bercak daun Cercospora sp. (Penyemprotan volume tinggi : 400 ml/ha)\r\nPadi : penyakit blas Pyricularia oryzae (Penyemprotan volume tinggi : 300 â€“ 480 ml/ha)\r\nSemangka : penyakit bercak daun Cercospora sp. (Penyemprotan volume tinggi : 0,5 â€“ 1 ml/l)\r\nTembakau : penyakit patik daun Cercospora nicotianae (Penyemprotan volume tinggi : 0,25 â€“ 0,50 ml/l)\r\nTomat : penyakit bercak kering Alternaria solani (Penyemprotan volume tinggi : 0,5 â€“ 1 ml/l)\r\nTomat : penyakit busuk Septoria lycopersici (Penyemprotan volume tinggi : 0,25 â€“ 0,5 ml/l)', 'fungisida bercak daun,\r\nobat bercak daun,\r\nobat daun bercak,\r\nfungisida bercak ungu,\r\nobat bercak ungu,\r\nfungisida hawar daun,\r\nobat hawar daun,\r\nfungisida blas,\r\nobat blas padi,\r\nfungisida antraknosa,\r\nobat antraknosa mangga,\r\nobat patek,\r\nfungisida embun tepung,\r\nobat embun tepung,\r\nfungisida penyakit tepung,\r\nobat karat daun,\r\nfungisida karat daun,\r\nfungisida busuk batang,\r\nobat busuk batang,\r\nfungisida busuk daun,\r\nfungisida busuk tomat,\r\nfungisida sistemik,\r\nobat jamur tanaman,\r\npengendali penyakit jamur,\r\nzpt tanaman', 'Score 250 EC merupakan fungisida sistemik berbahan aktif difenokonazol 250 g/L yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman hortikultura, perkebunan, dan tanaman pangan.\r\n\r\nProduk ini efektif digunakan sebagai fungisida bercak daun, fungisida bercak ungu, fungisida hawar daun, fungisida embun tepung, fungisida antraknosa, fungisida karat daun, fungisida busuk batang, fungisida hawar pelepah, fungisida blas padi, dan fungisida busuk daun.\r\n\r\nDapat digunakan pada tanaman cabai, bawang merah, bawang putih, tomat, kentang, jagung, padi, mangga, semangka, kacang panjang, kedelai, jeruk, apel, kelapa sawit, dan tembakau.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak daun, bercak ungu, daun menguning akibat jamur, hawar daun, embun tepung, karat daun, busuk batang, busuk buah, busuk daun, dan penyakit blas pada padi.\r\n\r\nSelain mengendalikan penyakit jamur, Score 250 EC mengandung zat pengatur tumbuh yang membantu meningkatkan kualitas tanaman, memperbaiki kesehatan tanaman, dan meningkatkan hasil panen.', 'Rp.35.000', '15', '50ml', '-', 'Tersedia', '06/04/2026 21:24:44', ''),
('7', 'Sidafos 480 SL â€“ Herbisida Sistemik Pembasmi Gulma', 'Herbisida', 'Padi, Sawit, Karet, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kosong', 'Dosis semprot:\r\n10 â€“ 20 ml per liter air\r\n\r\nDosis lapangan:\r\n4 â€“ 8 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter per hektar\r\n\r\nGulma ringan:\r\n4 liter per hektar\r\n\r\nGulma sedang:\r\n6 liter per hektar\r\n\r\nGulma lebat:\r\n8 liter per hektar', 'obat gulma,\r\nobat rumput liar,\r\nobat rumput sampai akar,\r\nherbisida sistemik,\r\npembasmi gulma,\r\nracun rumput,\r\nobat teki,\r\nobat teki-tekian,\r\nobat rumput sawah,\r\nobat rumput kebun,\r\nmembersihkan lahan,\r\npersiapan lahan,\r\nobat gulma sawit,\r\nobat gulma kopi,\r\nobat gulma karet,\r\nsistem tanpa olah tanah,\r\nTOT,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput bandel', 'Sidafos 480 SL merupakan herbisida sistemik berbahan aktif glifosat 480 g/L yang digunakan untuk membasmi gulma hingga ke akar.\r\n\r\nProduk ini efektif digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan sawah maupun perkebunan.\r\n\r\nCocok digunakan untuk persiapan lahan, sistem tanpa olah tanah, pengendalian gulma pada perkebunan sawit, kopi, karet, dan lahan pertanian lainnya.\r\n\r\nGejala yang dapat ditangani antara lain rumput liar yang tumbuh berlebihan, gulma yang sulit dikendalikan, teki-tekian yang menyebar luas, dan kebutuhan pembersihan lahan sebelum tanam.\r\n\r\nSidafos 480 SL bekerja secara sistemik dengan cara diserap daun dan diteruskan ke seluruh jaringan hingga akar sehingga gulma mati secara menyeluruh dan tidak mudah tumbuh kembali.', 'Rp.80.000', '20', '1liter', '-', 'Tersedia', '03/05/2026 23:19:48', ''),
('8', 'Anthracol 70 WP + Zinc', 'Fungisida', 'Cabai, Tomat, Padi, Jagung, Kentang, Ketimun, Semangka, Bawang Merah, Bawang Putih, Kedelai, Kacang Panjang, Anggrek, Krisan, Aglaonema, Tanaman Hias', 'Vegetatif, Generatif, Pencegahan Penyakit', 'Bercak Daun, Busuk Daun, Busuk Akar, Busuk Batang, Busuk Hitam, Karat Daun, Busuk Kaki, Penyakit Jamur', 'Sawah, Kebun, Lahan Terbuka, Pot, Polybag', 'Dosis disesuaikan dengan jenis tanaman dan umur tanaman sesuai petunjuk kemasan.\r\n\r\nCara aplikasi:\r\n- Larutkan Anthracol 70 WP ke dalam air hingga tercampur merata.\r\n- Semprotkan ke seluruh bagian tanaman menggunakan sprayer.\r\n- Tambahkan perekat atau pembasah apabila diperlukan.\r\n- Aplikasi dilakukan sejak gejala awal atau sebagai pencegahan penyakit.\r\n\r\nWaktu aplikasi:\r\n- Pagi hari atau sore hari.\r\n- Dapat digunakan pada musim hujan maupun musim kemarau.\r\n- Interval aplikasi menyesuaikan tingkat serangan penyakit.', 'fungisida bercak daun,\r\nobat bercak daun,\r\nfungisida busuk daun,\r\nobat busuk daun,\r\nfungisida busuk akar,\r\nobat busuk akar,\r\nfungisida busuk batang,\r\nobat busuk batang,\r\nfungisida busuk hitam,\r\nobat busuk hitam,\r\nfungisida karat daun,\r\nobat karat daun,\r\nfungisida tanaman hias,\r\nobat jamur tanaman hias,\r\nfungisida anggrek,\r\nfungisida krisan,\r\nfungisida aglaonema,\r\nobat daun menguning,\r\nobat daun bercak coklat,\r\nobat jamur tanaman,\r\nfungisida preventif,\r\nfungisida kontak,\r\nfungisida protektif,\r\nfungisida musim hujan', 'Anthracol 70 WP merupakan fungisida kontak berbahan aktif propineb 70 persen yang digunakan untuk mencegah dan mengendalikan berbagai penyakit jamur pada tanaman pangan, hortikultura, perkebunan, tanaman buah, dan tanaman hias.\nProduk ini efektif digunakan sebagai fungisida bercak daun, fungisida busuk daun, fungisida busuk akar, fungisida busuk batang, fungisida busuk hitam, fungisida karat daun, dan pengendali berbagai penyakit akibat jamur.\nDapat digunakan pada tanaman cabai, tomat, padi, jagung, kentang, ketimun, semangka, bawang merah, bawang putih, kedelai, kacang panjang, anggrek, krisan, aglaonema, dan tanaman hias lainnya.\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menguning akibat jamur, busuk batang, busuk akar, karat daun, busuk hitam, dan berbagai penyakit cendawan.\nAnthracol 70 WP juga mengandung unsur hara zinc yang membantu menjaga kesehatan tanaman dan mendukung pertumbuhan yang optimal.', 'Rp.70.000', '5', '500gr', '-', 'Tersedia', '18/04/2026 22:31:16', ''),
('9', 'Acrobat 50 WP', 'Fungisida', 'Tomat, Cabai, Kentang, Tembakau, Semangka, Jagung', 'Vegetatif, Generatif', 'Busuk Daun, Bercak Daun, Lanas, Embun Bulu, Bulai', 'Sawah, Kebun, Lahan Terbuka', 'Tomat:\r\nBusuk daun â†’ 0.5 â€“ 1 g/L air\r\nCabai:\r\nBercak daun â†’ 2 â€“ 4 g/L air\r\nKentang:\r\nBusuk daun â†’ 0.5 â€“ 0.625 g/L air\r\nTembakau:\r\nLanas â†’ 1 â€“ 1.25 g/L air\r\nSemangka:\r\nEmbun bulu â†’ 0.25 â€“ 0.5 g/L air\r\nJagung:\r\nBulai â†’ 1.25 â€“ 2.5 g/kg benih\r\n\r\nWaktu aplikasi:\r\n- Umur tanaman 21â€“70 HST\r\n- Dilakukan saat ditemukan gejala penyakit\r\n- Kelembaban di atas 90 persen\r\n- Interval penyemprotan 7â€“14 hari', 'fungisida busuk daun,\r\nobat busuk daun,\r\nfungisida bulai,\r\nobat bulai jagung,\r\nfungisida embun bulu,\r\nobat embun bulu,\r\nfungisida bercak daun,\r\nobat bercak daun cabai,\r\nfungisida lanas,\r\nobat lanas tembakau,\r\nfungisida phytophthora,\r\nobat phytophthora,\r\nfungisida jamur tanaman,\r\nobat daun membusuk,\r\nobat daun menghitam,\r\nfungisida sistemik,\r\nfungisida tomat,\r\nfungisida kentang,\r\nfungisida jagung,\r\npengendali penyakit jamur', 'Acrobat 50 WP merupakan fungisida sistemik berbahan aktif dimetomorf 50 persen yang digunakan untuk mengendalikan berbagai penyakit jamur dan cendawan pada tanaman hortikultura dan tanaman pangan.\r\nProduk ini efektif digunakan sebagai fungisida busuk daun, fungisida bercak daun, fungisida embun bulu, fungisida bulai jagung, dan fungisida lanas tembakau.\r\nDapat digunakan pada tanaman tomat, cabai, kentang, semangka, jagung, dan tembakau.\r\nGejala yang dapat dikendalikan antara lain daun membusuk, bercak daun, daun menghitam, busuk daun, embun bulu, penyakit bulai, dan penyakit akibat infeksi jamur phytophthora.\r\nAcrobat 50 WP bekerja secara sistemik lokal sehingga mampu menghentikan perkembangan jamur pada jaringan tanaman dan melindungi pertumbuhan tanaman yang sehat.', 'Rp.15.000', '10', '10gr', '-', 'Tersedia', '18/04/2026 22:37:26', ''),
('10', 'Fungisida Daconil 75WP Solusi Ampuh Basmi Jamur dan Penyakit Tanaman', 'Fungisida', 'Bawang Merah, Cabai, Tomat, Kentang, Kacang-kacangan', 'Vegetatif, Generatif, Pencegahan Penyakit', 'Embun Bulu, Bercak Daun, Busuk Daun, Antraknosa, Patek, Busuk Buah, Karat Daun, Bercak Ungu', 'Sawah, Kebun, Lahan Terbuka', 'Dosis umum:\r\n1.5 â€“ 2 gram per liter air\r\n\r\nCara aplikasi:\r\n- Semprotkan merata ke seluruh bagian tanaman.\r\n- Fokus pada bagian bawah daun yang rentan infeksi jamur.\r\n- Aplikasi dilakukan pagi atau sore hari.\r\n\r\nInterval:\r\n7 â€“ 10 hari sekali\r\n\r\nPada musim hujan atau tingkat serangan tinggi:\r\nInterval dapat diperpendek sesuai kondisi lapangan.', 'fungisida patek,\r\nobat patek cabai,\r\nfungisida antraknosa,\r\nobat antraknosa,\r\nfungisida busuk buah,\r\nobat busuk buah,\r\nfungisida busuk daun,\r\nobat busuk daun,\r\nfungisida embun bulu,\r\nobat embun bulu,\r\nfungisida bercak daun,\r\nobat bercak daun,\r\nfungisida bercak ungu,\r\nobat bercak ungu bawang,\r\nfungisida karat daun,\r\nobat karat daun,\r\nfungisida musim hujan,\r\nobat jamur tanaman,\r\nfungisida kontak,\r\nfungisida protektif,\r\npengendali penyakit jamur', 'Daconil 75 WP merupakan fungisida kontak berbahan aktif klorotalonil 75 persen yang digunakan untuk mencegah dan mengendalikan berbagai penyakit jamur pada tanaman hortikultura dan tanaman pangan.\r\n\r\nProduk ini efektif digunakan sebagai fungisida patek, fungisida antraknosa, fungisida busuk buah, fungisida busuk daun, fungisida embun bulu, fungisida bercak daun, fungisida bercak ungu, dan fungisida karat daun.\r\n\r\nDapat digunakan pada tanaman cabai, tomat, kentang, bawang merah, dan berbagai jenis kacang-kacangan.\r\n\r\nGejala yang dapat dikendalikan antara lain patek pada cabai, busuk buah, daun bercak coklat, embun bulu, bercak ungu bawang merah, karat daun, dan berbagai penyakit akibat infeksi jamur.\r\n\r\nDaconil 75 WP bekerja secara protektif sebagai pelindung tanaman sehingga sangat cocok digunakan untuk pencegahan penyakit terutama pada musim hujan dan kondisi kelembaban tinggi.', 'Rp105.000', '10', '500 gram', '-', 'Tersedia', '03/05/2026 20:46:43', ''),
('11', 'Herbisida Topzone', 'Herbisida', 'Padi, Jagung, Kelapa Sawit, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kering', 'Dosis umum:\r\n1.5 â€“ 3 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter air per hektar\r\n\r\nGulma ringan:\r\n1.5 liter per hektar\r\n\r\nGulma sedang:\r\n2 liter per hektar\r\n\r\nGulma lebat:\r\n3 liter per hektar\r\n\r\nWaktu aplikasi:\r\nSaat gulma aktif tumbuh dan memiliki daun yang cukup untuk terkena semprotan.', 'herbisida rumput,\r\nobat rumput liar,\r\nobat gulma,\r\npembasmi gulma,\r\nracun rumput,\r\nobat teki,\r\nobat teki-tekian,\r\nobat rumput sawah,\r\nobat rumput jagung,\r\nobat rumput sawit,\r\nobat rumput kopi,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar,\r\nrumput bandel,\r\ngulma kebun,\r\npembersih lahan,\r\npersiapan lahan tanam,\r\nherbisida kontak,\r\nsistem tanpa olah tanah,', 'Topzone 276 SL merupakan herbisida kontak berbahan aktif parakuat diklorida 276 g/L yang digunakan untuk membasmi gulma dan rumput liar pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini efektif digunakan sebagai pembasmi gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan padi, jagung, kelapa sawit, dan kopi.\r\n\r\nGejala yang dapat ditangani antara lain lahan ditumbuhi rumput liar, gulma mengganggu pertumbuhan tanaman, rumput bandel di kebun, serta kebutuhan pembersihan lahan sebelum tanam.\r\n\r\nTopzone 276 SL bekerja cepat pada bagian gulma yang terkena semprotan sehingga cocok digunakan untuk sistem tanpa olah tanah dan persiapan lahan tanam.', 'Rp.80.000', '20', '1liter', '-', 'Tersedia', '03/05/2026 23:10:07', ''),
('12', 'Rumpas 120EW 100ML', 'Herbisida', 'Padi Sawah', 'Awal Pertumbuhan Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah', 'Dosis semprot:\r\n0.5 â€“ 1 ml per liter air\r\n\r\nDosis lapangan:\r\n100 â€“ 200 ml per hektar\r\n\r\nWaktu aplikasi:\r\nPada fase awal pertumbuhan gulma.\r\n\r\nKondisi aplikasi:\r\nDisemprot saat air sawah dangkal atau macak-macak.\r\n\r\nFrekuensi:\r\nUmumnya 1 kali aplikasi per musim tanam.', 'herbisida padi,\r\nobat gulma padi,\r\nobat rumput sawah,\r\nracun rumput sawah,\r\nobat teki sawah,\r\nobat teki-tekian,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar sawah,\r\nrumput bandel sawah,\r\nlahan padi banyak rumput,\r\ngulma mengganggu padi,\r\nmembersihkan gulma sawah,\r\nobat gulma sampai akar,\r\nherbisida sistemik,\r\npenoxsulam,\r\nobat gulma awal tanam,\r\ngulma tumbuh cepat,\r\nrumput susah mati,\r\npembersih lahan sawah', 'Rumpas 120 EW merupakan herbisida sistemik berbahan aktif penoxsulam 120 g/L yang digunakan untuk mengendalikan gulma pada tanaman padi sawah.\r\n\r\nProduk ini efektif digunakan untuk membasmi gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian yang sering tumbuh pada lahan sawah.\r\n\r\nGejala yang dapat ditangani antara lain sawah dipenuhi rumput liar, gulma mengganggu pertumbuhan padi, teki-tekian menyebar luas, serta rumput bandel yang sulit dikendalikan.\r\n\r\nRumpas 120 EW bekerja secara sistemik melalui daun dan akar gulma sehingga gulma menguning, berhenti tumbuh, dan mati hingga ke jaringan tanaman.', 'Rp.50.000', '7', '100ml', '-', 'Tersedia', '04/05/2026 11:40:36', ''),
('13', 'Roundap Herbisida', 'Herbisida', 'Padi, Jagung, Kelapa Sawit, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kosong', 'Dosis semprot:\r\n12 â€“ 15 ml per liter air\r\n\r\nDosis lapangan:\r\n4 â€“ 10 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter per hektar\r\n\r\nGulma ringan:\r\n4 â€“ 6 liter per hektar\r\n\r\nGulma lebat:\r\n8 â€“ 10 liter per hektar', 'obat rumput sampai akar,\r\npembasmi gulma sampai akar,\r\nobat rumput liar,\r\nobat gulma sawah,\r\nobat gulma kebun,\r\nobat teki,\r\nobat rumput bandel,\r\nracun rumput,\r\nherbisida sistemik,\r\nrumput tidak mati,\r\nrumput tumbuh lagi,\r\nmembersihkan lahan,\r\npersiapan tanam,\r\nobat gulma sawit,\r\nobat gulma kopi,\r\nobat gulma jagung,\r\nobat gulma padi,\r\ngulma daun lebar,\r\ngulma daun sempit', 'Roundup merupakan herbisida sistemik berbahan aktif glifosat yang digunakan untuk membasmi gulma hingga ke akar.\r\n\r\nProduk ini efektif digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan pertanian maupun perkebunan.\r\n\r\nCocok digunakan untuk persiapan lahan padi, jagung, kelapa sawit, kopi, serta pembersihan lahan kosong sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain rumput liar yang sulit mati, gulma tumbuh kembali setelah dibersihkan, teki-tekian yang menyebar luas, dan lahan yang dipenuhi gulma.\r\n\r\nRoundup bekerja secara sistemik sehingga diserap melalui daun dan diteruskan hingga ke akar untuk membunuh gulma secara menyeluruh.', 'Rp.90.000', '30', '1liter', '-', 'Tersedia', '03/05/2026 23:16:09', ''),
('14', 'Sidafos 480 SL â€“ Herbisida Sistemik Pembasmi Gulma', 'Herbisida', 'Padi, Sawit, Karet, Kopi', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Kosong', 'Dosis semprot:\r\n10 â€“ 20 ml per liter air\r\n\r\nDosis lapangan:\r\n4 â€“ 8 liter per hektar\r\n\r\nVolume air:\r\n200 â€“ 400 liter per hektar\r\n\r\nGulma ringan:\r\n4 liter per hektar\r\n\r\nGulma sedang:\r\n6 liter per hektar\r\n\r\nGulma lebat:\r\n8 liter per hektar', 'obat gulma,\r\nobat rumput liar,\r\nobat rumput sampai akar,\r\nherbisida sistemik,\r\npembasmi gulma,\r\nracun rumput,\r\nobat teki,\r\nobat teki-tekian,\r\nobat rumput sawah,\r\nobat rumput kebun,\r\nmembersihkan lahan,\r\npersiapan lahan,\r\nobat gulma sawit,\r\nobat gulma kopi,\r\nobat gulma karet,\r\nsistem tanpa olah tanah,\r\nTOT,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput bandel', 'Sidafos 480 SL merupakan herbisida sistemik berbahan aktif glifosat 480 g/L yang digunakan untuk membasmi gulma hingga ke akar.\r\n\r\nProduk ini efektif digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian pada lahan sawah maupun perkebunan.\r\n\r\nCocok digunakan untuk persiapan lahan, sistem tanpa olah tanah, pengendalian gulma pada perkebunan sawit, kopi, karet, dan lahan pertanian lainnya.\r\n\r\nGejala yang dapat ditangani antara lain rumput liar yang tumbuh berlebihan, gulma yang sulit dikendalikan, teki-tekian yang menyebar luas, dan kebutuhan pembersihan lahan sebelum tanam.\r\n\r\nSidafos 480 SL bekerja secara sistemik dengan cara diserap daun dan diteruskan ke seluruh jaringan hingga akar sehingga gulma mati secara menyeluruh dan tidak mudah tumbuh kembali.', 'Rp.80.000', '20', '1liter', '-', 'Tersedia', '03/05/2026 23:19:48', ''),
('15', 'Dupont Ammate 150 EC 50 ml â€“ Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Tanaman Pangan, Lahan Kosong', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Terbuka', 'Dosis pemakaian Dupont Ammate 150 EC umumnya berkisar 1 â€“ 2 ml per liter air, atau sekitar 2 â€“ 4 liter per hektar, tergantung kepadatan gulma', 'herbisida gulma,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput liar,\r\nobat teki teki,\r\nherbisida teki teki,\r\nobat gulma sawah,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat lahan penuh rumput,\r\npengendali gulma,\r\nobat rumput liar,\r\npembersih lahan,\r\nherbisida pra tanam,\r\nobat lahan sebelum tanam,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar kebun,\r\nobat alang alang,\r\nherbisida perkebunan', 'Dupont Ammate 150 EC merupakan herbisida yang digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki teki pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini sering digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, herbisida sawit, herbisida karet, dan pembersih lahan sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain lahan dipenuhi rumput liar, pertumbuhan gulma yang mengganggu tanaman utama, serta infestasi teki teki pada area perkebunan dan pertanian.\r\n\r\nCocok digunakan pada tahap persiapan lahan dan sistem tanpa olah tanah sebelum proses budidaya dimulai.', 'Rp.60.000', '7', '50ml', '-', 'Tersedia', '04/05/2026 21:53:56', ''),
('16', 'Topdor 10 WP 100 g â€“ Fungisida Sistemik', 'Fungisida', 'Cabai, Tomat, Kubis, Sawi, Tanaman Hortikultura, Tanaman Perkebunan', 'Vegetatif, Generatif', 'Embun Tepung, Bercak Daun, Karat Daun, Busuk Daun, Antraknosa', 'Kebun, Sawah, Polybag, Greenhouse', 'Dosis semprot:\r\n0.5 â€“ 1 gram per liter air\r\n\r\nDosis tangki:\r\n5 â€“ 10 gram per tangki 14â€“16 liter\r\n\r\nDosis lapangan:\r\n0.5 â€“ 1 kg per hektar\r\n\r\nFrekuensi:\r\n7 â€“ 10 hari sekali\r\n\r\nWaktu aplikasi:\r\nSaat gejala penyakit mulai muncul atau sebagai pencegahan.', 'fungisida embun tepung,\r\nobat embun tepung,\r\nfungisida bercak daun,\r\nobat bercak daun,\r\nfungisida karat daun,\r\nobat karat daun,\r\nfungisida busuk daun,\r\nobat busuk daun,\r\nfungisida antraknosa,\r\nobat patek,\r\nobat daun bercak coklat,\r\ndaun berjamur,\r\ndaun putih bertepung,\r\ndaun mengering,\r\nbusuk daun cabai,\r\nbusuk daun tomat,\r\nfungisida sistemik,\r\nobat jamur tanaman,\r\nfungisida cabai,\r\nfungisida tomat', 'Topdor 10 WP merupakan fungisida sistemik berbahan aktif hexaconazole 10 persen yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman hortikultura dan perkebunan.\r\n\r\nProduk ini efektif digunakan sebagai fungisida embun tepung, fungisida bercak daun, fungisida karat daun, fungisida busuk daun, dan fungisida antraknosa.\r\n\r\nDapat digunakan pada tanaman cabai, tomat, kubis, sawi, dan berbagai tanaman hortikultura lainnya.\r\n\r\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun berjamur, daun putih bertepung, daun mengering, busuk daun, dan kerusakan akibat infeksi jamur.\r\n\r\nTopdor 10 WP bekerja secara sistemik sehingga mampu melindungi jaringan tanaman dari dalam dan menghambat perkembangan patogen penyebab penyakit.', 'Rp.15.000', '10', '100gram', '-', 'Tersedia', '03/05/2026 23:27:55', ''),
('17', 'Foltus 400 SL 1 L â€“ Herbisida', 'Herbisida', '', 'Vegetatif, Generatif', '', '', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air, tergantung kepadatan gulma.', '', 'Foltus 400 SL adalah herbisida berbentuk soluble liquid (SL) dengan bahan aktif glyphosate yang bekerja secara sistemik non-selektif untuk mengendalikan gulma pada lahan pertanian dan perkebunan. Produk ini efektif untuk mengendalikan rumput, gulma daun lebar, dan teki-tekian, yang sering mengganggu tanaman utama. Cara kerja Foltus adalah dengan diserap melalui daun dan ditranslokasikan ke seluruh jaringan gulma, sehingga gulma mati hingga ke akar.', 'Rp.55.000', '8', '1L', '-', 'Tersedia', '04/05/2026 22:17:31', ''),
('18', 'Hypolax 400 SL 1 L â€“ Herbisida', 'Herbisida', 'Perkebunan, Pertanian, Lahan Kosong', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput, Teki-Tekian', 'Perkebunan, Pertanian, Lahan Kosong', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air.', 'obat gulma,\r\nherbisida glyphosate,\r\nracun rumput,\r\nobat teki teki,\r\npembasmi alang alang,\r\nobat lahan penuh rumput,\r\npengendali gulma,\r\nherbisida sawit,\r\nherbisida perkebunan,\r\nobat gulma kebun,\r\nobat rumput liar,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\npembersih lahan,\r\nherbisida sebelum tanam,\r\nobat lahan kosong', 'Hypolax 400 SL merupakan herbisida sistemik berbahan aktif glyphosate yang digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki teki pada area pertanian maupun perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, pengendali teki teki, serta pembersih lahan sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain lahan dipenuhi rumput liar, pertumbuhan gulma yang menghambat tanaman utama, serta area perkebunan yang tertutup gulma dan semak liar.', 'Rp.60.000', '7', '1L', '-', 'Tersedia', '04/05/2026 22:22:32', ''),
('19', 'Indodine 485 SL 1 L â€“ Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Tebu, Lahan Pra Tanam', 'Pra Tanam, Awal Pertumbuhan Gulma', 'Gulma Daun Lebar, Gulma Rumput, Teki-Tekian', 'Sawah, Lahan Kering, Perkebunan', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air, tergantung kepadatan gulma', 'herbisida gulma,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput liar,\r\nobat teki teki,\r\nracun teki,\r\npengendali gulma sawah,\r\nherbisida glyphosate,\r\nobat rumput kebun,\r\npembasmi gulma perkebunan,\r\nobat rumput kelapa sawit,\r\nobat gulma jagung,\r\nobat gulma tebu,\r\nobat gulma karet,\r\ngulma daun lebar,\r\ngulma rumput,\r\ngulma teki,\r\nrumput liar,\r\nlahan penuh gulma,\r\npengendali gulma total,\r\nherbisida non selektif,\r\nherbisida sistemik', 'Indodine 485 SL merupakan herbisida sistemik berbahan aktif glyphosate yang digunakan untuk mengendalikan gulma rumput, gulma daun lebar, dan teki teki pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma, racun rumput liar, pembasmi teki teki, pengendali gulma kebun kelapa sawit, lahan karet, jagung, dan tebu.\r\n\r\nGejala yang dapat dikendalikan antara lain lahan ditumbuhi rumput liar, gulma mengganggu pertumbuhan tanaman, banyak teki teki di kebun, gulma daun lebar sulit dikendalikan, dan persaingan unsur hara akibat gulma.\r\n\r\nCocok digunakan sebelum tanam maupun saat gulma masih aktif tumbuh.\r\n\r\nDosis aplikasi 5 sampai 10 ml per liter air atau 2 sampai 6 liter per hektar tergantung kepadatan gulma.', 'Rp.75.000', '10', '1L', '-', 'Tersedia', '04/05/2026 22:33:30', ''),
('20', 'Rumpas 120EW 100ML', 'Herbisida', 'Padi Sawah', 'Awal Pertumbuhan Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput Liar, Teki-Tekian', 'Sawah', 'Dosis semprot:\r\n0.5 â€“ 1 ml per liter air\r\n\r\nDosis lapangan:\r\n100 â€“ 200 ml per hektar\r\n\r\nWaktu aplikasi:\r\nPada fase awal pertumbuhan gulma.\r\n\r\nKondisi aplikasi:\r\nDisemprot saat air sawah dangkal atau macak-macak.\r\n\r\nFrekuensi:\r\nUmumnya 1 kali aplikasi per musim tanam.', 'herbisida padi,\r\nobat gulma padi,\r\nobat rumput sawah,\r\nracun rumput sawah,\r\nobat teki sawah,\r\nobat teki-tekian,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar sawah,\r\nrumput bandel sawah,\r\nlahan padi banyak rumput,\r\ngulma mengganggu padi,\r\nmembersihkan gulma sawah,\r\nobat gulma sampai akar,\r\nherbisida sistemik,\r\npenoxsulam,\r\nobat gulma awal tanam,\r\ngulma tumbuh cepat,\r\nrumput susah mati,\r\npembersih lahan sawah', 'Rumpas 120 EW merupakan herbisida sistemik berbahan aktif penoxsulam 120 g/L yang digunakan untuk mengendalikan gulma pada tanaman padi sawah.\r\n\r\nProduk ini efektif digunakan untuk membasmi gulma daun lebar, gulma daun sempit, rumput liar, dan teki-tekian yang sering tumbuh pada lahan sawah.\r\n\r\nGejala yang dapat ditangani antara lain sawah dipenuhi rumput liar, gulma mengganggu pertumbuhan padi, teki-tekian menyebar luas, serta rumput bandel yang sulit dikendalikan.\r\n\r\nRumpas 120 EW bekerja secara sistemik melalui daun dan akar gulma sehingga gulma menguning, berhenti tumbuh, dan mati hingga ke jaringan tanaman.', 'Rp.50.000', '7', '100ml', '-', 'Tersedia', '04/05/2026 11:40:36', ''),
('21', 'Pixel 300 SL', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Lahan Persiapan Tanam', 'Pra Tanam, Pra Tanam Awal', 'Gulma Rumput, Gulma Daun Lebar, Gulma Muda', 'Kebun, Lahan Terbuka, Perkebunan', 'Dosis pemakaian Pixel 300 SL umumnya sekitar 2 â€“ 4 ml per liter air atau 2 â€“ 5 liter per hektar, tergantung kepadatan gulma.', 'herbisida,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput,\r\nobat rumput liar,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\ngulma teki,\r\ngulma daun lebar,\r\nrumput kebun,\r\nrumput sawit,\r\nrumput karet,\r\nsemprot rumput,\r\nobat rumput bandel,\r\nrumput liar kebun,\r\nbersihkan lahan,\r\npersiapan tanam,\r\nsemprot gulma,\r\nobat gulma sawit,\r\nobat gulma jagung,\r\npengendali gulma,\r\nrumput cepat mati,\r\nherbisida kontak,\r\nparaquat,\r\npixel 300 sl', 'Pixel 300 SL merupakan herbisida kontak berbahan aktif paraquat yang digunakan untuk mengendalikan gulma rumput, gulma daun lebar, dan gulma muda pada perkebunan kelapa sawit, karet, jagung, serta lahan sebelum tanam.\r\n\r\nProduk ini sering digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, obat teki, semprot rumput liar, dan pengendali gulma pada lahan pertanian.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma berlebihan, lahan tertutup rumput liar, alang alang yang mendominasi kebun, serta gulma yang mengganggu pertumbuhan tanaman utama.\r\n\r\nDosis penggunaan 2â€“4 ml per liter air atau 2â€“5 liter per hektar.', 'Rp100.000', '5', '200ml', '-', 'Tersedia', '05/05/2026 16:45:57', ''),
('22', 'Roundup Biosorb 486 SL', 'Herbisida', 'Kelapa Sawit, Karet, Kakao, Kopi, Teh, Jagung, Kedelai, Padi Gogo', 'Pra Tanam, Persiapan Lahan, Pasca Panen', 'Gulma Daun Lebar, Gulma Rumput, Teki-Tekian', 'Perkebunan, Sawah, Lahan Kering, Lahan Terbuka', '5â€“10 ml/L air atau 2â€“6 L/ha', 'roundup,\r\nroundup biosorb,\r\nobat rumput,\r\nracun rumput,\r\npembasmi rumput,\r\nherbisida rumput,\r\nobat gulma,\r\nracun gulma,\r\nherbisida gulma,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nobat rumput liar,\r\nherbisida kebun,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat lahan kosong,\r\nbersih lahan,\r\nsemprot rumput,\r\nobat gulma membandel,\r\nglyphosate,\r\nglifosat,\r\nobat rumput sawit,\r\nobat rumput jagung,\r\ntot,\r\ntanpa olah tanah', 'Roundup Biosorb 486 SL merupakan herbisida sistemik non selektif berbahan aktif glifosat yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun rumput, pembasmi alang alang, pengendali teki, dan herbisida gulma membandel pada perkebunan sawit, karet, kakao, kopi, teh, jagung, kedelai, dan padi gogo.\r\n\r\nGejala yang dapat dikendalikan antara lain lahan dipenuhi rumput liar, alang alang, gulma daun lebar, gulma rumput, dan teki yang mengganggu pertumbuhan tanaman utama.\r\n\r\nRoundup bekerja secara sistemik dengan diserap melalui daun kemudian ditranslokasikan hingga ke akar sehingga gulma mati sampai ke perakarannya.\r\n\r\nCocok digunakan saat persiapan lahan, sistem tanpa olah tanah (TOT), maupun pembersihan kebun sebelum tanam.', '145000', '5', '1 liter', '', '', '', ''),
('23', 'Gol-Ok Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Tebu', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput, Teki', 'Perkebunan, Lahan Terbuka', '4â€“10 ml/L air', 'golok,\r\ngol-ok,\r\nobat rumput,\r\nracun rumput,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nherbisida kebun,\r\nobat rumput sawit,\r\nobat rumput karet,\r\nobat lahan kosong,\r\nbersih kebun,\r\nsemprot rumput,\r\ngulma membandel,\r\nrumput liar,\r\nteki teki,\r\ngulma daun lebar,\r\nherbisida perkebunan,\r\nracun gulma', 'Gol-Ok merupakan herbisida sistemik non selektif yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan perkebunan dan pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun alang alang, pengendali teki, serta pembersih lahan sebelum tanam.\r\n\r\nCocok untuk mengendalikan gulma daun lebar, rumput liar, dan teki yang tumbuh pada perkebunan sawit, karet, tebu, maupun lahan pertanian lainnya.\r\n\r\nHerbisida ini bekerja dengan diserap melalui daun kemudian ditranslokasikan ke seluruh jaringan gulma hingga akar sehingga gulma mati secara menyeluruh.\r\n\r\nDigunakan pada fase persiapan lahan dan pembersihan kebun sebelum budidaya tanaman.', 'Rp60.000', '5', ' liter', '', '', '', ''),
('24', 'Maxxfosate Neo 525 SL', 'Herbisida', 'Kelapa Sawit, Karet, Perkebunan', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput, Teki', 'Perkebunan, Lahan Terbuka', '1,125â€“1,5 L/ha', 'maxxfosate,\r\nmaxxfosate neo,\r\nobat rumput,\r\nracun rumput,\r\nglyphosate,\r\nglifosat,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nsemprot rumput,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat gulma kebun,\r\npembersih lahan,\r\ngulma membandel,\r\nrumput liar,\r\nobat rumput perkebunan,\r\nherbisida glifosat,\r\nracun gulma', 'Maxxfosate Neo 525 SL merupakan herbisida sistemik non selektif berbahan aktif glifosat yang digunakan untuk mengendalikan gulma pada area perkebunan.\r\n\r\nProduk ini sering digunakan sebagai obat rumput, racun alang alang, pengendali teki, dan herbisida gulma membandel pada kebun sawit dan karet.\r\n\r\nGejala yang dapat dikendalikan antara lain dominasi gulma daun lebar, gulma rumput, serta teki yang menghambat pertumbuhan tanaman utama.\r\n\r\nMaxxfosate bekerja secara sistemik dengan ditranslokasikan hingga ke akar sehingga memberikan pengendalian gulma yang lebih tuntas.\r\n\r\nCocok diaplikasikan saat gulma tumbuh aktif dengan tingkat penutupan lahan tinggi.', '70000', '7', '500ml', '', '', '', ''),
('25', 'Insta Max 240 SL', 'Herbisida', 'Kelapa Sawit, Jagung, Karet', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput Muda', 'Perkebunan, Lahan Terbuka', '2â€“5 L/ha', 'insta max,\r\ninstamax,\r\nobat rumput,\r\nracun rumput,\r\nobat gulma,\r\nherbisida kontak,\r\nparaquat,\r\nparakuat,\r\nobat alang alang,\r\nracun alang alang,\r\nsemprot rumput,\r\nbersih kebun,\r\nobat gulma cepat mati,\r\nrumput cepat kering,\r\nherbisida perkebunan,\r\nobat lahan kosong,\r\nracun gulma,\r\nobat rumput sawit,\r\nobat rumput jagung,\r\ngulma muda', 'Insta Max 240 SL merupakan herbisida kontak yang bekerja cepat untuk mengendalikan gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun gulma, dan pembersih lahan sebelum tanam karena mampu mengeringkan gulma dalam waktu singkat.\r\n\r\nEfektif mengendalikan gulma daun lebar, rumput muda, dan berbagai gulma yang tumbuh pada kebun sawit, jagung, dan karet.\r\n\r\nCara kerja produk adalah merusak jaringan hijau gulma secara langsung sehingga gulma cepat layu dan mati.\r\n\r\nCocok digunakan untuk pembersihan kebun dan persiapan lahan budidaya.', '65.000', '5', '1 liter', '', '', '', ''),
('26', 'Neoxone 276 SL', 'Herbisida', 'Kelapa Sawit, Kakao, Jagung, Padi TOT', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Gulma Rumput, Teki', 'Perkebunan, Sawah TOT, Lahan Terbuka', '1,5â€“3 L/ha', 'neoxone,\r\nneoxone 276,\r\nobat rumput,\r\nracun rumput,\r\nparaquat,\r\nparakuat,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nsemprot rumput,\r\nobat gulma sawit,\r\nobat gulma kakao,\r\nobat gulma jagung,\r\nobat rumput padi,\r\ntot,\r\ntanpa olah tanah,\r\ngulma membandel,\r\nrumput liar,\r\nracun gulma cepat', 'Neoxone 276 SL merupakan herbisida kontak berbahan aktif parakuat diklorida yang digunakan untuk mengendalikan gulma pada perkebunan dan lahan pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun alang alang, pengendali teki, serta pembersih lahan sebelum tanam pada perkebunan sawit, kakao, jagung, dan sistem padi tanpa olah tanah.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma daun lebar, gulma rumput, dan teki yang menutupi lahan budidaya.\r\n\r\nNeoxone bekerja dengan merusak jaringan hijau tanaman gulma secara cepat sehingga gulma mengering dan mati.\r\n\r\nCocok digunakan untuk mempercepat persiapan lahan dan pengendalian gulma pada areal perkebunan.', '65000', '5', '1 liter', '', '', '', ''),
('27', 'Supremo 480 SL', 'Herbisida', 'Kelapa Sawit, Karet, Kakao, Teh, Kopi, Jagung', 'Pra Tanam, Persiapan Lahan, Pasca Panen', 'Gulma Daun Lebar, Gulma Rumput, Alang-Alang, Teki-Tekian', 'Perkebunan, Lahan Kering, Lahan Terbuka', '5â€“10 ml/L air atau 2â€“6 L/ha', 'supremo, supremo 480 sl, herbisida supremo, obat rumput, racun rumput, pembasmi rumput, obat gulma, racun gulma, obat alang alang, racun alang alang, obat teki, racun teki, rumput liar, herbisida sawit, herbisida karet, herbisida jagung, pembersih lahan, semprot rumput, bersih kebun, gulma membandel, herbisida glifosat, glifosat, glyphosate, obat rumput kebun, obat rumput sawit, tot, tanpa olah tanah', 'Supremo 480 SL merupakan herbisida sistemik non selektif berbahan aktif isopropil amina glifosat 480 g/L yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun rumput, pembasmi alang alang, pengendali teki, dan herbisida gulma membandel pada tanaman kelapa sawit, karet, kakao, teh, kopi, dan jagung.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan rumput liar, alang alang, gulma daun lebar, gulma rumput, dan teki teki yang menutupi area perakaran tanaman budidaya.\r\n\r\nSupremo bekerja secara sistemik dengan diserap melalui daun lalu ditranslokasikan hingga ke akar sehingga gulma mati secara menyeluruh sampai ke bagian bawah tanah.\r\n\r\nProduk ini sering digunakan pada sistem tanpa olah tanah (TOT), pembersihan kebun, persiapan lahan sebelum tanam, dan pengendalian gulma pada areal perkebunan produktif.', '60000', '5', '1 liter', '', '', '', ''),
('28', 'Chlormite 400 EC 100 ml â€“ Akarisida / Insektisida', 'Insektisida, Akarisida', 'Cabai, Tomat, Terong, Kentang, Jeruk, Apel, Teh, Kapas, Sayuran', 'Vegetatif, Generatif Awal', 'Tungau merah, Tungau kuning, Kutu daun, Serangga penghisap', 'Lahan pertanian, Bedengan, Kebun, Sawah tadah hujan', '1-2 ml per liter air, 200-400 ml per hektar, semprot merata terutama bagian bawah daun', 'tungau,tungau merah,tungau kuning,kutu daun,aphid,hama penghisap,daun keriting,keriting daun,daun menguning,bercak daun,daun kusam,cabai keriting,tomat keriting,hama daun,serangan tungau', 'Akarisida insektisida berbahan aktif chlormite formulasi EC yang bekerja sebagai racun kontak dan lambung untuk mengendalikan tungau merah, tungau kuning, kutu daun, dan serangga penghisap pada tanaman cabai, tomat, terong, kentang, jeruk, apel, teh, kapas, dan sayuran. Cocok digunakan pada fase vegetatif hingga generatif awal saat populasi tungau meningkat. Membantu mengatasi daun keriting, daun berbintik, daun kusam, daun menguning, dan penurunan fotosintesis akibat serangan tungau.', 'Rp.30.000', '15', '100ml', '-', 'Tersedia', '04/05/2026 13:34:40', ''),
('29', 'Cronus 18 EC â€“ Insektisida', 'Insektisida, Akarisida', 'Cabai, Tomat, Kentang, Bawang Merah, Melon, Semangka, Mentimun, Kubis, Sayuran', 'Vegetatif, Generatif Awal', 'Thrips, Tungau, Ulat daun, Kutu daun', 'Bedengan, Lahan pertanian, Polybag, Greenhouse', 'dosis_pemakaian=0.5-1 ml per liter air, 100-200 ml per hektar, semprot merata pada daun', 'thrips,tungau,kutu daun,aphid,ulat daun,daun keriting,keriting daun,daun menggulung,thrips cabai,cabai keriting,kutu kebul,hama penghisap,hama daun,abamektin,serangan thrips', 'Insektisida akarisida berbahan aktif abamektin formulasi EC yang bekerja sebagai racun kontak, lambung, dan translaminar untuk mengendalikan thrips, tungau, ulat daun, dan kutu daun pada tanaman cabai, tomat, kentang, bawang merah, melon, semangka, mentimun, kubis, dan sayuran. Efektif menjangkau hama yang bersembunyi di bawah daun. Membantu mengatasi daun keriting, daun menggulung, bercak akibat thrips, dan kerusakan daun karena serangan hama penghisap.', 'Rp.90.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 13:37:12', '');
INSERT INTO `dataproduk` (`COL 1`, `COL 2`, `COL 3`, `COL 4`, `COL 5`, `COL 6`, `COL 7`, `COL 8`, `COL 9`, `COL 10`, `COL 11`, `COL 12`, `COL 13`, `COL 14`, `COL 15`, `COL 16`, `COL 17`) VALUES
('30', 'Metsulindo 20 WG', 'Herbisida', 'Kelapa Sawit TBM, Karet, Tebu, Lahan Perkebunan', 'Pasca Tumbuh Gulma (Post Emergence)', 'Gulma Daun Lebar, Gulma Semusim, Gulma Berkayu Muda', 'Perkebunan, Lahan Kering', '10â€“50 gram/ha atau sesuai rekomendasi lapangan', 'metsulindo, metsulfuron methyl, herbisida metsulindo, obat gulma daun lebar, racun gulma daun lebar, pembasmi semak, obat semak liar, racun semak, herbisida sawit, herbisida karet, obat gulma kebun, gulma bandotan, gulma sembung rambat, gulma kirinyuh, gulma berkayu, gulma semusim, gulma tahunan, semprot gulma, pembersih kebun, obat rumput kebun, pengendali gulma perkebunan, sulfonilurea, sulfonylurea herbicide', 'Metsulindo merupakan herbisida selektif sistemik berbahan aktif metsulfuron methyl dari golongan sulfonilurea yang digunakan untuk mengendalikan gulma daun lebar dan semak pada lahan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma daun lebar, pembasmi semak liar, pengendali gulma berkayu muda, dan herbisida perkebunan pada tanaman kelapa sawit, karet, dan tebu.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma bandotan, kirinyuh, sembung rambat, gulma semusim, serta berbagai gulma daun lebar yang sulit dikendalikan dengan herbisida biasa.\r\n\r\nMetsulindo bekerja secara sistemik dengan menghambat pembelahan sel pada jaringan gulma sehingga pertumbuhan gulma berhenti, menguning, kemudian mati secara bertahap.\r\n\r\nProduk ini cocok digunakan pada areal perkebunan yang didominasi gulma daun lebar dan semak berkayu muda untuk menjaga kebersihan lahan dan mengurangi kompetisi unsur hara.', '45000', '5', '250 gram', '', '', '', ''),
('31', 'Dangke 40 WP 100 gr â€“ Insektisida', 'Insektisida', 'Bawang Merah, Cabai, Kacang Hijau, Kacang Panjang, Kacang Tanah, Kakao, Kedelai, Kelapa Sawit, Kubis, Tomat', 'Vegetatif, Generatif', 'Ulat grayak, Penggerek polong, Thrips, Kutu daun, Kepik hijau, Kepik polong, Lalat bibit, Penggulung daun, Penghisap daun, Pengisap buah, Ulat kantong, Ulat api, Ulat krop, Perusak buah', 'Lahan pertanian, Bedengan, Kebun, Perkebunan', 'dosis_pemakaian=Bawang merah ulat grayak 3 g/L; Cabai ulat grayak 2 g/L dan perusak buah 1-2 g/L; Kacang hijau 1.5-4 g/L; Kacang panjang 1.5-4 g/L; Kakao pengisap buah 1-2 g/L; Kedelai penggerek polong 1.5-3 g/L; Kelapa sawit ulat kantong dan ulat api 1-2 g/L; Kubis ulat daun dan ulat krop 1-2 g/L; Tomat perusak buah 3-4 g/L', 'ulat grayak,penggerek polong,thrips,kutu daun,aphid,kepik hijau,kepik polong,penghisap daun,pengisap buah,ulat kantong,ulat api,ulat krop,ulat daun,daun berlubang,daun habis dimakan ulat,buah rusak,polong rusak,cabai ulat,tomat ulat,kedelai penggerek,hama daun,hama buah', 'Insektisida formulasi WP yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat grayak, penggerek polong, thrips, kutu daun, kepik, lalat bibit, penghisap daun, ulat kantong, ulat api, ulat krop, dan hama perusak buah pada bawang merah, cabai, kacang hijau, kacang panjang, kacang tanah, kakao, kedelai, kelapa sawit, kubis, dan tomat. Cocok digunakan pada fase vegetatif hingga generatif saat populasi hama meningkat. Membantu mengatasi daun berlubang, daun habis dimakan ulat, buah rusak, polong rusak, daun keriting, dan serangan hama penghisap.', 'Rp.25.000', '10', '100gram', '-', 'Tersedia', '04/05/2026 14:01:09', ''),
('32', 'Decis 25 EC 100 ml â€“ Insektisida', 'Insektisida', 'Anggrek, Apel, Bawang Merah, Belimbing, Jagung, Cabai, Jeruk, Kacang Hijau, Kacang Panjang, Kakao, Kedelai, Kelapa Sawit, Kentang, Mentimun, Melon, Semangka, Kopi, Kubis, Mangga, Teh, Tembakau', 'Vegetatif, Generatif', 'Ulat grayak, Thrips, Kutu daun, Lalat buah, Penggerek batang, Penggerek tongkol, Kutu loncat, Lalat bibit, Pengisap buah, Pengisap polong, Ulat api, Wereng, Pengisap daun, Penggerek pucuk', 'Lahan pertanian, Bedengan, Kebun, Perkebunan', 'dosis_pemakaian=Umumnya 0.25-2 ml/L sesuai jenis tanaman dan hama sasaran, aplikasi semprot merata pada bagian tanaman yang terserang\n', 'Insektisida berbahan aktif deltametrin golongan piretroid yang bekerja sebagai racun kontak dan lambung dengan efek knockdown cepat untuk mengendalikan ulat grayak, thrips, kutu daun, lalat buah, penggerek batang, wereng, kutu loncat, dan serangga penghisap lainnya. Digunakan pada berbagai tanaman hortikultura, pangan, dan perkebunan. Membantu mengatasi daun keriting, daun berlubang, buah berlubang, buah rontok, serangan lalat buah, serangan wereng, serta kerusakan akibat ulat dan penggerek.', 'Insektisida berbahan aktif deltametrin golongan piretroid yang bekerja sebagai racun kontak dan lambung dengan efek knockdown cepat untuk mengendalikan ulat grayak, thrips, kutu daun, lalat buah, penggerek batang, wereng, kutu loncat, dan serangga penghisap lainnya. Digunakan pada berbagai tanaman hortikultura, pangan, dan perkebunan. Membantu mengatasi daun keriting, daun berlubang, buah berlubang, buah rontok, serangan lalat buah, serangan wereng, serta kerusakan akibat ulat dan penggerek.', 'Rp.28.000', '10', '100ml', '-', 'Tersedia', '04/05/2026 14:02:42', ''),
('33', 'Demolish 18 EC 100 ml â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Kentang, Mentimun, Semangka, Tanaman Hortikultura', 'Vegetatif, Generatif Awal', 'Thrips, Tungau, Ulat daun, Kutu daun', 'Bedengan, Greenhouse, Polybag, Lahan pertanian', 'dosis_pemakaian=0.5-1 ml per liter air, 100-200 ml per hektar, semprot merata terutama bagian bawah daun, interval 7-10 hari', 'abamektin,thrips,tungau,tungau merah,tungau kuning,kutu daun,aphid,ulat daun,daun keriting,cabai keriting,daun menggulung,keriting daun,bercak daun,daun kusam,hama penghisap,thrips cabai,tomat keriting,hama daun', 'Insektisida akarisida berbahan aktif abamektin formulasi EC yang bekerja sebagai racun kontak, racun lambung, dan translaminar untuk mengendalikan thrips, tungau, ulat daun, dan kutu daun pada tanaman cabai, tomat, kentang, mentimun, semangka, dan tanaman hortikultura lainnya. Efektif menjangkau hama yang bersembunyi di bawah daun dan membantu mengatasi daun keriting, daun menggulung, bercak akibat thrips, daun kusam, dan kerusakan daun akibat tungau.', 'Rp.80.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 15:26:12', ''),
('34', 'Delouse 200 SL 80 ml â€“ Insektisida', 'Insektisida', 'padi, cabai, tomat, mentimun, terong, hortikultura', 'Vegetatif, Generatif Awal', 'wereng, kutu daun, aphid, kutu kebul, whitefly, thrips', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Delouse 200 SL umumnya berkisar 0,25 â€“ 0,5 ml per liter air, atau sekitar 50 â€“ 100 ml per hektar, tergantung pada tingkat serangan hama. Aplikasi dilakukan dengan penyemprotan atau pengocoran pada tanaman. Frekuensi penggunaan biasanya 7â€“14 hari sekali.', 'insektisida sistemik,\r\nobat wereng,\r\npestisida wereng,\r\ninsektisida wereng,\r\nobat kutu daun,\r\npestisida kutu daun,\r\ninsektisida kutu daun,\r\nobat kutu kebul,\r\nwhitefly,\r\naphid,\r\nobat thrips,\r\nhama penghisap,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat daun kuning,\r\npengendali wereng padi,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida mentimun,\r\npengendali hama penghisap', 'Delouse 200 SL merupakan insektisida sistemik berbahan aktif imidacloprid yang digunakan untuk mengendalikan hama penghisap pada tanaman padi, cabai, tomat, mentimun, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini efektif digunakan sebagai obat wereng, pestisida kutu daun, insektisida kutu kebul, pengendali whitefly, serta pengendali thrips pada fase vegetatif dan generatif awal.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menggulung, daun menguning, pertumbuhan tanaman terhambat, tanaman kerdil, serta serangan hama penghisap pada daun muda.\r\n\r\nDelouse 200 SL bekerja secara sistemik sehingga diserap oleh tanaman dan memberikan perlindungan lebih lama terhadap hama yang bersembunyi pada bagian bawah daun maupun pucuk tanaman.\r\n\r\nDosis aplikasi 0,25 sampai 0,5 ml per liter air atau 50 sampai 100 ml per hektar dengan interval aplikasi 7 sampai 14 hari.', 'Rp.25.000', '5', '100gram', '-', 'Tersedia', '04/05/2026 21:04:34', ''),
('35', 'Destan 400 EC 100 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Tomat, Kentang, Hortikultura', 'Vegetatif', 'Kutu Daun, Wereng, Thrips, Hama Penghisap', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Destan 400 EC umumnya berkisar 1 â€“ 2 ml per liter air, atau sekitar 200 â€“ 400 ml per hektar, tergantung tingkat serangan hama. Aplikasi dilakukan dengan penyemprotan merata pada daun tanaman. Frekuensi penggunaan biasanya 7â€“10 hari sekali.', 'insektisida wereng,\r\nobat wereng,\r\npestisida wereng,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat thrips,\r\npestisida thrips,\r\nhama penghisap,\r\nobat daun keriting,\r\nobat daun kuning,\r\npengendali kutu daun,\r\npengendali thrips,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida kentang,\r\ninsektisida padi,\r\nobat tanaman kerdil,\r\npengendali serangga penghisap', 'Destan 400 EC merupakan insektisida kontak dan sistemik yang digunakan untuk mengendalikan hama wereng, kutu daun, thrips, dan berbagai hama penghisap pada tanaman padi, cabai, tomat, kentang, serta tanaman hortikultura lainnya.\r\n\r\nProduk ini digunakan sebagai pestisida wereng, obat kutu daun, insektisida thrips, dan pengendali serangga penghisap yang menyebabkan kerusakan pada daun dan pucuk tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menggulung, daun menguning, pertumbuhan terhambat, tanaman kerdil, dan kerusakan akibat aktivitas hama penghisap.\r\n\r\nDestan 400 EC cocok diaplikasikan pada fase vegetatif ketika populasi hama mulai meningkat dan berpotensi menurunkan produktivitas tanaman.\r\n\r\nDosis aplikasi 1 sampai 2 ml per liter air atau 200 sampai 400 ml per hektar dengan interval aplikasi 7 sampai 10 hari.', 'Rp.15.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 21:08:51', ''),
('36', 'Dharmabas 500 EC 400 ml â€“ Insektisida', 'Insektisida', 'Padi, Jagung, Cabai, Kedelai, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Penggerek Batang, Kutu Daun, Ulat Daun', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Dharmabas 500 EC umumnya berkisar 1,5 â€“ 2 ml per liter air, atau sekitar 300 â€“ 500 ml per hektar. Aplikasi dilakukan dengan penyemprotan merata pada tanaman yang terserang. Frekuensi penggunaan biasanya 7â€“10 hari sekali. Produk ini tersedia dalam kemasan 400 ml dengan kisaran harga sekitar Rp60.000 â€“ Rp120.000. Kata kunci penting meliputi: insektisida, klorpirifos, dharmabas, ulat grayak, penggerek batang, pestisida, racun kontak, racun lambung, pertanian, pengendalian hama.', 'obat ulat grayak,\r\ninsektisida ulat grayak,\r\npestisida ulat grayak,\r\nobat ulat daun,\r\npengendali ulat daun,\r\nobat penggerek batang,\r\ninsektisida penggerek batang,\r\nobat kutu daun,\r\ndaun berlubang,\r\ndaun dimakan ulat,\r\nbatang berlubang,\r\nhama jagung,\r\nhama padi,\r\nhama cabai,\r\nhama kedelai,\r\npengendali hama tanaman', 'Dharmabas 500 EC merupakan insektisida berbahan aktif klorpirifos yang digunakan untuk mengendalikan ulat grayak, ulat daun, penggerek batang, kutu daun, dan berbagai hama serangga pada tanaman padi, jagung, cabai, kedelai, dan hortikultura.\r\n\r\nProduk ini efektif digunakan sebagai obat ulat grayak, pestisida ulat daun, pengendali penggerek batang, dan insektisida spektrum luas untuk berbagai komoditas pertanian.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, daun habis dimakan ulat, batang berlubang, pucuk rusak, pertumbuhan terhambat, dan kerusakan akibat penggerek.\r\n\r\nDharmabas bekerja sebagai racun kontak dan lambung sehingga mampu memberikan efek pengendalian cepat terhadap serangan hama.\r\n\r\nDosis aplikasi 1,5 sampai 2 ml per liter air atau 300 sampai 500 ml per hektar dengan interval aplikasi 7 sampai 10 hari.', 'Rp.40.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 21:13:03', ''),
('37', 'Dharmasan 600 EC 100 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Bawang Merah, Kedelai, Kapas', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek Batang', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Dharmasan 600 EC umumnya berkisar 1 â€“ 2 ml per liter air, atau sekitar 200 â€“ 400 ml per hektar, tergantung tingkat serangan hama. Aplikasi dilakukan dengan penyemprotan merata pada daun dan batang tanaman. Frekuensi penggunaan biasanya 7â€“10 hari sekali.', 'obat ulat grayak,\ninsektisida ulat,\npestisida ulat,\nobat thrips,\ninsektisida thrips,\nobat kutu daun,\npengendali kutu daun,\nobat penggerek batang,\ndaun keriting,\ndaun berlubang,\npucuk rusak,\nbuah rusak,\nhama cabai,\nhama bawang merah,\nhama padi,\nhama kedelai,\npengendali hama serangga', 'Dharmasan 600 EC merupakan insektisida berbahan aktif profenofos yang digunakan untuk mengendalikan ulat grayak, thrips, kutu daun, penggerek batang, dan berbagai hama serangga pada tanaman padi, cabai, bawang merah, kedelai, dan kapas.\r\n\r\nProduk ini digunakan sebagai pestisida ulat grayak, insektisida thrips, obat kutu daun, dan pengendali penggerek batang yang sering menurunkan produktivitas tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun berlubang, pucuk rusak, batang rusak, buah rusak akibat ulat, serta serangan hama penghisap dan pengunyah.\r\n\r\nDharmasan bekerja sebagai racun kontak dan lambung dengan daya bunuh cepat terhadap berbagai jenis serangga sasaran.\r\n\r\nDosis aplikasi 1 sampai 2 ml per liter air atau 200 sampai 400 ml per hektar dengan interval aplikasi 7 sampai 10 hari.', 'Rp.25.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 21:51:18', ''),
('38', 'Dupont Ammate 150 EC 50 ml â€“ Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Tanaman Pangan, Lahan Kosong', 'Pra Tanam, Persiapan Lahan, Pasca Tumbuh Gulma', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput, Teki-Tekian', 'Sawah, Kebun, Perkebunan, Lahan Terbuka', 'Dosis pemakaian Dupont Ammate 150 EC umumnya berkisar 1 â€“ 2 ml per liter air, atau sekitar 2 â€“ 4 liter per hektar, tergantung kepadatan gulma', 'herbisida gulma,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput liar,\r\nobat teki teki,\r\nherbisida teki teki,\r\nobat gulma sawah,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat lahan penuh rumput,\r\npengendali gulma,\r\nobat rumput liar,\r\npembersih lahan,\r\nherbisida pra tanam,\r\nobat lahan sebelum tanam,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\nrumput liar kebun,\r\nobat alang alang,\r\nherbisida perkebunan', 'Dupont Ammate 150 EC merupakan herbisida yang digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki teki pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini sering digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, herbisida sawit, herbisida karet, dan pembersih lahan sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain lahan dipenuhi rumput liar, pertumbuhan gulma yang mengganggu tanaman utama, serta infestasi teki teki pada area perkebunan dan pertanian.\r\n\r\nCocok digunakan pada tahap persiapan lahan dan sistem tanpa olah tanah sebelum proses budidaya dimulai.', 'Rp.60.000', '7', '50ml', '-', 'Tersedia', '04/05/2026 21:53:56', ''),
('39', 'Dursban â€“ Insektisida', 'Insektisida', 'Padi, Jagung, Cabai, Bawang Merah, Kedelai, Tebu', 'Vegetatif, Generatif Awal', 'Ulat Grayak, Penggerek Batang, Rayap, Kutu Tanah, Wereng, Serangga Penghisap', 'Sawah, Kebun, Lahan Terbuka', 'Dosis pemakaian Dursban umumnya berkisar 1 â€“ 2 ml per liter air, atau sekitar 300 â€“ 500 ml per hektar, tergantung jenis tanaman dan tingkat serangan hama. Aplikasi dilakukan dengan penyemprotan atau pengocoran pada tanah dan tanaman.', 'obat ulat grayak,\r\ninsektisida ulat,\r\nracun ulat,\r\nobat penggerek batang,\r\nobat sundep,\r\ninsektisida padi,\r\nobat wereng,\r\nobat kutu tanah,\r\nobat rayap,\r\npestisida cabai,\r\ninsektisida jagung,\r\nobat hama kedelai,\r\nracun serangga penghisap,\r\npengendali ulat,\r\nobat tanaman dimakan ulat,\r\nobat daun berlubang,\r\nhama batang padi,\r\nobat serangan hama berat,\r\ninsektisida klorpirifos', 'Dursban merupakan insektisida berbahan aktif klorpirifos yang digunakan untuk mengendalikan ulat grayak, penggerek batang, wereng, rayap, kutu tanah, dan berbagai serangga penghisap pada tanaman padi, jagung, cabai, bawang merah, kedelai, dan tebu.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat grayak, insektisida penggerek batang, obat wereng padi, racun kutu tanah, dan pengendali hama tanaman yang menyebabkan daun berlubang maupun batang rusak.\r\n\r\nGejala yang dapat dikendalikan antara lain daun dimakan ulat, batang padi terserang sundep, tanaman layu akibat serangan hama tanah, dan pertumbuhan tanaman terganggu karena serangga penghisap.', 'Rp.30.000', '7', '100ml, 250ml, 500ml,1L', '-', 'Tersedia', '04/05/2026 22:02:52', ''),
('40', 'Endure 120 SC 100 ml â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Bawang Merah, Kubis', 'Vegetatif, Generatif Awal', 'Ulat Grayak, Ulat Buah, Thrips, Larva Serangga', 'Kebun, Lahan Terbuka', 'Dosis pemakaian Endure 120 SC umumnya berkisar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar, tergantung jenis tanaman dan intensitas serangan. Aplikasi dilakukan dengan penyemprotan merata pada daun tanaman. Frekuensi penggunaan biasanya 7â€“10 hari sekali.', 'obat ulat grayak,\r\nobat ulat buah,\r\ninsektisida spinosad,\r\nobat thrips,\r\npestisida cabai,\r\ninsektisida bawang merah,\r\nobat daun keriting,\r\nobat daun rusak,\r\nobat bunga rontok,\r\nobat buah rusak,\r\npengendali thrips,\r\nobat hama cabai,\r\ninsektisida tomat,\r\nracun ulat,\r\nobat tanaman diserang ulat,\r\npengendali larva,\r\nobat serangga pemakan daun', 'Endure 120 SC merupakan insektisida berbahan aktif spinosad yang digunakan untuk mengendalikan ulat grayak, ulat buah, thrips, dan larva serangga pada tanaman cabai, tomat, bawang merah, dan kubis.\r\n\r\nProduk ini banyak digunakan sebagai obat thrips cabai, obat ulat buah tomat, pengendali ulat grayak, dan insektisida hortikultura.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting akibat thrips, bunga rontok, buah rusak karena ulat, daun berlubang, serta serangan larva pada tanaman sayuran.', 'Rp. 175.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 22:04:53', ''),
('41', 'Fertera 2 kg â€“ Insektisida', 'Insektisida', 'Padi, Jagung', 'Awal Vegetatif', 'Penggerek Batang, Ulat Grayak, Larva Serangga', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Fertera umumnya sekitar 10 â€“ 15 kg per hektar, diaplikasikan saat tanam atau awal fase vegetatif.', 'obat penggerek batang,\r\nobat sundep,\r\ninsektisida padi,\r\ninsektisida jagung,\r\nobat ulat grayak,\r\nracun larva,\r\nobat hama akar,\r\ninsektisida granul,\r\nobat hama sejak tanam,\r\npengendali sundep,\r\nobat batang padi rusak,\r\nobat tanaman muda diserang ulat,\r\npengendali larva serangga,\r\nobat hama jagung,\r\nobat hama padi,\r\nperlindungan sejak awal tanam', 'Fertera merupakan insektisida granul berbahan aktif klorantraniliprol yang digunakan untuk mengendalikan penggerek batang, ulat grayak, sundep, beluk, dan berbagai larva serangga pada tanaman padi dan jagung.\r\n\r\nProduk ini banyak digunakan sebagai obat sundep padi, obat beluk padi, insektisida penggerek batang, pengendali ulat grayak, dan perlindungan tanaman sejak awal tanam.\r\n\r\nGejala yang dapat dikendalikan antara lain batang padi menguning akibat sundep, pucuk tanaman mati, tanaman jagung terserang larva, daun berlubang akibat ulat grayak, pertumbuhan tanaman muda terhambat, serta kerusakan batang akibat serangan penggerek.\r\n\r\nCocok diaplikasikan sejak awal tanam hingga fase vegetatif untuk memberikan perlindungan sistemik yang tahan lama.', 'Rp.75.000', '5', '2kg', '-', 'Tersedia', '04/05/2026 22:10:20', ''),
('42', 'Foltus 400 SL 1 L â€“ Herbisida', 'Herbisida', '', 'Vegetatif, Generatif', '', '', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air, tergantung kepadatan gulma.', '', 'Foltus 400 SL adalah herbisida berbentuk soluble liquid (SL) dengan bahan aktif glyphosate yang bekerja secara sistemik non-selektif untuk mengendalikan gulma pada lahan pertanian dan perkebunan. Produk ini efektif untuk mengendalikan rumput, gulma daun lebar, dan teki-tekian, yang sering mengganggu tanaman utama. Cara kerja Foltus adalah dengan diserap melalui daun dan ditranslokasikan ke seluruh jaringan gulma, sehingga gulma mati hingga ke akar.', 'Rp.55.000', '8', '1L', '-', 'Tersedia', '04/05/2026 22:17:31', ''),
('43', 'Furadan 3 GR 2 kg â€“ Insektisida / Nematisida', 'Insektisida', 'Padi, Jagung, Tebu, Sayuran', 'Saat Tanam, Awal Vegetatif', 'Penggerek Batang, Wereng, Ulat Tanah, Nematoda', 'Sawah, Tanah, Kebun', 'Dosis pemakaian umumnya 10 â€“ 20 kg per hektar, diaplikasikan melalui tanah atau saat tanam.', 'furadan,\r\ninsektisida granul,\r\nnematisida,\r\nobat nematoda,\r\nobat cacing akar,\r\nobat akar rusak,\r\nobat wereng,\r\nobat sundep,\r\nobat penggerek batang,\r\ninsektisida padi,\r\ninsektisida jagung,\r\nobat ulat tanah,\r\nracun hama tanah,\r\nhama akar tanaman,\r\ntanaman kerdil,\r\nakar rusak,\r\npengendali nematoda,\r\nobat hama bawah tanah,\r\ninsektisida sistemik,\r\nperlindungan sejak tanam', 'Furadan 3 GR merupakan insektisida dan nematisida sistemik berbentuk granul yang digunakan untuk mengendalikan penggerek batang, wereng, ulat tanah, dan nematoda pada tanaman padi, jagung, tebu, serta berbagai tanaman sayuran.\r\n\r\nProduk ini banyak digunakan sebagai obat nematoda, obat cacing akar, pengendali sundep, insektisida padi, dan racun hama tanah yang menyerang akar maupun batang tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain tanaman kerdil, akar rusak, akar membusuk akibat nematoda, batang padi terserang sundep, tanaman layu akibat hama tanah, dan pertumbuhan tanaman yang terhambat.\r\n\r\nCocok diaplikasikan saat tanam hingga awal fase vegetatif untuk memberikan perlindungan dari dalam tanaman.', 'Rp.40.000', '5', '2kg', '-', 'Tersedia', '04/05/2026 22:20:51', ''),
('44', 'Glido 200/18 EC 100 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Bawang Merah, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Penggerek Batang, Kutu Daun, Thrips', 'Sawah, Kebun', 'Dosis pemakaian umumnya 0,5 â€“ 1 ml per liter air atau sekitar 100 â€“ 200 ml per hektar.', 'obat ulat grayak,\r\ninsektisida ulat,\r\nobat sundep,\r\nobat penggerek batang,\r\nobat thrips,\r\nobat kutu daun,\r\ninsektisida cabai,\r\ninsektisida bawang merah,\r\nobat daun keriting,\r\nobat daun berlubang,\r\nobat tanaman dimakan ulat,\r\nracun serangga,\r\ninsektisida klorpirifos,\r\ninsektisida sipermetrin,\r\npengendali hama daun,\r\nobat hama jagung,\r\nobat hama padi', 'Glido 200/18 EC merupakan insektisida kombinasi klorpirifos dan sipermetrin yang digunakan untuk mengendalikan ulat grayak, penggerek batang, kutu daun, dan thrips pada tanaman padi, cabai, bawang merah, jagung, serta hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat grayak, pengendali sundep, insektisida thrips, dan racun kutu daun yang menyerang daun maupun batang tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting karena thrips dan kutu daun, batang tanaman rusak akibat penggerek, serta pertumbuhan tanaman yang terganggu akibat serangan serangga penghisap.', 'Rp. 45.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 22:20:53', ''),
('45', 'Hypolax 400 SL 1 L â€“ Herbisida', 'Herbisida', 'Perkebunan, Pertanian, Lahan Kosong', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Gulma Daun Sempit, Rumput, Teki-Tekian', 'Perkebunan, Pertanian, Lahan Kosong', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air.', 'obat gulma,\r\nherbisida glyphosate,\r\nracun rumput,\r\nobat teki teki,\r\npembasmi alang alang,\r\nobat lahan penuh rumput,\r\npengendali gulma,\r\nherbisida sawit,\r\nherbisida perkebunan,\r\nobat gulma kebun,\r\nobat rumput liar,\r\ngulma daun lebar,\r\ngulma daun sempit,\r\npembersih lahan,\r\nherbisida sebelum tanam,\r\nobat lahan kosong', 'Hypolax 400 SL merupakan herbisida sistemik berbahan aktif glyphosate yang digunakan untuk mengendalikan gulma daun lebar, gulma daun sempit, rumput liar, dan teki teki pada area pertanian maupun perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, pengendali teki teki, serta pembersih lahan sebelum tanam.\r\n\r\nGejala yang dapat ditangani antara lain lahan dipenuhi rumput liar, pertumbuhan gulma yang menghambat tanaman utama, serta area perkebunan yang tertutup gulma dan semak liar.', 'Rp.60.000', '7', '1L', '-', 'Tersedia', '04/05/2026 22:22:32', ''),
('46', 'Icon 100 CS 250 ml â€“ Insektisida', 'Insektisida', 'Pertanian, Lingkungan, Gudang', 'Saat Ditemukan Hama', 'Nyamuk, Lalat, Kecoa, Serangga Pengganggu', 'Bangunan, Lingkungan, Area Pertanian', 'Dosis pemakaian umumnya sekitar 2,5 â€“ 5 ml per liter air untuk aplikasi semprot permukaan.', 'obat nyamuk,\r\ninsektisida nyamuk,\r\nobat lalat,\r\nobat kecoa,\r\nracun serangga,\r\npengendali serangga,\r\ninsektisida lambda cyhalothrin,\r\nobat hama lingkungan,\r\npengendali lalat,\r\npengendali nyamuk,\r\nobat serangga gudang,\r\ninsektisida residual,\r\nobat serangga rumah,\r\nracun kecoa', 'Icon 100 CS merupakan insektisida berbahan aktif lambda cyhalothrin yang digunakan untuk mengendalikan nyamuk, lalat, kecoa, dan berbagai serangga pengganggu pada lingkungan maupun area pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat nyamuk, racun lalat, pengendali kecoa, dan insektisida residual yang memberikan perlindungan dalam jangka waktu lama.\r\n\r\nGejala yang dapat ditangani antara lain populasi serangga yang tinggi pada lingkungan, gudang penyimpanan, area pertanian, maupun bangunan yang memerlukan pengendalian hama.', 'Rp136.000', '5', '250ml', '-', 'Tersedia', '04/05/2026 22:25:22', ''),
('47', 'Iguana 50 EC 100ml', 'Insektisida', 'Padi, Cabai, Tomat, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Kutu Daun, Thrips, Belalang', 'Sawah, Kebun', 'Dosis pemakaian Iguana 50 EC umumnya sekitar 0,25 â€“ 0,5 ml per liter air, atau sekitar 50 â€“ 100 ml per hektar, tergantung tingkat serangan. Aplikasi dilakukan dengan penyemprotan merata pada daun tanaman.', 'obat ulat grayak,\r\ninsektisida ulat,\r\nobat thrips,\r\nobat kutu daun,\r\nobat belalang,\r\nracun serangga,\r\nobat daun berlubang,\r\nobat daun keriting,\r\nobat tanaman dimakan ulat,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida jagung,\r\ninsektisida padi,\r\npengendali thrips,\r\nracun hama pengunyah,\r\nobat serangan ulat', 'Iguana 50 EC merupakan insektisida berbahan aktif golongan piretroid yang digunakan untuk mengendalikan ulat grayak, kutu daun, thrips, dan belalang pada tanaman padi, cabai, tomat, jagung, serta berbagai tanaman hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat grayak, insektisida thrips, racun kutu daun, dan pengendali belalang yang merusak tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting karena kutu daun dan thrips, tanaman rusak akibat serangan belalang, serta penurunan pertumbuhan tanaman karena hama pengunyah.', 'Rp.70.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 22:31:14', ''),
('48', 'Indodine 485 SL 1 L â€“ Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Tebu, Lahan Pra Tanam', 'Pra Tanam, Awal Pertumbuhan Gulma', 'Gulma Daun Lebar, Gulma Rumput, Teki-Tekian', 'Sawah, Lahan Kering, Perkebunan', 'Dosis pemakaian umumnya 2 â€“ 6 liter per hektar atau sekitar 5 â€“ 10 ml per liter air, tergantung kepadatan gulma', 'herbisida gulma,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput liar,\r\nobat teki teki,\r\nracun teki,\r\npengendali gulma sawah,\r\nherbisida glyphosate,\r\nobat rumput kebun,\r\npembasmi gulma perkebunan,\r\nobat rumput kelapa sawit,\r\nobat gulma jagung,\r\nobat gulma tebu,\r\nobat gulma karet,\r\ngulma daun lebar,\r\ngulma rumput,\r\ngulma teki,\r\nrumput liar,\r\nlahan penuh gulma,\r\npengendali gulma total,\r\nherbisida non selektif,\r\nherbisida sistemik', 'Indodine 485 SL merupakan herbisida sistemik berbahan aktif glyphosate yang digunakan untuk mengendalikan gulma rumput, gulma daun lebar, dan teki teki pada lahan pertanian maupun perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma, racun rumput liar, pembasmi teki teki, pengendali gulma kebun kelapa sawit, lahan karet, jagung, dan tebu.\r\n\r\nGejala yang dapat dikendalikan antara lain lahan ditumbuhi rumput liar, gulma mengganggu pertumbuhan tanaman, banyak teki teki di kebun, gulma daun lebar sulit dikendalikan, dan persaingan unsur hara akibat gulma.\r\n\r\nCocok digunakan sebelum tanam maupun saat gulma masih aktif tumbuh.\r\n\r\nDosis aplikasi 5 sampai 10 ml per liter air atau 2 sampai 6 liter per hektar tergantung kepadatan gulma.', 'Rp.75.000', '10', '1L', '-', 'Tersedia', '04/05/2026 22:33:30', ''),
('49', 'Lesenta 80 WG 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Ulat, Kutu Daun, Thrips, Serangga Penghisap', 'Sawah, Lahan Terbuka', 'Dosis pemakaian umumnya sekitar 0,5 â€“ 1 gram per liter air, atau sekitar 100 â€“ 200 gram per hektar.', 'insektisida ulat,\r\nobat ulat,\r\nracun ulat,\r\npengendali ulat,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat thrips,\r\nracun thrips,\r\npengendali thrips,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat tanaman diserang kutu,\r\nobat tanaman diserang thrips,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida bawang merah,\r\ninsektisida padi,\r\npengendali hama penghisap,\r\nobat serangga tanaman,\r\npestisida ulat daun', 'Lesenta 80 WG merupakan insektisida yang digunakan untuk mengendalikan ulat, kutu daun, thrips, dan berbagai serangga penghisap pada tanaman cabai, tomat, bawang merah, padi, dan tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai obat ulat, insektisida kutu daun, pengendali thrips, dan pestisida hama penghisap yang menyebabkan kerusakan daun maupun pertumbuhan tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting akibat kutu daun, daun menggulung, serangan thrips pada pucuk, tanaman kerdil akibat hama penghisap, dan daun rusak akibat ulat.\r\n\r\nCocok diaplikasikan pada fase vegetatif maupun generatif ketika populasi hama mulai meningkat.\r\n\r\nDosis aplikasi sekitar 0,5 sampai 1 gram per liter air atau 100 sampai 200 gram per hektar.', 'Rp152.000', '5', '100gram', '-', 'Tersedia', '04/05/2026 22:38:08', ''),
('50', 'Pexalon 106 SC 100 ml â€“ Insektisida', 'Insektisida', 'Padi', 'Vegetatif, Generatif', 'Wereng Coklat, Wereng Hijau, Hama Penghisap', 'Sawah', 'Dosis pemakaian Pexalon 106 SC umumnya sekitar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar.', 'obat wereng,\r\ninsektisida wereng,\r\nracun wereng,\r\npengendali wereng coklat,\r\nobat padi kena wereng,\r\npestisida wereng padi,\r\nobat daun padi menguning,\r\nobat hopperburn,\r\npengendali hama penghisap padi,\r\ninsektisida sistemik padi,\r\nobat wereng hijau,\r\nracun hama padi,\r\npengendali serangga padi,\r\nobat tanaman padi kerdil,\r\npestisida padi', 'Pexalon 106 SC merupakan insektisida sistemik yang dirancang khusus untuk mengendalikan wereng coklat, wereng hijau, dan hama penghisap pada tanaman padi.\r\n\r\nProduk ini banyak digunakan sebagai obat wereng padi, insektisida wereng coklat, pengendali hama penghisap, dan perlindungan tanaman padi dari kerusakan akibat serangan wereng.\r\n\r\nGejala yang dapat dikendalikan antara lain daun padi menguning, tanaman padi mengering, pertumbuhan terhambat, gejala hopperburn, dan kerusakan akibat serangan wereng.\r\n\r\nCocok digunakan pada fase vegetatif hingga generatif awal.\r\n\r\nDosis aplikasi sekitar 0,5 sampai 1 ml per liter air atau 100 sampai 200 ml per hektar.', 'Rp. 248.000', '5', '100ml', '-', 'Tersedia', '04/05/2026 22:39:12', ''),
('51', 'Sankill 100 ml â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Padi, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat, Kutu Daun, Thrips, Serangga Penghisap', 'Sawah, Lahan Terbuka', 'Dosis pemakaian Sankill umumnya sekitar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar, tergantung tingkat serangan hama. Aplikasi dilakukan dengan penyemprotan merata pada daun tanaman.', 'insektisida ulat,\r\nobat ulat,\r\nracun ulat,\r\npengendali ulat grayak,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat thrips,\r\nracun thrips,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat tanaman diserang ulat,\r\nobat tanaman diserang kutu,\r\nobat tanaman diserang thrips,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida padi,\r\ninsektisida jagung,\r\npengendali hama serangga,\r\nracun hama tanaman,\r\npestisida serangga', 'Sankill merupakan insektisida yang digunakan untuk mengendalikan ulat, kutu daun, thrips, dan berbagai serangga penghisap pada tanaman cabai, tomat, padi, jagung, dan tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai obat ulat, racun kutu daun, pengendali thrips, dan pestisida serangga yang menyerang daun, pucuk, maupun batang tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting karena kutu daun, daun menggulung, pertumbuhan tanaman terhambat, serta kerusakan pucuk akibat serangan hama penghisap.\r\n\r\nCocok diaplikasikan pada fase vegetatif hingga generatif ketika populasi hama mulai meningkat.\r\n\r\nDosis aplikasi umumnya sekitar 0,5 sampai 2 ml per liter air sesuai jenis tanaman dan tingkat serangan.', 'Rp.20.000', '4', '100ml', '-', 'Tersedia', '04/05/2026 22:40:55', ''),
('52', 'Klensect 200 EC 100ml', 'Insektisida', 'Padi, Jagung, Cabai, Kedelai, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Penggerek Batang, Kutu Daun, Thrips', 'Sawah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 ml per liter air, atau sekitar 200 â€“ 400 ml per hektar. Aplikasi dilakukan dengan penyemprotan merata pada tanaman.', 'insektisida ulat grayak,\r\nobat ulat grayak,\r\nracun ulat grayak,\r\npengendali ulat grayak,\r\nobat penggerek batang,\r\ninsektisida penggerek batang,\r\nobat kutu daun,\r\nracun kutu daun,\r\nobat thrips,\r\nracun thrips,\r\nobat daun berlubang,\r\nobat daun keriting,\r\nobat tanaman dimakan ulat,\r\nobat tanaman terserang thrips,\r\nobat tanaman terserang kutu,\r\ninsektisida cabai,\r\ninsektisida padi,\r\ninsektisida jagung,\r\ninsektisida kedelai,\r\npengendali hama serangga', 'Klensect 200 EC merupakan insektisida berbahan aktif golongan organofosfat yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat grayak, penggerek batang, kutu daun, dan thrips pada tanaman padi, jagung, cabai, kedelai, dan hortikultura.\r\n\r\nProduk ini digunakan sebagai obat ulat grayak, insektisida penggerek batang, pengendali kutu daun, dan pestisida thrips yang menyerang berbagai tanaman pertanian.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, batang tanaman rusak karena penggerek, daun keriting akibat kutu daun, pucuk tanaman rusak karena thrips, serta pertumbuhan tanaman yang terhambat akibat serangan hama.\r\n\r\nCocok diaplikasikan pada fase vegetatif hingga generatif saat populasi hama mulai meningkat.\r\n\r\nDosis aplikasi 1 sampai 2 ml per liter air atau sekitar 200 sampai 400 ml per hektar.', 'Rp.20.000', '5', '100ml', 'â€”', 'Tersedia', '04/05/2026 22:52:13', ''),
('53', 'Lannate 25 WP 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Kubis, Bawang Merah, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Lalat', 'Lahan Terbuka, Sawah', 'Dosis pemakaian umumnya 1 â€“ 2 gram per liter air, atau sekitar 200 â€“ 400 gram per hektar.', 'insektisida ulat grayak,\r\nobat ulat grayak,\r\nracun ulat,\r\nobat thrips,\r\nracun thrips,\r\nobat kutu daun,\r\nracun kutu daun,\r\nobat lalat tanaman,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida kubis,\r\ninsektisida bawang merah,\r\nobat daun berlubang,\r\nobat daun keriting,\r\nobat pucuk rusak,\r\nobat tanaman diserang ulat,\r\npengendali hama serangga,\r\npestisida hortikultura,\r\nobat hama daun,\r\nracun hama tanaman', 'Lannate 25 WP merupakan insektisida berbahan aktif methomyl yang bekerja sebagai racun kontak dan lambung dengan efek knockdown cepat untuk mengendalikan ulat grayak, thrips, kutu daun, dan lalat pada tanaman cabai, tomat, kubis, dan bawang merah.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat grayak, insektisida thrips, pengendali kutu daun, dan pestisida serangga pada tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting karena kutu daun, pucuk tanaman rusak akibat thrips, tanaman layu karena serangan hama, dan kerusakan daun yang menurunkan hasil panen.\r\n\r\nCocok digunakan saat populasi hama meningkat pada fase vegetatif maupun generatif.\r\n\r\nDosis aplikasi 1 sampai 2 gram per liter air atau sekitar 200 sampai 400 gram per hektar.', 'Rp.20.000', '20', '100gram,15gram, 250gram, 500gram', '-', 'Tersedia', '04/05/2026 22:55:52', ''),
('54', 'Lannate 40 SP 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Kubis, Bawang Merah, Sayuran', 'Vegetatif, Generatif', 'Ulat, Thrips, Kutu Daun, Lalat Buah', 'Lahan Terbuka, Sawah', 'Dosis pemakaian umumnya 0,5 â€“ 1 gram per liter air, atau sekitar 150 â€“ 300 gram per hektar.', 'insektisida ulat,\r\nobat ulat,\r\nracun ulat,\r\nobat thrips,\r\nracun thrips,\r\nobat kutu daun,\r\nobat lalat buah,\r\npengendali lalat buah,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida kubis,\r\ninsektisida bawang merah,\r\nobat buah rusak,\r\nobat daun keriting,\r\nobat daun berlubang,\r\nobat tanaman terserang ulat,\r\npengendali hama sayuran,\r\nracun serangga tanaman,\r\nobat hama buah,\r\npestisida hortikultura', 'Lannate 40 SP merupakan insektisida berbahan aktif methomyl konsentrasi tinggi yang digunakan untuk mengendalikan ulat, thrips, kutu daun, dan lalat buah pada tanaman cabai, tomat, kubis, bawang merah, dan berbagai sayuran.\r\n\r\nProduk ini digunakan sebagai obat ulat, insektisida lalat buah, pengendali thrips, dan pestisida kutu daun yang menyerang tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, daun keriting, buah rusak akibat lalat buah, pucuk tanaman rusak, dan pertumbuhan tanaman yang terganggu akibat serangan serangga.\r\n\r\nCocok digunakan saat serangan hama mulai terlihat pada fase vegetatif maupun generatif.\r\n\r\nDosis aplikasi 0,5 sampai 1 gram per liter air atau sekitar 150 sampai 300 gram per hektar.', 'Rp.30.000', '20', '100gr, 15gr, 250gr', '-', 'Tersedia', '04/05/2026 23:00:39', ''),
('55', 'Larvin 75 WP 100 gr â€“ Insektisida', 'Insektisida', 'Kedelai, Kapas, Cabai, Tomat, Jagung', 'Vegetatif, Generatif', 'Ulat Grayak, Ulat Buah, Penggerek Tanaman', 'Sawah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 gram per liter air, atau sekitar 200 â€“ 400 gram per hektar.', 'insektisida ulat grayak,\r\nobat ulat grayak,\r\nracun ulat buah,\r\nobat ulat buah,\r\npengendali penggerek,\r\nobat penggerek tanaman,\r\ninsektisida kedelai,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida jagung,\r\nobat daun berlubang,\r\nobat buah berlubang,\r\nobat tanaman dimakan ulat,\r\nobat tanaman terserang penggerek,\r\nracun larva,\r\npengendali ulat tanaman,\r\nobat hama pemakan daun,\r\npestisida ulat,\r\nobat hama buah,\r\ninsektisida larva', 'Larvin 75 WP merupakan insektisida berbahan aktif thiodicarb yang bekerja sebagai racun lambung dan kontak untuk mengendalikan ulat grayak, ulat buah, dan penggerek tanaman pada kedelai, kapas, cabai, tomat, dan jagung.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat grayak, insektisida ulat buah, pengendali penggerek tanaman, dan pestisida larva serangga.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, buah rusak karena ulat buah, batang terserang penggerek, tanaman muda rusak akibat larva, dan pertumbuhan tanaman yang terhambat.\r\n\r\nCocok diaplikasikan sejak awal serangan hama untuk mencegah kerusakan yang lebih luas.\r\n\r\nDosis aplikasi 1 sampai 2 gram per liter air atau sekitar 200 sampai 400 gram per hektar.', 'Rp. 70.000', '4', '100gr, 15gr', '-', 'Tersedia', '04/05/2026 23:03:14', ''),
('56', 'Manthene 75 SP 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Padi, Bawang Merah, Hortikultura', 'Vegetatif, Generatif', 'Kutu Daun, Thrips, Ulat, Serangga Penghisap', 'Sawah, Lahan Terbuka', 'Dosis pemakaian umumnya 0,5 â€“ 1 gram per liter air, atau sekitar 100 â€“ 200 gram per hektar.', 'obat kutu daun,\r\ninsektisida kutu daun,\r\nobat thrips,\r\nracun thrips,\r\nobat ulat,\r\nracun ulat,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat tanaman diserang kutu,\r\nobat tanaman diserang thrips,\r\nobat tanaman diserang ulat,\r\ninsektisida cabai,\r\ninsektisida padi,\r\ninsektisida bawang merah,\r\npengendali hama penghisap,\r\nracun serangga tanaman,\r\nobat pucuk rusak,\r\nobat tanaman kerdil,\r\npestisida hortikultura,\r\npengendali hama serangga', 'Manthene 75 SP merupakan insektisida yang digunakan untuk mengendalikan kutu daun, thrips, ulat, dan berbagai serangga penghisap pada tanaman cabai, padi, bawang merah, dan tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai obat kutu daun, insektisida thrips, pengendali ulat, dan pestisida serangga penghisap yang menyebabkan kerusakan daun dan pucuk tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting akibat kutu daun, daun menggulung karena thrips, daun berlubang akibat ulat, pucuk tanaman rusak, serta pertumbuhan tanaman terhambat akibat serangan hama.\r\n\r\nCocok diaplikasikan pada fase vegetatif maupun generatif ketika populasi hama mulai meningkat.\r\n\r\nDosis aplikasi 0,5 sampai 1 gram per liter air atau sekitar 100 sampai 200 gram per hektar.', 'Rp.', '5', '100gr, 400gr', '-', 'Tersedia', '04/05/2026 23:07:11', ''),
('57', 'Marshal 200 EC 500 ml â€“ Insektisida / Nematisida', 'Insektisida', 'Padi, Jagung, Tebu, Kentang, Sayuran', 'Vegetatif, Generatif Awal', 'Wereng, Penggerek Batang, Ulat Tanah, Nematoda', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 ml per liter air, atau sekitar 200 â€“ 500 ml per hektar.', 'insektisida wereng,\r\nobat wereng padi,\r\npestisida wereng,\r\nobat penggerek batang,\r\ninsektisida penggerek batang,\r\nobat sundep,\r\nobat beluk,\r\npengendali ulat tanah,\r\nobat nematoda,\r\nnematisida tanaman,\r\ninsektisida jagung,\r\ninsektisida tebu,\r\ninsektisida kentang,\r\nobat akar rusak,\r\nobat tanaman layu karena nematoda,\r\nhama penghisap,\r\nobat hama padi,\r\nobat hama jagung,\r\ncarbosulfan,\r\nmarshal 200 ec', 'Marshal 200 EC merupakan insektisida dan nematisida berbahan aktif carbosulfan yang bekerja secara sistemik, kontak, dan lambung untuk mengendalikan wereng, penggerek batang, ulat tanah, serta nematoda pada tanaman padi, jagung, tebu, kentang, dan berbagai sayuran.\r\n\r\nProduk ini banyak digunakan sebagai obat wereng padi, insektisida penggerek batang, obat sundep, obat beluk, pengendali ulat tanah, dan nematisida untuk mengatasi gangguan akar tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain tanaman padi menguning akibat wereng, batang tanaman rusak akibat penggerek batang, tanaman rebah karena sundep, akar rusak akibat nematoda, pertumbuhan tanaman terhambat, serta serangan ulat tanah pada tanaman muda.\r\n\r\nDosis pemakaian umumnya 1â€“2 ml per liter air atau 200â€“500 ml per hektar dengan aplikasi semprot merata pada tanaman yang terserang.', '68.000', '5', '500ml', '-', 'Tersedia', '05/05/2026 15:07:01', ''),
('58', 'Matador 25 EC 80 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Tomat, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Belalang', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Matador 25 EC umumnya 0,25 â€“ 0,5 ml per liter air, atau sekitar 50 â€“ 100 ml per hektar, tergantung tingkat serangan hama', 'obat ulat grayak,\r\ninsektisida ulat grayak,\r\npestisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat belalang,\r\npengendali serangga pengunyah,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama cabai,\r\nhama tomat,\r\nhama jagung,\r\nhama padi,\r\nlambda cyhalothrin,\r\nmatador 25 ec', 'Matador 25 EC merupakan insektisida berbahan aktif lambda-cyhalothrin yang bekerja sebagai racun kontak dan lambung dengan efek knockdown cepat untuk mengendalikan ulat grayak, thrips, kutu daun, dan belalang.\r\n\r\nProduk ini digunakan sebagai insektisida ulat grayak, obat thrips cabai, pengendali kutu daun, dan pestisida untuk hama pengunyah pada tanaman padi, cabai, tomat, jagung, serta tanaman hortikultura lainnya.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, pertumbuhan tanaman terganggu karena kutu daun, dan kerusakan daun akibat belalang.\r\n\r\nDosis pemakaian umumnya 0,25â€“0,5 ml per liter air atau 50â€“100 ml per hektar dengan penyemprotan merata pada tanaman.', 'Rp.25.000', '25', '50ml, 80ml, 250ml', '-', 'Tersedia', '05/05/2026 15:15:24', ''),
('59', 'Metha 400 EC 500 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Tomat, Kedelai, Hortikultura', 'Vegetatif', 'Kutu Daun, Wereng, Thrips, Serangga Penghisap', 'Sawah, Tanah', 'Dosis pemakaian umumnya 1 â€“ 2 ml per liter air, atau sekitar 200 â€“ 400 ml per hektar.', 'obat wereng,\r\ninsektisida wereng,\r\nobat kutu daun,\r\nobat thrips,\r\npengendali serangga penghisap,\r\ninsektisida sistemik,\r\nobat daun keriting,\r\nobat daun menguning,\r\nhama padi,\r\nhama cabai,\r\nhama tomat,\r\nhama kedelai,\r\ndimetoat,\r\ndimethoate,\r\nmetha 400 ec', 'Metha 400 EC merupakan insektisida sistemik berbahan aktif dimetoat yang digunakan untuk mengendalikan kutu daun, wereng, thrips, dan berbagai serangga penghisap pada tanaman padi, cabai, tomat, kedelai, dan hortikultura.\r\n\r\nProduk ini sering digunakan sebagai obat wereng padi, pengendali kutu daun cabai, insektisida thrips, dan pestisida serangga penghisap yang menyerang tanaman budidaya.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menguning, pertumbuhan tanaman terhambat, tanaman kerdil akibat serangan wereng, serta kerusakan akibat kutu daun dan thrips.\r\n\r\nDosis pemakaian umumnya 1â€“2 ml per liter air atau 200â€“400 ml per hektar.', 'Rp.75.000', '3', '500ml', '-', 'Tersedia', '05/05/2026 15:17:50', ''),
('60', 'Metindo 25 WP 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Kubis, Bawang Merah, Sayuran', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Lalat Buah', 'Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 gram per liter air, atau sekitar 200 â€“ 400 gram per hektar.', 'obat ulat grayak,\r\ninsektisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\nobat lalat buah,\r\npengendali ulat cabai,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama bawang merah,\r\nhama tomat,\r\nhama kubis,\r\nmethomyl,\r\nmetindo 25 wp', 'Metindo 25 WP merupakan insektisida berbahan aktif methomyl yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat grayak, thrips, kutu daun, dan lalat buah.\r\n\r\nProduk ini digunakan sebagai insektisida ulat grayak, obat thrips cabai, pengendali kutu daun, dan pestisida lalat buah pada tanaman cabai, tomat, kubis, bawang merah, serta sayuran lainnya.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, buah rusak karena lalat buah, dan pertumbuhan tanaman terganggu akibat kutu daun.\r\n\r\nDosis pemakaian umumnya 1â€“2 gram per liter air atau 200â€“400 gram per hektar.', 'Rp.16.000', '5', '100gr, 250gr, 50gr', '-', 'Tersedia', '05/05/2026 15:28:40', ''),
('61', 'Metindo 40 SP 200gr', 'Insektisida', 'Cabai, Tomat, Kubis, Bawang Merah, Hortikultura', 'Vegetatif, Generatif', 'Ulat, Thrips, Kutu Daun, Lalat Buah', 'Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 0,5 â€“ 1 gram per liter air, atau sekitar 150 â€“ 300 gram per hektar', 'obat ulat,\r\ninsektisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\nobat lalat buah,\r\npengendali serangga penghisap,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama tomat,\r\nhama kubis,\r\nhama bawang merah,\r\nmethomyl,\r\nmetindo 40 sp', 'Metindo 40 SP merupakan insektisida berbahan aktif methomyl dengan konsentrasi tinggi yang digunakan untuk mengendalikan ulat, thrips, kutu daun, dan lalat buah pada tanaman cabai, tomat, kubis, bawang merah, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai obat ulat, insektisida thrips, pengendali kutu daun, serta pestisida lalat buah yang menyebabkan kerusakan pada tanaman dan hasil panen.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, serangan kutu daun pada pucuk tanaman, dan buah rusak akibat lalat buah.\r\n\r\nDosis pemakaian umumnya 0,5â€“1 gram per liter air atau 150â€“300 gram per hektar dengan penyemprotan merata pada tanaman yang terserang.', 'Rp.45.000', '6', '100gr, 200gr', '-', 'Tersedia', '05/05/2026 15:30:38', '');
INSERT INTO `dataproduk` (`COL 1`, `COL 2`, `COL 3`, `COL 4`, `COL 5`, `COL 6`, `COL 7`, `COL 8`, `COL 9`, `COL 10`, `COL 11`, `COL 12`, `COL 13`, `COL 14`, `COL 15`, `COL 16`, `COL 17`) VALUES
('62', 'Mexican 300 EC 80ml', 'Insektisida', 'Cabai, Padi, Bawang Merah, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 gram per liter air atau 200 â€“ 400 gram per hektar', 'obat ulat grayak,\r\ninsektisida ulat grayak,\r\npestisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat penggerek batang,\r\nobat sundep,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama cabai,\r\nhama bawang merah,\r\nhama padi,\r\nprofenofos,\r\nmexican 300 ec,\r\nracun kontak,\r\nracun lambung', 'Mexican 300 EC merupakan insektisida berbahan aktif profenofos yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat grayak, thrips, kutu daun, serta penggerek pada tanaman cabai, padi, bawang merah, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai insektisida ulat grayak, obat thrips cabai, pengendali kutu daun, obat sundep, dan pestisida penggerek batang yang sering menyebabkan kerusakan tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, pucuk tanaman rusak akibat kutu daun, batang tanaman terserang penggerek, serta pertumbuhan tanaman yang terganggu karena serangan hama.\r\n\r\nDosis pemakaian umumnya 1â€“2 ml per liter air atau 200â€“400 ml per hektar dengan penyemprotan merata pada tanaman yang terserang.', 'Rp.60.000', '5', '80ml', '-', 'Tersedia', '05/05/2026 15:56:45', ''),
('63', 'Mipcinta 50 WP 100gr', 'Insektisida', 'Padi, Sayuran', 'Vegetatif', 'Wereng, Kutu Daun, Serangga Penghisap', 'Sawah, Tanah', 'Dosis pemakaian umumnya 1 â€“ 2 gram per liter air atau 200 â€“ 400 gram per hektar.', 'obat wereng,\r\ninsektisida wereng,\r\npestisida wereng padi,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat hama penghisap,\r\npengendali wereng coklat,\r\nobat tanaman kerdil,\r\nobat daun menguning,\r\nhama padi,\r\nhama sayuran,\r\nmipc,\r\nisoprocarb,\r\nmipcinta 50 wp,\r\ninsektisida sistemik ringan', 'Mipcinta 50 WP merupakan insektisida berbahan aktif MIPC (isoprocarb) yang bekerja sebagai racun kontak dan sistemik ringan untuk mengendalikan wereng, kutu daun, dan berbagai serangga penghisap pada tanaman padi dan sayuran.\r\n\r\nProduk ini digunakan sebagai obat wereng padi, insektisida kutu daun, pengendali hama penghisap, dan pestisida untuk mengatasi serangan wereng coklat pada lahan budidaya.\r\n\r\nGejala yang dapat dikendalikan antara lain tanaman padi menguning, pertumbuhan tanaman kerdil, daun menggulung akibat serangan hama penghisap, serta kerusakan pucuk tanaman karena kutu daun.\r\n\r\nDosis pemakaian umumnya 1â€“2 gram per liter air atau 200â€“400 gram per hektar.', 'Rp.15.000', '6', '100gr', '-', 'Tersedia', '05/05/2026 15:58:55', ''),
('64', 'Miramar 40 SP 100 gr â€“ Insektisida', 'Insektisida', 'Cabai, Tomat, Kubis, Sayuran', 'Vegetatif, Generatif', 'Ulat, Thrips, Kutu Daun, Lalat Buah', 'Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 0,5 â€“ 1 gram per liter air atau 100 â€“ 200 gram per hektar', 'obat ulat,\r\ninsektisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\npengendali hama cabai,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama tomat,\r\nhama kubis,\r\nhama sayuran,\r\nmiramar 40 sp,\r\nracun kontak,\r\nracun lambung', 'Miramar 40 SP merupakan insektisida yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat, thrips, dan kutu daun pada tanaman cabai, tomat, kubis, serta berbagai tanaman sayuran.\r\n\r\nProduk ini digunakan sebagai insektisida ulat, obat thrips cabai, pengendali kutu daun, dan pestisida untuk mengatasi serangan hama yang merusak daun dan pucuk tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, pucuk tanaman rusak akibat kutu daun, dan pertumbuhan tanaman yang terhambat karena serangan serangga.\r\n\r\nDosis pemakaian umumnya 0,5â€“1 gram per liter air atau 100â€“200 gram per hektar.', 'Rp.24.000', '10', '100gr, 400gr', '-', 'Tersedia', '05/05/2026 16:00:31', ''),
('65', 'Monalisa 333 SC 100 ml â€“ Insektisida', 'Insektisida', 'Padi, Cabai, Tomat, Hortikultura', 'Vegetatif', 'Kutu Daun, Wereng, Kutu Kebul', 'Sawah, Tanah', 'Dosis pemakaian umumnya 0,25 â€“ 0,5 ml per liter air atau 50 â€“ 100 ml per hektar.', 'obat wereng,\r\ninsektisida wereng,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat kutu kebul,\r\nobat kutu putih,\r\npengendali hama penghisap,\r\nobat daun keriting,\r\nobat tanaman kerdil,\r\nobat daun menguning,\r\nhama cabai,\r\nhama tomat,\r\nhama padi,\r\nimidacloprid,\r\nmonalisa 333 sc,\r\ninsektisida sistemik', 'Monalisa 333 SC merupakan insektisida sistemik golongan neonikotinoid yang digunakan untuk mengendalikan kutu daun, wereng, dan kutu kebul pada tanaman padi, cabai, tomat, serta berbagai tanaman hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat wereng padi, insektisida kutu daun, obat kutu kebul, dan pengendali hama penghisap yang sering menyerang pucuk serta daun muda tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menguning, tanaman kerdil akibat wereng, serangan kutu putih, serta pertumbuhan tanaman yang terhambat karena hama penghisap.\r\n\r\nDosis pemakaian umumnya 0,25â€“0,5 ml per liter air atau 50â€“100 ml per hektar.', 'Rp.77.000', '8', '100ml, 200ml', '-', 'Tersedia', '05/05/2026 16:12:50', ''),
('66', 'Neoban Plus 600 EC 100ml', 'Insektisida', 'Cabai, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Ulat, Thrips, Kutu Daun, Penggerek', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 ml per liter air atau 200 â€“ 400 ml per hektar.', 'obat ulat,\r\ninsektisida ulat,\r\nobat thrips,\r\ninsektisida thrips,\r\nobat kutu daun,\r\ninsektisida kutu daun,\r\nobat penggerek batang,\r\nobat sundep,\r\nobat daun berlubang,\r\nobat cabai keriting,\r\nhama cabai,\r\nhama bawang merah,\r\nhama padi,\r\nprofenofos,\r\nneoban plus 600 ec,\r\nracun kontak,\r\nracun lambung', 'Neoban Plus 600 EC merupakan insektisida berbahan aktif profenofos yang bekerja sebagai racun kontak dan lambung untuk mengendalikan ulat, thrips, kutu daun, serta penggerek pada tanaman cabai, bawang merah, padi, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini digunakan sebagai insektisida ulat, obat thrips cabai, pengendali kutu daun, obat sundep, dan pestisida penggerek batang yang sering menurunkan hasil panen.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang akibat ulat, daun keriting akibat thrips, kerusakan pucuk karena kutu daun, batang tanaman terserang penggerek, serta pertumbuhan tanaman yang terganggu akibat serangan hama.\r\n\r\nDosis pemakaian umumnya 1â€“2 ml per liter air atau 200â€“400 ml per hektar dengan penyemprotan merata pada tanaman yang terserang.', 'Rp.20.000', '8', '100ml, 500ml', '-', 'Tersedia', '05/05/2026 16:15:43', ''),
('67', 'New Mexican 300 EC 200 ml â€“ Insektisida', 'Insektisida', 'Cabai, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Tanah, Sawah, Lahan Terbuka', 'Dosis pemakaian umumnya 1 â€“ 2 ml per liter air atau 200 â€“ 400 ml per hektar', 'obat ulat grayak,\r\npestisida ulat,\r\ninsektisida ulat,\r\nobat thrips,\r\nobat trips,\r\npestisida thrips,\r\nobat kutu daun,\r\ndaun keriting,\r\ncabai keriting,\r\nobat penggerek,\r\npenggerek batang,\r\nobat hama cabai,\r\nhama bawang,\r\nobat ulat cabai,\r\nobat ulat bawang,\r\nobat ulat padi,\r\nserangan ulat,\r\ndaun berlubang,\r\nhama pemakan daun,\r\nracun ulat,\r\nobat tanaman dimakan ulat', 'New Mexican 300 EC merupakan insektisida racun kontak dan lambung untuk mengendalikan ulat grayak, thrips, kutu daun, dan penggerek pada tanaman cabai, bawang merah, padi, serta tanaman hortikultura.\r\n\r\nProduk ini sering digunakan sebagai obat ulat cabai, obat trips cabai, obat kutu daun, pestisida daun keriting, dan pengendali penggerek batang.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, daun keriting akibat kutu daun, serangan thrips pada cabai, pertumbuhan tanaman terganggu, dan kerusakan batang akibat penggerek.\r\n\r\nDosis penggunaan 1â€“2 ml per liter air atau sekitar 200â€“400 ml per hektar.', 'Rp120.000', '5', '200ml', '-', 'Tersedia', '05/05/2026 16:17:39', ''),
('68', 'Nurelle D 500/50 EC 100ml', 'Insektisida', 'Padi, Jagung, Cabai, Kedelai', 'Vegetatif, Generatif', 'Ulat Grayak, Penggerek Batang, Thrips, Kutu Daun', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian umumnya 0,5 â€“ 1 ml per liter air atau 100 â€“ 200 ml per hektar.', 'obat ulat grayak,\r\nobat sundep,\r\npenggerek batang,\r\ninsektisida padi,\r\nobat wereng,\r\nobat thrips,\r\nobat trips,\r\nobat kutu daun,\r\nobat ulat jagung,\r\nobat ulat cabai,\r\nhama pengunyah,\r\ndaun berlubang,\r\nbatang padi rusak,\r\nsundep padi,\r\nbeluk padi,\r\nracun ulat,\r\npestisida ulat,\r\nobat hama padi', 'Nurelle D 500/50 EC merupakan insektisida kombinasi chlorpyrifos dan cypermethrin yang efektif mengendalikan ulat grayak, penggerek batang, thrips, dan kutu daun.\r\n\r\nProduk ini digunakan sebagai obat sundep padi, pengendali penggerek batang, obat ulat cabai, obat trips, serta pestisida untuk tanaman jagung dan kedelai.\r\n\r\nGejala yang dapat dikendalikan meliputi daun berlubang, sundep pada padi, batang rusak akibat penggerek, serta daun keriting akibat serangan kutu daun dan thrips.\r\n\r\nDosis penggunaan 0,5â€“1 ml per liter air.', 'Rp.25.000', '6', '100ml, 500ml', '-', 'Tersedia', '05/05/2026 16:18:59', ''),
('69', 'Ovistop 100 EC', 'Insektisida', 'Cabai, Tomat, Jeruk, Teh', 'Awal Vegetatif, Vegetatif', 'Tungau, Kutu Daun, Thrips, Telur Hama', 'Tanah, Kebun, Lahan Terbuka', 'Dosis pemakaian Ovistop 100 EC umumnya sekitar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar, tergantung tingkat serangan.', 'obat tungau,\r\nobat kutu merah,\r\nobat kutu kuning,\r\nakarisida,\r\nobat telur hama,\r\nobat thrips,\r\nobat trips,\r\nobat kutu daun,\r\ndaun keriting,\r\ndaun keriting cabai,\r\ncabai keriting,\r\nobat hama cabai,\r\nhama putih daun,\r\nobat kutu kebul,\r\nobat pencegah hama,\r\npengendali telur hama,\r\nobat tungau cabai', 'Ovistop 100 EC merupakan insektisida dan akarisida yang bekerja membunuh telur hama, tungau, thrips, dan kutu daun pada tanaman cabai, tomat, jeruk, dan teh.\r\n\r\nProduk ini sering digunakan sebagai obat kutu merah, obat tungau cabai, obat trips, obat kutu daun, dan pengendali telur hama sebelum populasi berkembang.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menguning, bercak akibat tungau, serangan thrips, serta kutu daun pada tanaman hortikultura.\r\n\r\nDosis penggunaan 0,5â€“1 ml per liter air.', 'Rp.47.000', '5', '100ml', '-', 'Tersedia', '05/05/2026 16:38:56', ''),
('70', 'Pegasus 500 SC 80 ml â€“ Insektisida / Akarisida', 'Insektisida, Akarisida', 'Cabai, Tomat, Kapas, Teh', 'Vegetatif, Generatif', 'Tungau, Kutu Kebul, Thrips, Kutu Daun', 'Tanah, Kebun, Lahan Terbuka', 'Dosis pemakaian Pegasus 500 SC umumnya sekitar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar.', 'obat kutu kebul,\r\nobat kebul,\r\nobat tungau,\r\nobat kutu merah,\r\nobat thrips,\r\nobat trips,\r\ncabai keriting,\r\ndaun keriting,\r\nobat kutu daun,\r\nhama putih bawah daun,\r\nkutu putih,\r\nobat hama cabai,\r\nakarisida cabai,\r\ninsektisida cabai,\r\nobat serangga penghisap,\r\nobat tanaman keriting', 'Pegasus 500 SC merupakan insektisida dan akarisida yang digunakan untuk mengendalikan tungau, kutu kebul, thrips, dan kutu daun pada tanaman cabai, tomat, kapas, dan teh.\r\n\r\nProduk ini sering digunakan sebagai obat kutu kebul cabai, obat kutu putih, obat daun keriting, obat trips cabai, serta pengendali tungau yang telah resisten terhadap insektisida lain.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menguning, pertumbuhan tanaman terhambat, kutu putih bawah daun, dan serangan hama penghisap.\r\n\r\nDosis penggunaan 0,5â€“1 ml per liter air.', 'Rp.85.000', '5', '80ml', '-', 'Tersedia', '05/05/2026 16:40:07', ''),
('71', 'PEXALON 106 SC 100 ml', 'Insektisida', 'Padi', 'Vegetatif', 'Wereng Coklat', 'Sawah', 'Dosis pemakaian Pexalon 106 SC umumnya sekitar 0,5 â€“ 1 ml per liter air, atau sekitar 100 â€“ 200 ml per hektar. Aplikasi dilakukan dengan penyemprotan merata pada tanaman padi saat gejala awal serangan muncul.', 'obat wereng,\r\ninsektisida wereng,\r\nobat wereng coklat,\r\nwereng padi,\r\npadi hopperburn,\r\nobat hama padi,\r\nobat padi menguning,\r\npengendali wereng,\r\nobat serangga penghisap,\r\ninsektisida padi,\r\nobat padi kering,\r\ndaun padi menguning,\r\nhama penghisap padi,\r\nobat padi terserang wereng,\r\nobat sawah', 'Pexalon 106 SC merupakan insektisida sistemik dan kontak yang dirancang khusus untuk mengendalikan wereng coklat pada tanaman padi.\r\n\r\nProduk ini digunakan sebagai obat wereng padi, insektisida sawah, pengendali hama penghisap, dan perlindungan tanaman padi dari serangan wereng.\r\n\r\nGejala yang dapat dikendalikan antara lain daun padi menguning, hopperburn, tanaman mengering, pertumbuhan terhambat, dan kerusakan akibat serangan wereng coklat.\r\n\r\nDosis penggunaan 0,5â€“1 ml per liter air atau sekitar 100â€“200 ml per hektar.', 'Rp248.000', '5', '100ml', '-', 'Tersedia', '05/05/2026 16:41:31', ''),
('72', 'Pixel 300 SL', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Lahan Persiapan Tanam', 'Pra Tanam, Pra Tanam Awal', 'Gulma Rumput, Gulma Daun Lebar, Gulma Muda', 'Kebun, Lahan Terbuka, Perkebunan', 'Dosis pemakaian Pixel 300 SL umumnya sekitar 2 â€“ 4 ml per liter air atau 2 â€“ 5 liter per hektar, tergantung kepadatan gulma.', 'herbisida,\r\nobat gulma,\r\nracun rumput,\r\npembasmi rumput,\r\nobat rumput liar,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\ngulma teki,\r\ngulma daun lebar,\r\nrumput kebun,\r\nrumput sawit,\r\nrumput karet,\r\nsemprot rumput,\r\nobat rumput bandel,\r\nrumput liar kebun,\r\nbersihkan lahan,\r\npersiapan tanam,\r\nsemprot gulma,\r\nobat gulma sawit,\r\nobat gulma jagung,\r\npengendali gulma,\r\nrumput cepat mati,\r\nherbisida kontak,\r\nparaquat,\r\npixel 300 sl', 'Pixel 300 SL merupakan herbisida kontak berbahan aktif paraquat yang digunakan untuk mengendalikan gulma rumput, gulma daun lebar, dan gulma muda pada perkebunan kelapa sawit, karet, jagung, serta lahan sebelum tanam.\r\n\r\nProduk ini sering digunakan sebagai obat gulma, racun rumput, pembasmi alang alang, obat teki, semprot rumput liar, dan pengendali gulma pada lahan pertanian.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma berlebihan, lahan tertutup rumput liar, alang alang yang mendominasi kebun, serta gulma yang mengganggu pertumbuhan tanaman utama.\r\n\r\nDosis penggunaan 2â€“4 ml per liter air atau 2â€“5 liter per hektar.', 'Rp100.000', '5', '200ml', '-', 'Tersedia', '05/05/2026 16:45:57', ''),
('73', 'Plenum 50 WG 100gr', 'Insektisida', 'Padi, Cabai, Kentang, Sayuran', 'Vegetatif, Generatif Awal', 'Wereng, Kutu Daun, Kutu Kebul', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Plenum 50 WG umumnya sekitar 0,25 â€“ 0,5 gram per liter air atau 50 â€“ 100 gram per hektar.', 'obat wereng,\r\ninsektisida wereng,\r\nobat wereng coklat,\r\npadi kena wereng,\r\nobat kutu daun,\r\ncabai keriting,\r\ndaun keriting,\r\nobat kutu kebul,\r\nkutu putih,\r\nhama putih bawah daun,\r\nobat penghisap daun,\r\ninsektisida sistemik,\r\nobat padi menguning,\r\nhopperburn,\r\nobat tanaman keriting,\r\npengendali wereng,\r\npengendali kutu daun,\r\nplenum,\r\nplenum 50 wg', 'Plenum 50 WG merupakan insektisida sistemik berbahan aktif pymetrozine yang efektif mengendalikan wereng, kutu daun, dan kutu kebul pada tanaman padi, cabai, kentang, serta sayuran.\r\n\r\nProduk ini sering digunakan sebagai obat wereng padi, obat kutu daun cabai, obat kutu kebul, dan pengendali hama penghisap yang menyebabkan tanaman keriting.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menguning, serangan kutu putih, hopperburn pada padi, dan pertumbuhan tanaman terhambat akibat hama penghisap.\r\n\r\nDosis penggunaan 0,25â€“0,5 gram per liter air.', 'Rp185.000', '5', '100gr, 25gr,', '-', 'Tersedia', '05/05/2026 16:47:03', ''),
('74', 'Prevathon 50 SC 100 ml â€“ Insektisida', 'Insektisida', 'Padi, Jagung, Cabai, Tomat', 'Vegetatif, Generatif', 'Ulat Grayak, Ulat Buah, Penggerek', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Prevathon 50 SC umumnya sekitar 0,3 â€“ 0,5 ml per liter air atau 75 â€“ 150 ml per hektar.', 'obat ulat,\r\nobat ulat grayak,\r\nulat grayak cabai,\r\nulat jagung,\r\nulat buah,\r\nulat makan daun,\r\ndaun berlubang,\r\nobat penggerek,\r\npenggerek batang,\r\nobat sundep,\r\nsundep padi,\r\nbeluk padi,\r\nobat ulat tomat,\r\nobat ulat cabai,\r\ninsektisida ulat,\r\nracun ulat,\r\nobat hama pemakan daun,\r\nobat larva,\r\nchlorantraniliprole,\r\nprevathon', 'Prevathon 50 SC merupakan insektisida berbahan aktif chlorantraniliprole yang digunakan untuk mengendalikan ulat grayak, ulat buah, dan penggerek tanaman.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat cabai, obat ulat jagung, obat sundep padi, pengendali penggerek batang, dan pengendali larva serangga.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, serangan ulat pemakan daun, buah rusak akibat ulat, sundep pada padi, dan kerusakan batang akibat penggerek.\r\n\r\nDosis penggunaan 0,3â€“0,5 ml per liter air.', 'Rp.65.000', '8', '100ml, 250ml', '-', 'Tersedia', '05/05/2026 16:48:29', ''),
('75', 'Rahwana 500 EC - 500ml', 'Insektisida', 'Padi, Jagung, Kedelai, Tebu, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Penggerek Batang, Hama Tanah', 'Sawah, Tanah, Lahan Terbuka', 'Dosis pemakaian Rahwana 500 EC umumnya sekitar 1 â€“ 2 ml per liter air atau 200 â€“ 400 ml per hektar.', 'obat ulat grayak,\r\nobat ulat tanah,\r\nhama tanah,\r\nobat penggerek,\r\npenggerek batang,\r\nobat sundep,\r\nsundep padi,\r\nbeluk padi,\r\nulat jagung,\r\nulat kedelai,\r\ninsektisida padi,\r\ninsektisida jagung,\r\nobat tanaman dimakan ulat,\r\nracun ulat,\r\nobat hama tebu,\r\nobat ulat pemakan daun,\r\ndaun berlubang,\r\nhama batang,\r\nklorpirifos,\r\nrahwana 500 ec', 'Rahwana 500 EC merupakan insektisida berbahan aktif klorpirifos yang digunakan untuk mengendalikan ulat grayak, penggerek batang, dan hama tanah pada tanaman padi, jagung, kedelai, tebu, dan hortikultura.\r\n\r\nProduk ini sering digunakan sebagai obat ulat grayak, obat sundep padi, pengendali penggerek batang, obat ulat tanah, dan pestisida untuk hama pemakan daun.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, tanaman rebah akibat hama tanah, batang rusak karena penggerek, sundep pada padi, dan pertumbuhan tanaman terganggu.\r\n\r\nDosis penggunaan 1â€“2 ml per liter air atau sekitar 200â€“400 ml per hektar.', 'Rp.52.000', '8', '500ml, 1L', '-', 'Tersedia', '05/05/2026 16:50:06', ''),
('76', 'Ranevo 30/250 EC 100ml â€“ Insektisida', 'Insektisida', 'Cabai, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Tanah, Sawah, Lahan Terbuka', 'Dosis pemakaian Ranevo 30/250 EC umumnya sekitar 0,5 â€“ 1 ml per liter air atau 100 â€“ 200 ml per hektar', 'obat ulat grayak\r\nracun ulat grayak\r\ninsektisida ulat\r\nobat thrips\r\nobat daun keriting\r\nobat kutu daun\r\nobat penggerek batang\r\nobat hama cabai\r\nobat hama bawang merah\r\nobat hama padi\r\nsemprot ulat\r\nsemprot thrips\r\npestisida cabai\r\npestisida bawang merah\r\npestisida padi\r\ndaun berlubang\r\nserangan ulat\r\nserangan thrips\r\nhama penghisap\r\npengendali ulat\r\npengendali thrips', 'Ranevo 30/250 EC merupakan insektisida berbahan aktif profenofos dan cypermethrin yang bekerja sebagai racun kontak dan racun lambung dengan efek knockdown cepat.\r\n\r\nProduk ini digunakan sebagai obat ulat grayak, racun ulat cabai, obat thrips bawang merah, pengendali kutu daun, serta pengendali penggerek batang pada tanaman padi dan hortikultura.\r\n\r\nCocok digunakan saat tanaman mengalami daun berlubang, daun keriting akibat thrips, serangan ulat, serta kerusakan tanaman akibat hama penghisap.\r\n\r\nDosis aplikasi 0,5â€“1 ml per liter air atau 100â€“200 ml per hektar.', 'Rp.65.000', '6', '100ml, 200ml', '-', 'Tersedia', '05/05/2026 16:52:28', ''),
('77', 'Salsa 605 EC 100 ml â€“ Insektisida', 'Insektisida', 'Cabai, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Tanah, Sawah', 'Dosis pemakaian Salsa 605 EC umumnya sekitar 1 â€“ 2 ml per liter air atau 200 â€“ 400 ml per hektar, tergantung tingkat serangan.', 'obat ulat\r\nracun ulat\r\nobat thrips\r\nobat daun keriting\r\nobat kutu daun\r\nobat penggerek batang\r\nobat hama cabai\r\nobat hama padi\r\nobat hama bawang merah\r\nsemprot ulat\r\nsemprot thrips\r\ndaun berlubang\r\nhama penghisap\r\npestisida cabai\r\npestisida padi\r\npestisida bawang merah\r\npengendali ulat\r\npengendali thrips', 'Salsa 605 EC merupakan insektisida berbahan aktif organofosfat yang digunakan untuk mengendalikan ulat grayak, thrips, kutu daun, dan penggerek pada tanaman cabai, padi, bawang merah, serta hortikultura.\r\n\r\nProduk ini cocok digunakan sebagai obat ulat, racun ulat cabai, obat thrips, pengendali daun keriting, serta pengendali hama penghisap.\r\n\r\nGejala yang dapat dikendalikan meliputi daun berlubang, daun keriting, tanaman kerdil, dan kerusakan akibat serangan ulat maupun thrips.\r\n\r\nDosis aplikasi 1â€“2 ml per liter air atau 200â€“400 ml per hektar.', 'Rp.22.000', '6', '100ml, 500ml', '-', 'Tersedia', '05/05/2026 16:55:36', ''),
('78', 'Sevin 85 SP 100 gr â€“ Insektisida', 'Insektisida', 'Padi, Jagung, Sayuran, Buah-buahan', 'Vegetatif, Generatif', 'Ulat, Belalang, Kumbang', 'Tanah, Sawah', 'Dosis pemakaian Sevin 85 SP umumnya sekitar 1 â€“ 2 gram per liter air, atau sekitar 200 â€“ 400 gram per hektar.', 'obat ulat\r\nracun ulat\r\nobat belalang\r\nobat kumbang\r\nobat daun bolong\r\nobat hama jagung\r\nobat hama padi\r\nobat hama sayuran\r\nsemprot ulat\r\nsemprot belalang\r\npengendali ulat\r\npengendali belalang\r\ndaun habis dimakan\r\nhama pemakan daun', 'Sevin 85 SP merupakan insektisida berbahan aktif carbaryl yang digunakan untuk mengendalikan ulat, belalang, kumbang, dan hama pemakan daun.\r\n\r\nProduk ini cocok digunakan sebagai obat ulat, racun ulat, obat belalang, serta pengendali daun berlubang pada tanaman padi, jagung, buah-buahan, dan sayuran.\r\n\r\nGejala yang dapat dikendalikan antara lain daun bolong, daun habis dimakan ulat, serangan belalang, serta kerusakan tanaman akibat hama pengunyah.\r\n\r\nDosis aplikasi 1â€“2 gram per liter air atau 200â€“400 gram per hektar.', 'Rp.40.000', '6', '100gr', '-', 'Tersedia', '05/05/2026 16:57:33', ''),
('79', 'Sidamethrin 50 EC 100ml', 'Insektisida', 'Padi, Cabai, Tomat, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun', 'Tanah, Sawah', 'Dosis pemakaian Sidamethrin 50 EC umumnya sekitar 0,25 â€“ 0,5 ml per liter air, atau sekitar 50 â€“ 100 ml per hektar.', 'obat ulat grayak\r\nracun ulat\r\nobat thrips\r\nobat daun keriting\r\nobat kutu daun\r\nobat hama cabai\r\nobat hama tomat\r\nobat hama padi\r\nobat hama jagung\r\nsemprot ulat\r\nsemprot thrips\r\nsemprot kutu daun\r\ndaun berlubang\r\ndaun keriting\r\nhama penghisap', 'Sidamethrin 50 EC merupakan insektisida berbahan aktif cypermethrin yang bekerja cepat untuk mengendalikan ulat grayak, thrips, dan kutu daun.\r\n\r\nProduk ini digunakan sebagai obat ulat cabai, racun ulat padi, obat thrips tomat, pengendali daun keriting, dan pengendali kutu daun.\r\n\r\nGejala yang dapat dikendalikan meliputi daun berlubang, daun keriting, pertumbuhan tanaman terganggu, dan kerusakan akibat serangan hama penghisap.\r\n\r\nDosis aplikasi 0,25â€“0,5 ml per liter air atau 50â€“100 ml per hektar.', 'Rp.30.000', '15', '100ml, 250ml, 400ml', '-', 'Tersedia', '05/05/2026 17:17:05', ''),
('80', 'Sinergy', 'Fungisida', 'Padi, Jagung, Bawang Merah', 'Vegetatif, Generatif', 'Busuk Upih, Bercak Daun, Bercak Ungu', 'Sawah, Tanah', 'padi 0.7ml/L ; jagung 3-4.5ml/L ; bawang merah 0.75-1.5ml/L', 'obat busuk upih\r\nfungisida busuk upih\r\nobat rhizoctonia\r\nobat bercak daun jagung\r\nfungisida bercak daun\r\nobat daun bercak coklat\r\nobat bercak ungu bawang\r\nfungisida bawang merah\r\nobat penyakit padi\r\nobat penyakit jagung\r\nobat penyakit bawang merah\r\nobat jamur daun\r\nfungisida sistemik\r\nanti jamur tanaman\r\nobat daun menguning\r\nobat daun mengering\r\npengendali penyakit jamur', 'Sinergy merupakan fungisida sistemik yang digunakan untuk mengendalikan penyakit busuk upih Rhizoctonia solani pada padi, bercak daun Helminthosporium maydis pada jagung, serta bercak ungu Alternaria porri pada bawang merah.\r\n\r\nProduk ini cocok digunakan sebagai obat busuk upih, fungisida bercak daun jagung, obat bercak ungu bawang merah, pengendali penyakit jamur, serta anti jamur tanaman.\r\n\r\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menguning akibat jamur, bercak ungu pada bawang merah, dan kerusakan pelepah akibat busuk upih.\r\n\r\nDosis aplikasi padi 0,7 ml per liter air, jagung 3â€“4,5 ml per liter air, dan bawang merah 0,75â€“1,5 ml per liter air.', '140.000', '5', '250ml', '-', 'Tersedia', '27/05/2026 9:51:59', ''),
('81', 'Mospilan 30 EC', 'Insektisida', 'Cabai, Kubis, Teh, Jeruk, Tomat, Mentimun, Terong, Semangka, Melon, Padi, Kedelai, Kacang Panjang, Bawang Merah', 'Vegetatif, Generatif', 'Kutu Daun, Kutu Kebul, Kutu Putih, Thrips, Wereng, Lalat Buah, Penggerek Polong, Ulat Daun, Ulat Perusak Daun, Penggulung Pucuk', 'Tanah, Sawah, Lahan Terbuka', '0,5â€“1,2 ml/L air', 'mospilan,\r\nmospilan 30 ec,\r\ninsektisida mospilan,\r\nasetamiprid,\r\nobat kutu daun,\r\npembasmi kutu daun,\r\nracun kutu daun,\r\nobat wereng,\r\npembasmi wereng,\r\nobat kutu kebul,\r\nobat kutu putih,\r\nobat lalat buah,\r\nobat thrips,\r\nobat trips,\r\npembasmi trips,\r\nobat hama cabai,\r\ninsektisida cabai,\r\npestisida cabai,\r\nobat lalat buah cabai,\r\nobat kutu daun cabai,\r\nobat hama kubis,\r\nobat ulat kubis,\r\nobat plutella,\r\nobat penggulung pucuk,\r\nobat hama teh,\r\nobat hama jeruk,\r\nobat hama tomat,\r\nobat hama melon,\r\nobat hama semangka,\r\nobat hama bawang merah,\r\nobat hama padi,\r\nobat wereng padi,\r\nobat penggerek polong,\r\npengendali hama penghisap,\r\npengendali kutu kebul,\r\npengendali lalat buah,\r\nanti kutu daun,\r\nanti wereng,\r\ninsektisida sistemik,\r\ninsektisida kontak,\r\nracun serangga penghisap,\r\nobat daun keriting,\r\nobat tanaman diserang kutu,\r\nobat tanaman keriting,\r\nobat daun menggulung,\r\nobat hama buah', 'Mospilan 30 EC merupakan insektisida berbahan aktif asetamiprid 30 g/L yang bekerja secara kontak dan sistemik untuk mengendalikan berbagai hama penghisap pada tanaman pertanian dan hortikultura.\n\nProduk ini banyak digunakan sebagai obat kutu daun, obat wereng padi, obat kutu kebul, obat kutu putih, obat thrips, dan obat lalat buah pada tanaman cabai, kubis, bawang merah, tomat, mentimun, melon, semangka, teh, jeruk, padi, dan kedelai.\n\nMospilan sangat efektif untuk mengendalikan hama penghisap yang menyebabkan daun keriting, daun menggulung, pertumbuhan tanaman terhambat, buah rusak akibat lalat buah, serta serangan kutu daun dan wereng yang menurunkan produktivitas tanaman.\n\nBahan aktif asetamiprid diserap oleh jaringan tanaman sehingga memberikan perlindungan sistemik dan mampu menjangkau hama yang bersembunyi di bagian bawah daun.\n\nProduk ini cocok diaplikasikan pada fase vegetatif maupun generatif ketika populasi kutu daun, kutu kebul, wereng, thrips, lalat buah, dan hama penghisap mulai meningkat.\n\nDosis penggunaan umumnya 0,5 sampai 1,2 ml per liter air tergantung jenis tanaman dan tingkat serangan hama.', '42000', '10', '250ml', '-', 'Tersedia', '', ''),
('82', 'Tandem 325 EC', 'Insektisida', 'Cabai, Bawang Merah, Padi, Tomat, Sayuran', 'Vegetatif, Generatif', 'Thrips, Ulat Grayak, Kutu Daun, Penggerek, Wereng', 'Tanah, Sawah, Lahan Terbuka', '0,5â€“1 ml/L', 'tandem 325 ec,\r\ninsektisida tandem,\r\nobat trips,\r\nobat thrips,\r\nobat keriting cabai,\r\nobat ulat grayak,\r\nobat kutu daun,\r\nobat penggerek,\r\nobat wereng,\r\nracun ulat,\r\nracun trips,\r\ninsektisida cabai,\r\npestisida cabai,\r\nobat daun keriting,\r\nobat pucuk keriting,\r\nobat hama bawang merah,\r\nobat hama padi,\r\npembasmi ulat,\r\npengendali trips,\r\npengendali kutu daun', 'Tandem 325 EC merupakan insektisida berbahan aktif profenofos dan sipermetrin yang bekerja sebagai racun kontak dan lambung untuk mengendalikan berbagai hama penting tanaman.\r\n\r\nProduk ini banyak digunakan sebagai obat trips cabai, obat ulat grayak, obat kutu daun, obat penggerek batang, dan obat wereng pada tanaman cabai, padi, bawang merah, tomat, serta tanaman hortikultura lainnya.\r\n\r\nGejala yang dapat dikendalikan meliputi daun keriting akibat trips, daun berlubang akibat ulat, tanaman menguning akibat kutu daun, serta kerusakan batang akibat penggerek.', '50.000', '5', '250ml', '', '', '', ''),
('83', 'X Score Plus 475 SC', 'Fungisida', 'Cabai, Tomat, Bawang Merah, Kentang, Padi', 'Vegetatif, Generatif', 'Patek, Busuk Daun, Bercak Daun, Antraknosa', 'Tanah, Sawah', '0,5â€“1 ml/L', 'x score plus,\r\nfungisida score,\r\nobat patek,\r\nobat antraknosa,\r\nobat busuk daun,\r\nanti patek,\r\nobat bercak daun,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida bawang merah,\r\nobat busuk buah,\r\nobat daun menghitam,\r\nobat daun bercak,\r\nobat jamur cabai,\r\nobat jamur tomat,\r\nanti jamur tanaman', 'X Score Plus 475 SC merupakan fungisida sistemik yang digunakan untuk mengendalikan penyakit jamur pada tanaman hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat patek cabai, obat antraknosa, obat busuk daun, obat bercak daun, dan fungisida untuk tanaman cabai, tomat, kentang, serta bawang merah.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak coklat pada daun, buah cabai busuk, daun menghitam, daun menguning akibat jamur, dan patek pada buah.', '85.000', '10', '500ml', '', '', '', ''),
('84', 'Abacel 18 EC', 'Insektisida', 'Cabai, Bawang Merah, Tomat', 'Vegetatif, Generatif', 'Thrips, Tungau, Kutu Daun, Kutu Kebul, Ulat Grayak', 'Tanah, Lahan Terbuka', '10â€“20 ml/16 liter air', 'abacel,\r\nabacel 18 ec,\r\nabamektin,\r\nobat trips,\r\nobat thrips,\r\nobat keriting cabai,\r\nobat tungau,\r\nobat kutu kebul,\r\nobat kutu daun,\r\nobat ulat grayak,\r\ninsektisida abamektin,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat cabai keriting,\r\nobat hama bawang merah,\r\nobat hama tomat,\r\nobat hama cabai,\r\nracun trips,\r\npembasmi tungau,\r\nanti tungau', 'Abacel 18 EC merupakan insektisida berbahan aktif abamektin yang bekerja sebagai racun kontak, lambung, dan translaminar untuk mengendalikan hama penghisap maupun tungau.\r\n\r\nProduk ini sangat dikenal petani sebagai obat trips cabai, obat keriting daun, obat tungau, obat kutu kebul, dan obat kutu daun pada tanaman cabai, tomat, serta bawang merah.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menggulung, pucuk mengkerut, serangan trips pada bunga, serta kerusakan daun akibat tungau. :contentReference[oaicite:1]{index=1}', '35000', '15', '250ml', '', '', '', ''),
('85', 'Srikandi Insektisida', 'Insektisida', 'Cabai, Padi, Sayuran', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun', 'Tanah, Sawah', '10â€“20 ml/16 liter air', 'srikandi insektisida,\r\nobat ulat,\r\nobat trips,\r\nobat thrips,\r\nobat kutu daun,\r\nobat hama cabai,\r\nobat hama padi,\r\nracun ulat,\r\ninsektisida sayuran,\r\npembasmi ulat grayak,\r\npengendali hama tanaman', 'Srikandi merupakan insektisida untuk mengendalikan berbagai hama penting pada tanaman hortikultura dan pangan.\r\n\r\nProduk ini digunakan sebagai obat ulat grayak, obat trips, obat kutu daun, serta pengendali hama serangga pada tanaman cabai, padi, dan sayuran.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, daun keriting, pucuk rusak, dan pertumbuhan tanaman terhambat akibat serangan hama.', '45.000', '20', '250ml', '', '', '', ''),
('86', 'Custodia', 'Fungisida', 'Padi, Cabai, Tomat, Bawang Merah', 'Vegetatif, Generatif', 'Busuk Upih, Patek, Bercak Daun, Karat Daun, Busuk Buah', 'Sawah, Tana', '0,5â€“1 ml/L', 'custodia,\r\nfungisida custodia,\r\nobat busuk upih,\r\nobat patek,\r\nobat antraknosa,\r\nobat busuk buah,\r\nobat bercak daun,\r\nfungisida padi,\r\nfungisida cabai,\r\nfungisida bawang merah,\r\nobat karat daun,\r\nobat hawar daun,\r\nanti jamur,\r\nanti patek,\r\nobat jamur tanaman,\r\nobat penyakit padi,\r\nobat busuk pelepah,\r\nobat sheat blight', 'Custodia merupakan fungisida sistemik berbahan aktif azoxystrobin dan tebuconazole yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman pangan dan hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat busuk upih padi, obat patek cabai, obat bercak daun, obat karat daun, serta pengendali penyakit busuk buah.\r\n\r\nGejala yang dapat dikendalikan meliputi bercak daun, busuk pelepah, busuk buah, patek pada cabai, serta penyakit jamur yang menyebabkan penurunan hasil panen.', '70.000', '10', '250ml', '', '', '', ''),
('87', 'Regent 50 SC', 'Insektisida', 'Cabai, Padi, Jagung, Kentang, Kubis, Semangka, Kedelai, Tebu, Jeruk, Kakao, Kacang Panjang, Kelapa Sawit', 'Vegetatif, Generatif', 'Thrips, Kutu Daun, Wereng Coklat, Walang Sangit, Penggulung Daun, Kepik Hijau, Belalang, Penggerek Polong, Penggerek Buah', 'Sawah, Tanah, Lahan Terbuka', '0,5â€“1 ml/L air', 'obat wereng,\nobat wereng padi,\ninsektisida padi,\nobat thrips,\nobat trips,\nobat kutu daun,\nobat walang sangit,\nobat belalang,\nobat penggulung daun,\nobat penggerek polong,\nobat penggerek buah,\nobat hama cabai,\nobat hama kentang,obat hama semangka,\nobat hama kedelai,\nobat hama jagung,\nregent 50 sc,\nfipronil,\nracun wereng,\nracun thrips,\npembasmi kutu daun,\ninsektisida sistemik', 'Regent 50 SC merupakan insektisida berbahan aktif fipronil 50 g/L yang bekerja sebagai racun kontak dan lambung untuk mengendalikan berbagai hama penting pada tanaman pangan dan hortikultura.\n\nProduk ini banyak digunakan petani sebagai obat wereng padi, obat thrips cabai, obat kutu daun, obat walang sangit, obat penggulung daun, serta pengendali berbagai hama penghisap dan pengunyah.\n\nGejala yang dapat dikendalikan antara lain daun menguning akibat wereng, daun keriting akibat thrips, tanaman kerdil akibat kutu daun, dan kerusakan daun maupun buah akibat serangan serangga.', '110000', '15', '250ml', '', '', '', ''),
('88', 'Sumo', 'Insektisida', 'Cabai, Padi, Jagung, Sayuran', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Wereng', 'Sawah, Tanah', 'dosis 1 ml - 2 ml atau 15 ml - 30 ml per tangki 14 liter', 'sumo insektisida,\nobat ulat grayak,\nobat trips,\nobat thrips,\nobat kutu daun,\nobat wereng,\nobat daun keriting,\nobat hama cabai,\nobat hama padi,\ninsektisida padi,\ninsektisida cabai,\nracun ulat,\npembasmi ulat,\npengendali hama tanaman', 'Sumo merupakan insektisida yang digunakan untuk mengendalikan berbagai hama serangga pada tanaman pangan dan hortikultura.\n\nProduk ini banyak dicari petani sebagai obat ulat grayak, obat thrips, obat kutu daun, dan obat wereng pada tanaman cabai, padi, jagung, serta sayuran.\n\nGejala yang dapat dikendalikan antara lain daun berlubang, daun keriting, pucuk rusak, serta penurunan pertumbuhan akibat serangan hama serangga.', '30.000', '10', '250ml', '', '', '', ''),
('89', 'Starelle 660 EC', 'Insektisida', 'Bawang Merah, Kedelai, Cabai', 'Vegetatif, Generatif', 'Ulat Grayak, Penggulung Daun, Penggerek Polong, Pengisap Polong, Thrips', 'Tanah, Sawah, Lahan Terbuka', '1â€“2 ml/L air', 'obat ulat grayak,\r\nracun ulat grayak,\r\ninsektisida ulat grayak,\r\nobat ulat bawang,\r\nobat ulat cabai,\r\nobat thrips,\r\nracun thrips,\r\nobat daun keriting,\r\nobat daun menggulung,\r\nobat penggerek polong,\r\nobat polong berlubang,\r\nobat pengisap polong,\r\nobat hama kedelai,\r\ninsektisida kedelai,\r\ninsektisida bawang merah,\r\nobat hama bawang,\r\nobat daun habis dimakan ulat,\r\nhama pemakan daun,\r\nobat ulat tentara,\r\nracun ulat spodoptera,\r\nstarelle,\r\nstarel,\r\nklorpirifos sipermetrin,\r\nobat ulat paling ampuh,\r\nobat hama cabai,\r\ninsektisida kontak lambung', 'Starelle 660 EC merupakan insektisida berbahan aktif klorpirifos 600 g/L dan sipermetrin 60 g/L yang bekerja sebagai racun kontak, lambung, dan pernapasan untuk mengendalikan berbagai hama penting tanaman.\n\nProduk ini banyak digunakan sebagai obat ulat grayak bawang merah, racun thrips cabai, pengendali penggerek polong kedelai, dan insektisida spektrum luas untuk tanaman hortikultura.\n\nGejala yang dapat dikendalikan antara lain daun berlubang, daun habis dimakan ulat, daun menggulung, bunga rontok akibat thrips, polong rusak akibat penggerek, dan serangan hama pengisap polong.\n\nCocok digunakan pada fase vegetatif hingga generatif ketika populasi hama mulai meningkat.\n\nDosis aplikasi umumnya 1â€“2 ml per liter air.', '20.000', '5', '250ml', '', '', '', ''),
('90', 'Corona 325 EC', 'Fungisida', 'Cabai, Tomat, Kentang, Kakao, Kedelai, Mangga, Kelapa Sawit', 'Vegetatif, Generatif', 'Antraknosa, Patek, Busuk Buah, Bercak Coklat, Karat Daun', 'Tanah, Kebun, Lahan Terbuka', '2â€“3 ml/L air', 'obat patek,\r\nfungisida patek,\r\nanti patek cabai,\r\nobat antraknosa,\r\nfungisida antraknosa,\r\nobat busuk buah,\r\nobat bercak daun,\r\nfungisida bercak daun,\r\nobat daun bercak coklat,\r\nobat karat daun,\r\nobat buah busuk,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida kentang,\r\nobat jamur tanaman,\r\nobat buah cabai hitam,\r\nobat busuk buah kakao,\r\ncorona fungisida,\r\nobat jamur cabai,\r\nanti busuk buah,\r\nfungisida sistemik,\r\nobat penyakit tanaman', 'Corona 325 EC merupakan fungisida sistemik yang digunakan untuk mengendalikan penyakit antraknosa, patek, bercak daun, karat daun, dan busuk buah pada berbagai tanaman.\r\n\r\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida antraknosa, anti busuk buah kakao, dan pengendali bercak daun pada tomat maupun kentang.\r\n\r\nGejala yang dapat dikendalikan antara lain buah cabai menghitam, buah busuk, daun bercak coklat, daun berkarat, bercak bulat pada daun, serta busuk buah akibat serangan jamur.\r\n\r\nDosis aplikasi umumnya 2â€“3 ml per liter air.', '87.000', '5', '150ml', '', '', '', ''),
('91', 'Hantu', 'Insektisida', 'Cabai, Padi, Jagung, Tomat, Bawang Merah', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Tanah, Sawah, Lahan Terbuka', '0,5â€“1 ml/L air', 'obat ulat grayak,\r\nobat thrips,\r\nobat kutu daun,\r\nobat daun keriting,\r\nobat penggerek,\r\ninsektisida cabai,\r\ninsektisida padi,\r\nobat hama tomat,\r\nobat ulat buah,\r\nracun ulat,\r\nracun kutu daun,\r\nobat serangga tanaman,\r\nhama penghisap,\r\nhama pemakan daun,\r\nobat daun berlubang,\r\nobat tanaman keriting,\r\nobat tanaman diserang ulat,\r\nobat tanaman layu akibat hama,\r\ninsektisida spektrum luas,\r\nhantu insektisida', 'Hantu merupakan insektisida yang digunakan untuk mengendalikan ulat grayak, thrips, kutu daun, dan penggerek pada berbagai tanaman pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat ulat cabai, racun thrips, pengendali kutu daun, dan insektisida untuk tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, daun keriting, bunga rontok akibat thrips, pertumbuhan tanaman terhambat, serta kerusakan batang dan buah akibat penggerek.\r\n\r\nCocok diaplikasikan sejak fase vegetatif hingga generatif saat populasi hama meningkat.', '45.000', '5', '250ml', '', '', '', ''),
('92', 'Spontan Insektisida', 'Insektisida', 'Cabai, Tomat, Padi, Jagung, Sayuran', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Wereng', 'Tanah, Sawah, Lahan Terbuka', '0,5â€“1 ml/L air', 'obat ulat,\r\nobat thrips,\r\nobat wereng,\r\nobat kutu daun,\r\nracun ulat grayak,\r\ninsektisida cabai,\r\ninsektisida padi,\r\nobat daun keriting,\r\nobat tanaman kuning,\r\nobat serangga penghisap,\r\nobat daun berlubang,\r\nobat tanaman diserang ulat,\r\nobat hama padi,\r\nobat hama sayuran,\r\npengendali hama tanaman,\r\nspontan insektisida,\r\nobat wereng coklat,\r\nobat hama cabai,\r\nracun hama tanaman', 'Spontan merupakan insektisida spektrum luas yang digunakan untuk mengendalikan berbagai hama pengunyah dan penghisap pada tanaman pertanian.\r\n\r\nProduk ini efektif sebagai obat wereng padi, obat thrips cabai, pengendali kutu daun, serta racun ulat grayak pada berbagai sayuran.\r\n\r\nGejala yang dapat dikendalikan meliputi daun keriting, daun berlubang, tanaman menguning akibat serangan hama penghisap, serta kerusakan daun dan pucuk akibat ulat.', '55.000', '10', '250ml', '', '', '', ''),
('93', 'Guela', 'Insektisida', 'Cabai, Tomat, Bawang Merah, Padi, Hortikultura', 'Vegetatif, Generatif', 'Thrips, Kutu Daun, Ulat Grayak, Wereng', 'Tanah, Sawah, Lahan Terbuka', '0,5â€“1 ml/L air', 'obat thrips,\nracun thrips,\nobat kutu daun,\nobat wereng,\nobat ulat grayak,\nobat daun keriting,\nobat tanaman keriting,\nobat daun menggulung,\nobat pucuk keriting,\ninsektisida cabai,\ninsektisida bawang merah,\ninsektisida tomat,\nobat serangga penghisap,\nobat hama tanaman,\npengendali hama cabai,\nracun kutu daun,\nobat tanaman kuning,\nguela insektisida,\nobat hama sayuran,\nracun ulat', 'Guela merupakan insektisida yang digunakan untuk mengendalikan thrips, kutu daun, wereng, dan ulat grayak pada tanaman hortikultura dan tanaman pangan.\r\n\r\nProduk ini sering digunakan sebagai obat daun keriting cabai, racun thrips, pengendali wereng padi, dan insektisida untuk mengatasi serangan hama penghisap.\r\n\r\nGejala yang dapat dikendalikan antara lain daun keriting, daun menggulung, tanaman kerdil, pucuk rusak, daun menguning, serta kerusakan akibat ulat pemakan daun.\r\n\r\nCocok digunakan pada fase vegetatif hingga generatif saat serangan hama mulai terlihat.', '35.000', '15', '250ml', '', '', '', ''),
('94', 'Imidor 200 SL', 'Insektisida', 'Padi, Cabai, Tomat, Kentang, Sayuran, Hortikultura', 'Vegetatif, Generatif', 'Wereng, Kutu Daun, Kutu Kebul, Thrips, Leafhopper, Planthopper', 'Tanah, Sawah, Lahan Terbuka', '0,25â€“0,5 ml/L air', 'imidor,\r\nimidor 200 sl,\r\nimidacloprid,\r\nobat wereng,\r\nracun wereng,\r\ninsektisida wereng,\r\nobat kutu daun,\r\nobat kutu kebul,\r\nobat thrips,\r\nracun thrips,\r\ninsektisida sistemik,\r\nobat hama penghisap,\r\npestisida padi,\r\nobat wereng coklat,\r\nobat daun keriting,\r\nobat tanaman keriting,\r\nobat kutu putih,\r\nobat kutu tanaman,\r\nhama penghisap daun,\r\npengendali wereng,\r\npengendali kutu daun,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\ninsektisida padi', 'Imidor 200 SL merupakan insektisida sistemik berbahan aktif imidacloprid yang digunakan untuk mengendalikan hama penghisap seperti wereng, kutu daun, kutu kebul, dan thrips pada tanaman padi, cabai, tomat, kentang, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini banyak dicari petani sebagai obat wereng padi, racun wereng coklat, obat kutu daun cabai, obat kutu kebul tomat, serta pestisida untuk mengatasi daun keriting akibat serangan hama penghisap.\r\n\r\nGejala yang dapat dikendalikan antara lain daun menguning, daun keriting, pertumbuhan tanaman terhambat, tanaman kerdil, serangan kutu putih, dan populasi wereng yang tinggi.\r\n\r\nImidor bekerja secara sistemik sehingga diserap oleh tanaman dan memberikan perlindungan lebih lama terhadap hama penghisap.', '90.000', '5', '500ml', '', '', '', ''),
('95', 'Zychate', 'Insektisida', 'Cabai, Tomat, Padi, Jagung, Hortikultura', 'Vegetatif, Generatif', 'Ulat Grayak, Thrips, Kutu Daun, Penggerek', 'Tanah, Sawah', '0,5â€“1 ml/L air', 'zychate,\r\nobat ulat grayak,\r\nracun ulat,\r\nobat thrips,\r\nobat kutu daun,\r\ninsektisida cabai,\r\ninsektisida tomat,\r\nobat daun berlubang,\r\nobat tanaman keriting,\r\nobat hama cabai,\r\nobat hama tomat,\r\npengendali penggerek,\r\nracun serangga tanaman,\r\nobat kutu tanaman,\r\nobat serangga penghisap', 'Zychate merupakan insektisida yang digunakan untuk mengendalikan ulat grayak, thrips, kutu daun, dan hama penggerek pada tanaman cabai, tomat, padi, jagung, dan hortikultura.\r\n\r\nProduk ini sering dicari sebagai obat ulat grayak cabai, racun thrips, obat kutu daun, dan pengendali tanaman yang mengalami daun berlubang maupun daun keriting akibat hama.\r\n\r\nGejala yang dapat dikendalikan meliputi kerusakan daun, pucuk keriting, bunga rontok, buah cacat, serta pertumbuhan tanaman yang terhambat akibat serangan serangga.', '40.000', '7', '250ml', '', '', '', ''),
('96', 'Sagri Beat 7/30 WP', 'Insektisida', 'Padi, Jagung, Kedelai, Cabai, Tomat, Kentang, Bawang Merah, Kubis', 'Vegetatif, Generatif', 'Ulat Grayak, Ulat Daun, Ulat Buah, Thrips, Penggerek Batang, Penggerek Buah', 'Sawah, Tanah, Lahan Terbuka', '0,5 â€“ 0,75 g/L (7,5 â€“ 10 g/tangki 15L)', 'sagri beat,\r\nsagri beat 730 wp,\r\nobat ulat grayak,\r\nobat ulat daun,\r\nobat ulat buah,\r\nobat penggerek batang,\r\nobat penggerek buah,\r\nobat thrips,\r\ninsektisida ulat,\r\nracun ulat,\r\nobat daun berlubang,\r\nobat buah berlubang,\r\nobat ulat padi,\r\nobat ulat jagung,\r\nobat ulat cabai,\r\nobat sundep,\r\nobat beluk,\r\nracun penggerek batang,\r\npengendali ulat', 'Sagri Beat 7/30 WP merupakan insektisida sistemik berbahan aktif emamektin benzoat dan klorbenzuron yang digunakan untuk mengendalikan ulat grayak, ulat daun, ulat buah, penggerek batang, penggerek buah, dan thrips.\r\n\r\nProduk ini banyak digunakan sebagai obat sundep padi, obat beluk, obat ulat grayak cabai, obat ulat jagung, serta pengendali penggerek batang dan buah.\r\n\r\nGejala yang dapat dikendalikan antara lain daun berlubang, batang padi mati pucuk, buah berlubang akibat larva, tanaman kerdil, dan kerusakan akibat serangan ulat pada fase vegetatif maupun generatif.', '100.000', '10', '80gram', '', '', '', ''),
('97', 'Siodan', 'Fungisida', 'Cabai, Tomat, Bawang Merah, Kentang, Sayuran, Hortikultura', 'Awal Vegetatif, Vegetatif, Generatif', 'Busuk Daun, Patek, Antraknosa, Bercak Daun, Hawar Daun', 'Tanah, Bedengan, Lahan Terbuka', '1â€“2 g/ml per liter air (sesuai label)', 'siodan fungisida,\r\nobat patek,\r\nfungisida patek,\r\nobat antraknosa,\r\nobat busuk daun,\r\nfungisida busuk daun,\r\nobat bercak daun,\r\nobat daun menguning,\r\nobat daun menghitam,\r\nobat buah busuk,\r\nobat jamur cabai,\r\nobat jamur tomat,\r\nobat layu jamur,\r\nobat penyakit tanaman,\r\nobat cabai busuk,\r\nobat patek cabai,\r\nobat busuk buah cabai,\r\nobat busuk batang,\r\nobat jamur daun,\r\nanti jamur tanaman,\r\npengendali penyakit jamur,\r\nfungisida hortikultura,\r\nobat hawar daun,\r\nobat daun keriting karena jamur', 'Siodan Fungisida digunakan untuk mengendalikan penyakit akibat jamur seperti patek, antraknosa, busuk daun, bercak daun, dan hawar daun pada tanaman cabai, tomat, bawang merah, kentang, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini sering dicari petani sebagai obat patek cabai, obat busuk buah cabai, fungisida antraknosa, obat bercak daun, dan pengendali penyakit jamur tanaman.\r\n\r\nGejala yang dapat dikendalikan meliputi bercak coklat pada daun, buah cabai menghitam, busuk buah, daun menguning, daun kering, serta kerusakan tanaman akibat infeksi jamur.\r\n\r\nCocok digunakan sejak awal muncul gejala penyakit hingga fase generatif untuk menjaga kualitas hasil panen.', '50.000', '15', '250ml', '', '', '', ''),
('98', 'Victory 80 WP', 'Fungisida', 'Cabai, Tomat, Kentang, Bawang Merah, Sayuran', 'Vegetatif, Generatif', 'Busuk Daun, Bercak Daun, Patek, Jamur Daun', 'Tanah, Bedengan', '1â€“2 g/L air', 'Victory 80 wp,\nfungisida factory,\nobat patek,\nobat busuk daun,\nfungisida busuk daun,\nobat bercak daun,\nobat jamur tanaman,\nobat jamur cabai,\nobat jamur tomat,\nobat buah busuk,\nobat daun bercak,\nobat daun kuning,\nobat daun kering,\nanti jamur tanaman,\nfungisida sayuran,\nobat penyakit daun,\nobat antraknosa,\nobat patek cabai,\nobat busuk buah,\nobat layu jamur', 'Victory 80 WP merupakan fungisida yang digunakan untuk mengendalikan berbagai penyakit jamur seperti patek, busuk daun, bercak daun, dan penyakit daun lainnya pada cabai, tomat, kentang, dan tanaman sayuran.\r\n\r\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida busuk daun tomat, obat bercak daun, dan pengendali penyakit akibat jamur pada fase vegetatif maupun generatif.\r\n\r\nGejala yang dapat dikendalikan meliputi daun bercak coklat, daun menguning, buah membusuk, batang menghitam, serta kerusakan tanaman akibat infeksi jamur.', '85.000', '15', '1kg', '', '', '', ''),
('99', 'Bendas 50 WP', 'Fungisida', 'Padi, Cabai, Tomat, Bawang Merah, Hortikultura', 'Vegetatif, Generatif', 'Blast, Bercak Daun, Busuk Daun, Patek', 'Sawah, Tanah', '1â€“2 g/L air', 'bendas 50 wp,\r\nfungisida bendas,\r\nobat blast,\r\nobat kresek,\r\nobat bercak daun,\r\nobat busuk daun,\r\nobat patek,\r\nobat jamur padi,\r\nfungisida padi,\r\nobat daun kuning,\r\nobat daun kering,\r\nobat penyakit daun,\r\nobat jamur cabai,\r\nobat jamur tomat,\r\nobat hawar daun,\r\npengendali penyakit jamur,\r\nanti jamur tanaman,\r\nobat busuk buah,\r\nobat antraknosa', 'Bendas 50 WP merupakan fungisida yang digunakan untuk mengendalikan berbagai penyakit jamur seperti blast, bercak daun, busuk daun, dan patek pada tanaman padi maupun hortikultura.\r\n\r\nProduk ini sering digunakan sebagai obat blast padi, fungisida bercak daun, obat patek cabai, dan pengendali penyakit daun akibat serangan jamur.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak coklat pada daun, daun mengering, busuk daun, busuk buah, serta penurunan pertumbuhan akibat infeksi patogen jamur.', '60.000', '10', '250gram', '', '', '', '');
INSERT INTO `dataproduk` (`COL 1`, `COL 2`, `COL 3`, `COL 4`, `COL 5`, `COL 6`, `COL 7`, `COL 8`, `COL 9`, `COL 10`, `COL 11`, `COL 12`, `COL 13`, `COL 14`, `COL 15`, `COL 16`, `COL 17`) VALUES
('100', 'Triactive Plus 70 WP', 'Fungisida', 'Padi, Cabai, Tomat, Jagung, Bawang Merah', 'Vegetatif, Generatif', 'Blast, Hawar Daun, Bercak Daun, Busuk Daun', 'Sawah, Tanah', '1â€“2 g/L air', 'triactive plus,\r\ntriactive plus 70 wp,\r\nfungisida padi,\r\nobat blast,\r\nobat hawar daun,\r\nobat bercak daun,\r\nobat jamur daun,\r\nobat busuk daun,\r\nobat patek,\r\nobat kresek,\r\nfungisida cabai,\r\nfungisida tomat,\r\nobat daun menguning,\r\nobat daun kering,\r\nanti jamur tanaman,\r\nobat penyakit tanaman,\r\nobat busuk batang,\r\nobat antraknosa,\r\npengendali penyakit jamur', 'Triactive Plus 70 WP merupakan fungisida spektrum luas yang digunakan untuk mengendalikan blast, hawar daun, bercak daun, busuk daun, dan berbagai penyakit jamur pada tanaman padi, cabai, tomat, jagung, dan bawang merah.\r\n\r\nProduk ini banyak dicari sebagai obat blast padi, obat hawar daun, fungisida busuk daun, serta pengendali penyakit jamur pada tanaman pangan dan hortikultura.\r\n\r\nGejala yang dapat dikendalikan meliputi daun bercak, daun mengering, daun menguning, busuk batang, serta gangguan pertumbuhan akibat infeksi jamur.', '40.000', '15', '100gram', '', '', '', ''),
('101', 'Nordox 56 WP', 'Fungisida Bakterisida', 'Cabai, Tomat, Kentang, Jeruk, Bawang Merah, Hortikultura', 'Awal Vegetatif, Vegetatif, Generatif', 'Patek, Busuk Daun, Bercak Daun, Hawar Daun, Bercak Bakteri', 'Tanah, Bedengan, Lahan Terbuka', '1â€“3 g/L air', 'nordox 56 wp,\r\nfungisida nordox,\r\nbakterisida nordox,\r\nobat patek,\r\nobat busuk daun,\r\nobat bercak daun,\r\nobat hawar daun,\r\nobat bercak bakteri,\r\nobat layu bakteri,\r\nobat busuk buah,\r\nobat antraknosa,\r\nobat cabai busuk,\r\nobat patek cabai,\r\nobat daun berlubang karena bakteri,\r\nobat jamur tanaman,\r\nanti jamur tanaman,\r\nanti bakteri tanaman,\r\nfungisida bakterisida,\r\nobat daun menghitam,\r\nobat penyakit tanaman,\r\nobat kresek,\r\npengendali penyakit bakteri,\r\npengendali penyakit jamur', 'Nordox 56 WP merupakan fungisida sekaligus bakterisida berbahan tembaga yang digunakan untuk mengendalikan penyakit jamur dan bakteri pada tanaman cabai, tomat, kentang, jeruk, bawang merah, dan berbagai tanaman hortikultura.\r\n\r\nProduk ini sering digunakan sebagai obat patek cabai, obat busuk daun, obat bercak bakteri, fungisida antraknosa, dan pengendali penyakit tanaman akibat infeksi jamur maupun bakteri.\r\n\r\nGejala yang dapat dikendalikan meliputi buah cabai menghitam, bercak daun, busuk daun, daun menguning, bercak bakteri, serta kerusakan tanaman akibat serangan patogen.\r\n\r\nCocok digunakan sebagai tindakan pencegahan maupun pengobatan pada fase vegetatif dan generatif tanaman.', '45.000', '', '', '', '', '', ''),
('102', 'Dithane M-45', 'Fungisida', 'Cabai, Tomat, Kentang, Bawang Merah, Padi, Jagung, Sayuran', 'Awal Vegetatif, Vegetatif, Generatif', 'Busuk Daun, Patek, Antraknosa, Bercak Daun, Hawar Daun, Karat Daun', 'Tanah, Sawah, Lahan Terbuka', '2â€“3 g/L air', 'dithane m45,\ndithane m-45,\nfungisida dithane,\nobat patek,\nobat patek cabai,\nfungisida patek,\nobat busuk daun,\nfungisida busuk daun,\nobat antraknosa,\nobat bercak daun,\nobat hawar daun,\nobat karat daun,\nobat daun kuning,\nobat daun menghitam,\nobat daun kering,\nobat buah busuk,\nobat jamur tanaman,\nobat penyakit tanaman,\nanti jamur tanaman,\nfungisida cabai,\nfungisida tomat,\nfungisida kentang,\nfungisida bawang merah,\nobat busuk buah cabai,\nobat layu jamur,\npengendali penyakit jamur', 'Dithane M-45 merupakan fungisida kontak berbahan aktif mankozeb yang digunakan untuk mengendalikan berbagai penyakit jamur seperti busuk daun, patek, antraknosa, bercak daun, hawar daun, dan karat daun pada tanaman cabai, tomat, kentang, bawang merah, padi, jagung, dan sayuran.\r\n\r\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida busuk daun tomat, obat antraknosa, serta pengendali penyakit daun akibat serangan jamur.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak coklat pada daun, daun menguning, daun mengering, buah membusuk, busuk daun, dan kerusakan tanaman akibat infeksi jamur.\r\n\r\nCocok diaplikasikan pada fase vegetatif hingga generatif sebagai tindakan pencegahan maupun pengendalian penyakit.', '80.000', '5', '500gram', '', '', '', ''),
('103', 'Bion M', 'Fungisida', 'Cabai, Tomat, Kentang, Bawang Merah, Sayuran', 'Vegetatif, Generatif', 'Patek, Busuk Daun, Antraknosa, Bercak Daun, Jamur Daun', 'Tanah, Lahan Terbuka', '1â€“2 g/L air', 'bion m,\r\nfungisida bion m,\r\nobat patek,\r\nobat patek cabai,\r\nfungisida patek,\r\nobat busuk daun,\r\nobat antraknosa,\r\nobat bercak daun,\r\nobat jamur tanaman,\r\nobat daun kuning,\r\nobat daun menghitam,\r\nobat daun bercak,\r\nobat buah busuk,\r\nobat penyakit tanaman,\r\nanti jamur tanaman,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida bawang,\r\nobat busuk buah,\r\nobat layu jamur,\r\npengendali penyakit jamur', 'Bion M merupakan fungisida yang digunakan untuk mengendalikan penyakit jamur seperti patek, antraknosa, busuk daun, bercak daun, dan penyakit daun lainnya pada tanaman cabai, tomat, kentang, bawang merah, dan sayuran.\r\n\r\nProduk ini sering digunakan sebagai obat patek cabai, obat busuk daun tomat, fungisida antraknosa, serta pengendali penyakit jamur pada tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan meliputi buah busuk, bercak daun, daun menguning, daun mengering, serta kerusakan tanaman akibat infeksi jamur.', '110.000', '7', '500gram', '', '', '', ''),
('104', 'Demox 30 WP', 'Fungisida', 'Cabai, Tomat, Bawang Merah, Kentang, Sayuran', 'Awal Vegetatif, Vegetatif, Generatif', 'Patek, Busuk Daun, Bercak Daun, Hawar Daun, Jamur Daun', 'Tanah, Lahan Terbuka', '1â€“2 g/L air', 'demox 30 wp,\r\nfungisida demox,\r\nobat patek,\r\nobat busuk daun,\r\nfungisida busuk daun,\r\nobat bercak daun,\r\nobat hawar daun,\r\nobat jamur tanaman,\r\nobat daun kuning,\r\nobat daun kering,\r\nobat daun menghitam,\r\nobat penyakit tanaman,\r\nobat buah busuk,\r\nobat patek cabai,\r\nobat antraknosa,\r\nanti jamur tanaman,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida bawang,\r\npengendali penyakit jamur', 'Demox 30 WP merupakan fungisida yang digunakan untuk mengendalikan penyakit jamur seperti patek, busuk daun, bercak daun, hawar daun, dan penyakit daun lainnya pada tanaman cabai, tomat, bawang merah, kentang, dan sayuran.\r\n\r\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida busuk daun, obat bercak daun, dan pengendali penyakit jamur pada tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan meliputi bercak daun, daun menguning, daun mengering, buah membusuk, dan kerusakan tanaman akibat infeksi jamur.', '50.000', '5', '500gram', '', '', '', ''),
('105', 'Copcide 77 WP', 'Fungisida Bakterisida', 'Cabai, Tomat, Kentang, Jeruk, Bawang Merah, Hortikultura', 'Awal Vegetatif, Vegetatif, Generatif', 'Bercak Bakteri, Busuk Daun, Patek, Antraknosa, Hawar Daun', 'Tanah, Lahan Terbuka', '2â€“3 g/L air', 'copcide 77 wp,\r\nfungisida copcide,\r\nbakterisida copcide,\r\nobat patek,\r\nobat busuk daun,\r\nobat bercak bakteri,\r\nobat layu bakteri,\r\nobat antraknosa,\r\nobat bercak daun,\r\nobat hawar daun,\r\nobat jamur tanaman,\r\nanti bakteri tanaman,\r\nanti jamur tanaman,\r\nobat cabai busuk,\r\nobat buah busuk,\r\nobat penyakit tanaman,\r\nfungisida cabai,\r\nfungisida tomat,\r\nobat daun menguning,\r\npengendali penyakit bakteri,\r\npengendali penyakit jamur', 'Copcide 77 WP merupakan fungisida dan bakterisida berbahan tembaga yang digunakan untuk mengendalikan penyakit akibat jamur dan bakteri pada tanaman cabai, tomat, kentang, jeruk, bawang merah, dan tanaman hortikultura lainnya.\r\n\r\nProduk ini sering digunakan sebagai obat patek cabai, obat bercak bakteri, fungisida antraknosa, obat busuk daun, serta pengendali penyakit tanaman akibat infeksi jamur dan bakteri.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak daun, bercak bakteri, daun menguning, busuk buah, busuk daun, serta kerusakan tanaman akibat serangan patogen.', '130.000', '5', '500gram', '', '', '', ''),
('106', 'Sagri Manzim', 'Fungisida', 'Cabai, Tomat, Kentang, Bawang Merah, Padi, Jagung, Sayuran', 'Awal Vegetatif, Vegetatif, Generatif', 'Busuk Daun, Patek, Antraknosa, Bercak Daun, Karat Daun', 'Tanah, Sawah, Lahan Terbuka', '2â€“3 g/L air', 'sagri manzim,\r\nfungisida sagri manzim,\r\nmankozeb,\r\nobat patek,\r\nobat patek cabai,\r\nfungisida patek,\r\nobat busuk daun,\r\nobat antraknosa,\r\nobat bercak daun,\r\nobat karat daun,\r\nobat jamur tanaman,\r\nobat daun kuning,\r\nobat daun menghitam,\r\nobat buah busuk,\r\nobat penyakit tanaman,\r\nanti jamur tanaman,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida kentang,\r\nfungisida bawang merah,\r\npengendali penyakit jamur', 'Sagri Manzim merupakan fungisida berbahan aktif mankozeb yang digunakan untuk mengendalikan penyakit jamur seperti busuk daun, patek, antraknosa, bercak daun, dan karat daun pada tanaman cabai, tomat, kentang, bawang merah, padi, jagung, dan berbagai tanaman sayuran.\n\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida busuk daun tomat, obat antraknosa, serta pengendali penyakit jamur pada tanaman hortikultura dan tanaman pangan.\n\nGejala yang dapat dikendalikan meliputi bercak daun, daun menguning, daun mengering, busuk buah, busuk daun, dan kerusakan tanaman akibat infeksi jamur.\n\nCocok digunakan sebagai pencegahan maupun pengobatan pada fase vegetatif hingga generatif tanaman.', '110.000', '5', '500gram', '', '', '', ''),
('107', 'Roundup Biosorb 486 SL', 'Herbisida', 'Kelapa Sawit, Karet, Kakao, Kopi, Teh, Jagung, Kedelai, Padi Gogo', 'Pra Tanam, Persiapan Lahan, Pasca Panen', 'Gulma Daun Lebar, Gulma Rumput, Teki-Tekian', 'Perkebunan, Sawah, Lahan Kering, Lahan Terbuka', '5â€“10 ml/L air atau 2â€“6 L/ha', 'roundup,\r\nroundup biosorb,\r\nobat rumput,\r\nracun rumput,\r\npembasmi rumput,\r\nherbisida rumput,\r\nobat gulma,\r\nracun gulma,\r\nherbisida gulma,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nobat rumput liar,\r\nherbisida kebun,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat lahan kosong,\r\nbersih lahan,\r\nsemprot rumput,\r\nobat gulma membandel,\r\nglyphosate,\r\nglifosat,\r\nobat rumput sawit,\r\nobat rumput jagung,\r\ntot,\r\ntanpa olah tanah', 'Roundup Biosorb 486 SL merupakan herbisida sistemik non selektif berbahan aktif glifosat yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun rumput, pembasmi alang alang, pengendali teki, dan herbisida gulma membandel pada perkebunan sawit, karet, kakao, kopi, teh, jagung, kedelai, dan padi gogo.\r\n\r\nGejala yang dapat dikendalikan antara lain lahan dipenuhi rumput liar, alang alang, gulma daun lebar, gulma rumput, dan teki yang mengganggu pertumbuhan tanaman utama.\r\n\r\nRoundup bekerja secara sistemik dengan diserap melalui daun kemudian ditranslokasikan hingga ke akar sehingga gulma mati sampai ke perakarannya.\r\n\r\nCocok digunakan saat persiapan lahan, sistem tanpa olah tanah (TOT), maupun pembersihan kebun sebelum tanam.', '145000', '5', '1 liter', '', '', '', ''),
('108', 'Gol-Ok Herbisida', 'Herbisida', 'Kelapa Sawit, Karet, Jagung, Tebu', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput, Teki', 'Perkebunan, Lahan Terbuka', '4â€“10 ml/L air', 'golok,\r\ngol-ok,\r\nobat rumput,\r\nracun rumput,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nherbisida kebun,\r\nobat rumput sawit,\r\nobat rumput karet,\r\nobat lahan kosong,\r\nbersih kebun,\r\nsemprot rumput,\r\ngulma membandel,\r\nrumput liar,\r\nteki teki,\r\ngulma daun lebar,\r\nherbisida perkebunan,\r\nracun gulma', 'Gol-Ok merupakan herbisida sistemik non selektif yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan perkebunan dan pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun alang alang, pengendali teki, serta pembersih lahan sebelum tanam.\r\n\r\nCocok untuk mengendalikan gulma daun lebar, rumput liar, dan teki yang tumbuh pada perkebunan sawit, karet, tebu, maupun lahan pertanian lainnya.\r\n\r\nHerbisida ini bekerja dengan diserap melalui daun kemudian ditranslokasikan ke seluruh jaringan gulma hingga akar sehingga gulma mati secara menyeluruh.\r\n\r\nDigunakan pada fase persiapan lahan dan pembersihan kebun sebelum budidaya tanaman.', '60000', '5', ' liter', '', '', '', ''),
('109', 'Maxxfosate Neo 525 SL', 'Herbisida', 'Kelapa Sawit, Karet, Perkebunan', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput, Teki', 'Perkebunan, Lahan Terbuka', '1,125â€“1,5 L/ha', 'maxxfosate,\r\nmaxxfosate neo,\r\nobat rumput,\r\nracun rumput,\r\nglyphosate,\r\nglifosat,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nsemprot rumput,\r\nherbisida sawit,\r\nherbisida karet,\r\nobat gulma kebun,\r\npembersih lahan,\r\ngulma membandel,\r\nrumput liar,\r\nobat rumput perkebunan,\r\nherbisida glifosat,\r\nracun gulma', 'Maxxfosate Neo 525 SL merupakan herbisida sistemik non selektif berbahan aktif glifosat yang digunakan untuk mengendalikan gulma pada area perkebunan.\r\n\r\nProduk ini sering digunakan sebagai obat rumput, racun alang alang, pengendali teki, dan herbisida gulma membandel pada kebun sawit dan karet.\r\n\r\nGejala yang dapat dikendalikan antara lain dominasi gulma daun lebar, gulma rumput, serta teki yang menghambat pertumbuhan tanaman utama.\r\n\r\nMaxxfosate bekerja secara sistemik dengan ditranslokasikan hingga ke akar sehingga memberikan pengendalian gulma yang lebih tuntas.\r\n\r\nCocok diaplikasikan saat gulma tumbuh aktif dengan tingkat penutupan lahan tinggi.', '70000', '7', '500ml', '', '', '', ''),
('110', 'Insta Max 240 SL', 'Herbisida', 'Kelapa Sawit, Jagung, Karet', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Rumput Muda', 'Perkebunan, Lahan Terbuka', '2â€“5 L/ha', 'insta max,\r\ninstamax,\r\nobat rumput,\r\nracun rumput,\r\nobat gulma,\r\nherbisida kontak,\r\nparaquat,\r\nparakuat,\r\nobat alang alang,\r\nracun alang alang,\r\nsemprot rumput,\r\nbersih kebun,\r\nobat gulma cepat mati,\r\nrumput cepat kering,\r\nherbisida perkebunan,\r\nobat lahan kosong,\r\nracun gulma,\r\nobat rumput sawit,\r\nobat rumput jagung,\r\ngulma muda', 'Insta Max 240 SL merupakan herbisida kontak yang bekerja cepat untuk mengendalikan gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun gulma, dan pembersih lahan sebelum tanam karena mampu mengeringkan gulma dalam waktu singkat.\r\n\r\nEfektif mengendalikan gulma daun lebar, rumput muda, dan berbagai gulma yang tumbuh pada kebun sawit, jagung, dan karet.\r\n\r\nCara kerja produk adalah merusak jaringan hijau gulma secara langsung sehingga gulma cepat layu dan mati.\r\n\r\nCocok digunakan untuk pembersihan kebun dan persiapan lahan budidaya.', '65.000', '5', '1 liter', '', '', '', ''),
('111', 'Neoxone 276 SL', 'Herbisida', 'Kelapa Sawit, Kakao, Jagung, Padi TOT', 'Pra Tanam, Persiapan Lahan', 'Gulma Daun Lebar, Gulma Rumput, Teki', 'Perkebunan, Sawah TOT, Lahan Terbuka', '1,5â€“3 L/ha', 'neoxone,\r\nneoxone 276,\r\nobat rumput,\r\nracun rumput,\r\nparaquat,\r\nparakuat,\r\nobat alang alang,\r\nracun alang alang,\r\nobat teki,\r\nracun teki,\r\nsemprot rumput,\r\nobat gulma sawit,\r\nobat gulma kakao,\r\nobat gulma jagung,\r\nobat rumput padi,\r\ntot,\r\ntanpa olah tanah,\r\ngulma membandel,\r\nrumput liar,\r\nracun gulma cepat', 'Neoxone 276 SL merupakan herbisida kontak berbahan aktif parakuat diklorida yang digunakan untuk mengendalikan gulma pada perkebunan dan lahan pertanian.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun alang alang, pengendali teki, serta pembersih lahan sebelum tanam pada perkebunan sawit, kakao, jagung, dan sistem padi tanpa olah tanah.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma daun lebar, gulma rumput, dan teki yang menutupi lahan budidaya.\r\n\r\nNeoxone bekerja dengan merusak jaringan hijau tanaman gulma secara cepat sehingga gulma mengering dan mati.\r\n\r\nCocok digunakan untuk mempercepat persiapan lahan dan pengendalian gulma pada areal perkebunan.', '65000', '5', '1 liter', '', '', '', ''),
('112', 'Supremo 480 SL', 'Herbisida', 'Kelapa Sawit, Karet, Kakao, Teh, Kopi, Jagung', 'Pra Tanam, Persiapan Lahan, Pasca Panen', 'Gulma Daun Lebar, Gulma Rumput, Alang-Alang, Teki-Tekian', 'Perkebunan, Lahan Kering, Lahan Terbuka', '5â€“10 ml/L air atau 2â€“6 L/ha', 'supremo, supremo 480 sl, herbisida supremo, obat rumput, racun rumput, pembasmi rumput, obat gulma, racun gulma, obat alang alang, racun alang alang, obat teki, racun teki, rumput liar, herbisida sawit, herbisida karet, herbisida jagung, pembersih lahan, semprot rumput, bersih kebun, gulma membandel, herbisida glifosat, glifosat, glyphosate, obat rumput kebun, obat rumput sawit, tot, tanpa olah tanah', 'Supremo 480 SL merupakan herbisida sistemik non selektif berbahan aktif isopropil amina glifosat 480 g/L yang digunakan untuk mengendalikan berbagai jenis gulma pada lahan pertanian dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat rumput, racun rumput, pembasmi alang alang, pengendali teki, dan herbisida gulma membandel pada tanaman kelapa sawit, karet, kakao, teh, kopi, dan jagung.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan rumput liar, alang alang, gulma daun lebar, gulma rumput, dan teki teki yang menutupi area perakaran tanaman budidaya.\r\n\r\nSupremo bekerja secara sistemik dengan diserap melalui daun lalu ditranslokasikan hingga ke akar sehingga gulma mati secara menyeluruh sampai ke bagian bawah tanah.\r\n\r\nProduk ini sering digunakan pada sistem tanpa olah tanah (TOT), pembersihan kebun, persiapan lahan sebelum tanam, dan pengendalian gulma pada areal perkebunan produktif.', '60000', '5', '1 liter', '', '', '', ''),
('113', 'Metsulindo 20 WG', 'Herbisida', 'Kelapa Sawit TBM, Karet, Tebu, Lahan Perkebunan', 'Pasca Tumbuh Gulma (Post Emergence)', 'Gulma Daun Lebar, Gulma Semusim, Gulma Berkayu Muda', 'Perkebunan, Lahan Kering', '10â€“50 gram/ha atau sesuai rekomendasi lapangan', 'metsulindo, metsulfuron methyl, herbisida metsulindo, obat gulma daun lebar, racun gulma daun lebar, pembasmi semak, obat semak liar, racun semak, herbisida sawit, herbisida karet, obat gulma kebun, gulma bandotan, gulma sembung rambat, gulma kirinyuh, gulma berkayu, gulma semusim, gulma tahunan, semprot gulma, pembersih kebun, obat rumput kebun, pengendali gulma perkebunan, sulfonilurea, sulfonylurea herbicide', 'Metsulindo merupakan herbisida selektif sistemik berbahan aktif metsulfuron methyl dari golongan sulfonilurea yang digunakan untuk mengendalikan gulma daun lebar dan semak pada lahan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat gulma daun lebar, pembasmi semak liar, pengendali gulma berkayu muda, dan herbisida perkebunan pada tanaman kelapa sawit, karet, dan tebu.\r\n\r\nGejala yang dapat dikendalikan antara lain pertumbuhan gulma bandotan, kirinyuh, sembung rambat, gulma semusim, serta berbagai gulma daun lebar yang sulit dikendalikan dengan herbisida biasa.\r\n\r\nMetsulindo bekerja secara sistemik dengan menghambat pembelahan sel pada jaringan gulma sehingga pertumbuhan gulma berhenti, menguning, kemudian mati secara bertahap.\r\n\r\nProduk ini cocok digunakan pada areal perkebunan yang didominasi gulma daun lebar dan semak berkayu muda untuk menjaga kebersihan lahan dan mengurangi kompetisi unsur hara.', '45000', '5', '250 gram', '', '', '', ''),
('114', 'Ridomil Gold MZ 68 WG', 'Fungisida', 'Tomat, Kentang, Melon, Jeruk, Kakao', 'Vegetatif, Generatif Awal', 'Busuk Daun, Embun Bulu, Hawar Daun, Downy Mildew, Phytophthora', 'Tanah, Bedengan, Lahan Terbuka', '2â€“3 gram/liter air', 'fungisida busuk daun,\r\nobat busuk daun,\r\nobat hawar daun,\r\nfungisida hawar daun,\r\nobat embun bulu,\r\nfungisida embun bulu,\r\nobat phytophthora,\r\nfungisida tomat,\r\nfungisida kentang,\r\nobat daun menghitam,\r\nobat daun gosong,\r\nobat daun bercak coklat,\r\nobat tanaman layu,\r\nfungisida melon,\r\nfungisida kakao,\r\nfungisida jeruk,\r\nobat penyakit jamur,\r\nobat daun keriting karena jamur,\r\nfungisida sistemik,\r\nobat busuk batang,\r\nobat busuk buah,\r\nobat daun kuning,\r\npengendali penyakit tanaman', 'Ridomil Gold MZ 68 WG merupakan fungisida sistemik dan kontak berbahan aktif mefenoxam 4% dan mankozeb 64% yang digunakan untuk mengendalikan penyakit busuk daun, embun bulu, hawar daun, dan penyakit yang disebabkan oleh jamur Oomycetes.\r\n\r\nProduk ini banyak digunakan sebagai obat busuk daun tomat, fungisida kentang, obat embun bulu melon, serta pengendali penyakit Phytophthora pada tanaman hortikultura.\r\n\r\nGejala yang dapat dikendalikan antara lain daun menghitam, daun layu, bercak coklat, busuk batang, busuk buah, dan kerusakan akibat infeksi jamur.\r\n\r\nCocok digunakan pada fase vegetatif hingga generatif awal sebagai perlindungan dan pengobatan penyakit tanaman.', '35000', '5', '250gram', 'â€”', '', '', ''),
('115', 'Blastgone 75 WP', 'Fungisida', 'Padi', 'Vegetatif, Pembentukan Malai', 'Blas, Blast, Pyricularia oryzae', 'Sawah', '1â€“2 sachet/tangki', 'fungisida blas,\r\nobat blas padi,\r\nobat daun padi bercak,\r\nfungisida padi,\r\nobat penyakit blast,\r\nobat padi terbakar,\r\nfungisida pyricularia,\r\nobat bercak belah ketupat,\r\nobat daun padi kering,\r\nobat penyakit leher malai,\r\nfungisida sawah,\r\nobat padi kuning,\r\nobat daun padi rusak,\r\npengendali penyakit padi,\r\nobat jamur padi', 'Blastgone 75 WP merupakan fungisida sistemik berbahan aktif tricyclazole 750 g/kg yang digunakan untuk mengendalikan penyakit blas pada tanaman padi.\r\n\r\nProduk ini sering digunakan sebagai obat blas padi, fungisida blast, dan pengendali penyakit Pyricularia oryzae yang menyebabkan kerusakan pada daun maupun leher malai.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak belah ketupat pada daun, daun mengering, malai kosong, dan penurunan hasil panen akibat penyakit blas.\r\n\r\nCocok diaplikasikan pada fase vegetatif hingga pembentukan malai.', '35000', '6', '120gram', '', '', '', ''),
('116', 'Heksa 50 SC', 'Fungisida', 'Padi, Cabai, Bawang Merah, Jagung, Kakao, Karet', 'Vegetatif, Generatif Awal', 'Bercak Daun, Hawar Daun, Karat Daun, Jamur Daun', 'Sawah, Lahan Terbuka', '0,5â€“1 ml/liter air', 'fungisida heksakonazol,\r\nobat bercak daun,\r\nfungisida bercak daun,\r\nobat karat daun,\r\nfungisida karat daun,\r\nobat hawar daun,\r\nfungisida padi,\r\nfungisida cabai,\r\nfungisida bawang merah,\r\nobat daun menguning,\r\nobat daun bercak coklat,\r\nobat jamur daun,\r\nfungisida sistemik,\r\nobat penyakit tanaman,\r\npengendali jamur tanaman', 'Heksa 50 SC merupakan fungisida sistemik berbahan aktif heksakonazol 50 g/L yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman padi, cabai, bawang merah, jagung, kakao, dan karet.\r\n\r\nProduk ini sering digunakan sebagai obat bercak daun, fungisida karat daun, dan pengendali penyakit jamur pada berbagai komoditas pertanian.\r\n\r\nGejala yang dapat dikendalikan antara lain bercak daun, karat daun, daun menguning, dan kerusakan jaringan akibat infeksi jamur.\r\n\r\nCocok digunakan sejak awal munculnya gejala penyakit.', '35000', '5', '100ml', '-', '', '', ''),
('117', 'Manzate 82 WP', 'Fungisida', 'Cabai, Tomat, Bawang Merah, Kentang, Semangka, Melon, Anggur, Karet', 'Vegetatif, Generatif', 'Busuk Daun, Bercak Daun, Embun Bulu, Tepung Palsu', 'Tanah, Bedengan, Lahan Terbuka', '2â€“3 gram/liter air', 'fungisida mankozeb,\r\nobat busuk daun,\r\nfungisida busuk daun,\r\nobat bercak daun,\r\nobat embun bulu,\r\nfungisida embun bulu,\r\nobat tepung palsu,\r\nfungisida tomat,\r\nfungisida cabai,\r\nfungisida kentang,\r\nfungisida bawang merah,\r\nobat daun menghitam,\r\nobat daun bercak coklat,\r\nobat jamur tanaman,\r\nobat penyakit daun,\r\npengendali jamur tanaman', 'Manzate 82 WP merupakan fungisida kontak berbahan aktif mankozeb 82% yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman hortikultura dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat busuk daun tomat, fungisida kentang, obat embun bulu semangka, dan pengendali bercak daun pada cabai serta bawang merah.\r\n\r\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menghitam, embun bulu, dan busuk daun akibat infeksi jamur.\r\n\r\nCocok digunakan sebagai fungisida pencegahan sebelum penyakit berkembang luas.', '52000', '5', '250gram', '-', '', '', ''),
('118', 'Delsen 64/8 WP', 'Fungisida', 'Cabai, Bawang Merah, Jagung, Kacang Tanah, Karet, Kentang, Padi, Tomat', 'Vegetatif, Generatif', 'Hawar Daun, Bercak Daun, Karat Daun, Busuk Daun, Downy Mildew', 'Sawah, Tanah, Lahan Terbuka', '2â€“3 gram/liter air', 'fungisida metalaksil,\r\nfungisida mankozeb,\r\nobat hawar daun,\r\nfungisida hawar daun,\r\nobat bercak daun,\r\nobat karat daun,\r\nobat busuk daun,\r\nfungisida padi,\r\nfungisida cabai,\r\nfungisida bawang merah,\r\nfungisida kentang,\r\nobat embun bulu,\r\nobat jamur tanaman,\r\nobat penyakit daun,\r\npengendali penyakit jamur,\r\nobat daun menguning,\r\nobat daun bercak coklat', 'Delsen 64/8 WP merupakan fungisida kontak dan sistemik berbahan aktif mankozeb 64% dan metalaksil 8% yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman pangan, hortikultura, dan perkebunan.\r\n\r\nProduk ini banyak digunakan sebagai obat hawar daun, fungisida busuk daun, pengendali bercak daun, karat daun, dan embun bulu pada berbagai komoditas.\r\n\r\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menguning, busuk daun, karat daun, serta kerusakan tanaman akibat infeksi jamur patogen.\r\n\r\nCocok digunakan pada fase vegetatif maupun generatif sebagai tindakan pencegahan dan pengendalian penyakit.', '128450', '', '75gram', '-', '', '', ''),
('119', 'Curzate 8/64 WP', 'Fungisida', 'Kentang, Tomat, Cabai, Semangka, Tembakau', 'Vegetatif, Generatif Awal', '	\n\nBusuk Daun, Hawar Daun, Embun Bulu, Lanas', 'Tanah, Lahan Terbuka', '0,5 â€“ 1 g/L air; 1 â€“ 2 kg/ha; aplikasi 7â€“14 hari sekali', 'fungisida busuk daun,\nobat hawar daun,\nanti embun bulu,\nobat lanas tembakau,\nfungisida kentang,\nfungisida tomat,\nfungisida cabai,\nfungisida semangka,\ncurzate 8/64 wp,\nobat jamur daun', 'Curzate 8/64 WP merupakan fungisida sistemik dan kontak berbahan aktif cymoxanil dan mankozeb yang digunakan untuk mengendalikan penyakit busuk daun, hawar daun, embun bulu, dan lanas pada tanaman kentang, tomat, cabai, semangka, dan tembakau.\n\nProduk ini cocok digunakan sebagai fungisida busuk daun kentang, obat hawar daun tomat, anti embun bulu semangka, serta pengendali penyakit lanas tembakau.\n\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menghitam, busuk daun, embun putih pada daun, serta kerusakan tanaman akibat infeksi jamur.', '15000', '10 gram, 100 gram', '', '', '', '', ''),
('120', 'Nando 500 SC', 'Fungisida', 'Padi, Cabai, Bawang Merah, Jagung, Kedelai', 'Vegetatif, Generatif', 'Blas, Hawar Daun, Bercak Daun, Karat Daun', 'Sawah, Tanah, Lahan Terbuka', '0,5 â€“ 1 ml/L air; 100 â€“ 200 ml/ha; aplikasi 7â€“10 hari sekali', 'fungisida padi,\nobat blas padi,\nanti hawar daun,\nfungisida cabai,\nfungisida bawang merah,\nnando 500 sc,\nobat bercak daun,\nfungisida jagung,\nfungisida kedelai,\npengendali penyakit daun,', 'Nando 500 SC merupakan fungisida sistemik berbentuk suspension concentrate yang digunakan untuk mengendalikan penyakit blas, hawar daun, bercak daun, dan karat daun pada tanaman padi, cabai, bawang merah, jagung, dan kedelai.\n\nProduk ini cocok digunakan sebagai fungisida padi, obat blas padi, anti hawar daun cabai, serta pengendali bercak daun bawang merah.\n\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menguning, hawar pada daun, karat daun, serta penurunan pertumbuhan akibat serangan jamur.', '85000', '5', '100 ml', '', '', '', ''),
('121', 'Banjoforte 400 SC', 'Fungisida', 'Padi, Cabai, Tomat, Kentang', 'Vegetatif, Generatif Awal', 'Busuk Daun, Hawar Daun, Blas, Bercak Daun', 'Sawah, Tanah, Lahan Terbuka', '0,5 â€“ 1 ml/L air; 100 â€“ 200 ml/ha; aplikasi 7â€“10 hari sekali', 'fungisida busuk daun,\nobat hawar daun,\nobat blas padi,\nfungisida cabai,\nfungisida tomat,\nfungisida kentang,\nbanjoforte 400 sc,\nanti bercak daun,\npengendali jamur daun,\nobat daun menghitam,', 'Banjoforte 400 SC merupakan fungisida sistemik berbentuk suspension concentrate yang digunakan untuk mengendalikan penyakit busuk daun, hawar daun, blas, dan bercak daun pada tanaman padi, cabai, tomat, dan kentang.\n\nProduk ini cocok digunakan sebagai fungisida busuk daun kentang, obat hawar daun tomat, anti blas padi, serta pengendali bercak daun cabai.\n\nGejala yang dapat dikendalikan antara lain daun bercak coklat, daun menghitam, hawar pada daun, busuk daun, serta kerusakan tanaman akibat infeksi jamur.', '95000', '5', '100 ml', '', '', '', ''),
('122', 'Amistar Top 325 SC', 'Fungisida', 'Padi, Cabai, Bawang Merah, Tomat, Jagung', 'Vegetatif, Generatif', 'Blas, Hawar Daun, Bercak Daun, Karat Daun, Busuk Daun', 'Sawah, Tanah, Lahan Terbuka', '0,5 â€“ 1 ml/L air; 100 â€“ 200 ml/ha; aplikasi 7â€“14 hari sekali', 'fungisida padi,\nobat blas padi,\nfungisida cabai,\nfungisida bawang merah,\nanti hawar daun,\nanti bercak daun,\nobat busuk daun,\namistar top 325 sc,\nfungisida jagung,\npengendali penyakit jamur,', 'Amistar Top 325 SC merupakan fungisida sistemik berbentuk suspension concentrate yang digunakan untuk mengendalikan penyakit blas, hawar daun, bercak daun, karat daun, dan busuk daun pada tanaman padi, cabai, bawang merah, tomat, dan jagung.\n\nProduk ini cocok digunakan sebagai fungisida padi, obat blas padi, anti hawar daun cabai, pengendali bercak daun bawang merah, serta fungisida busuk daun tomat.\n\nGejala yang dapat dikendalikan antara lain daun bercak coklat, hawar pada daun, karat daun, busuk daun, serta kerusakan tanaman akibat infeksi jamur.', '120.000', '5', '100 ml', '', '', '', ''),
('123', 'Ortiva 250 SC', 'Fungisida', 'Cabai, Tomat, Bawang Merah, Kentang, Padi', 'Vegetatif, Generatif', 'Antraknosa, Patek, Bercak Daun, Hawar Daun, Busuk Daun', 'Tanah, Sawah, Lahan Terbuka', '0,5 â€“ 1 ml/L air; 100 â€“ 200 ml/ha; aplikasi 7â€“10 hari sekali', 'fungisida antraknosa,\nobat patek cabai,\nanti bercak daun,\nobat busuk daun,\nfungisida tomat,\nfungisida bawang merah,\nfungisida kentang,\nfungisida padi,\nortiva 250 sc,\npengendali penyakit jamur,', 'Ortiva 250 SC merupakan fungisida sistemik berbentuk suspension concentrate yang digunakan untuk mengendalikan penyakit antraknosa, patek, bercak daun, hawar daun, dan busuk daun pada tanaman cabai, tomat, bawang merah, kentang, dan padi.\n\nProduk ini cocok digunakan sebagai fungisida antraknosa cabai, obat patek cabai, anti bercak daun tomat, serta pengendali busuk daun kentang.\n\nGejala yang dapat dikendalikan antara lain buah cabai patek, daun bercak coklat, hawar pada daun, busuk daun, serta kerusakan tanaman akibat infeksi jamur.', '135.000', '5', '100 ml', '-', '', '', ''),
('124', 'Cabrio Top 60 WG', 'Fungisida', 'Cabai, Tomat, Kentang, Bawang Merah, Apel, Mangga, Kacang Tanah, Kacang Hijau', 'Vegetatif, Generatif', 'Antraknosa, Busuk Daun, Embun Tepung, Bercak Daun, Hawar Daun, Busuk Buah', 'Lahan Terbuka, Sawah, Kebun, Hortikultura', '1â€“3 g/L air', 'fungisida antraknosa,\r\nobat patek cabai,\r\nobat busuk daun,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida kentang,\r\nfungisida bawang merah,\r\nobat daun keriting jamur,\r\nobat bercak daun,\r\nobat hawar daun,\r\nfungisida musim hujan,\r\nobat jamur buah,\r\nobat busuk buah,\r\nfungisida sistemik,\r\nfungisida kontak,\r\nobat daun menguning,\r\nobat daun bercak coklat,\r\nobat patek buah cabai,\r\nobat penyakit jamur tanaman,\r\nfungisida broad spectrum,\r\nobat jamur cabai keriting,\r\nfungisida piraklostrobin,\r\nfungisida metiram', 'Cabrio Top 60 WG merupakan fungisida berbahan aktif piraklostrobin 5% dan metiram 55% yang bekerja secara sistemik, translaminar, dan protektif untuk mengendalikan berbagai penyakit jamur pada tanaman hortikultura.\r\nProduk ini banyak digunakan sebagai obat patek cabai, fungisida antraknosa, pengendali busuk daun, serta pencegah penyakit jamur pada tomat, kentang, bawang merah, apel, dan mangga.\r\nGejala yang dapat dikendalikan antara lain bercak daun, daun menguning akibat jamur, busuk buah, embun tepung, antraknosa, dan hawar daun.\r\nMemiliki efek residual yang panjang sehingga cocok digunakan saat musim hujan maupun saat tekanan penyakit tinggi.', '77.000', '4', '250 gr', '', '', '', ''),
('125', 'Nativo 75 WG', 'Fungisida', 'Padi, Cabai, Tomat, Bawang Merah, Jagung, Kedelai, Mentimun, Semangka, Melon', 'Vegetatif, Generatif', 'Blas, Busuk Upih, Antraknosa, Embun Tepung, Bercak Daun, Hawar Daun, Bercak Ungu', 'Sawah, Lahan Terbuka, Hortikultura', '0,5â€“1 g/L air', 'fungisida blas,\r\nobat blas padi,\r\nobat busuk upih,\r\nfungisida busuk upih,\r\nobat patek cabai,\r\nfungisida antraknosa,\r\nobat embun tepung,\r\nfungisida bawang merah,\r\nobat bercak ungu,\r\nfungisida cabai,\r\nfungisida tomat,\r\nfungisida padi,\r\nobat hawar daun,\r\nobat jamur tanaman,\r\nfungisida sistemik,\r\nobat daun bercak,\r\nobat penyakit bulai,\r\nobat jamur daun,\r\nobat busuk buah,\r\nfungisida trifloksistrobin,\r\nfungisida tebukonazol', 'Nativo 75 WG merupakan fungisida sistemik berbahan aktif trifloksistrobin 25% dan tebukonazol 50% yang memiliki sifat preventif, kuratif, protektif, dan eradikatif.\r\nProduk ini banyak digunakan petani sebagai obat blas padi, fungisida busuk upih, obat patek cabai, pengendali antraknosa, embun tepung, bercak daun, dan berbagai penyakit jamur lainnya.\r\nGejala yang dapat dikendalikan antara lain bercak daun, busuk upih, bercak ungu bawang merah, antraknosa buah cabai, busuk buah, serta hawar daun.\r\nMemiliki efek sistemik dan residual panjang sehingga efektif digunakan pada fase vegetatif maupun generatif.', '23.000', '5', '12,5 gr', '', '', '', ''),
('126', 'Folicur 250 EC', 'Fungisida', 'Padi, Cabai, Bawang Merah, Jagung, Kedelai, Gandum', 'Vegetatif, Generatif', 'Blas, Karat Daun, Embun Tepung, Bercak Daun, Busuk Pelepah', 'Sawah, Lahan Terbuka', '0,5â€“1 ml/L air', 'fungisida blas,\r\nobat blas padi,\r\nfungisida karat daun,\r\nobat karat daun,\r\nobat embun tepung,\r\nfungisida sistemik,\r\nobat busuk pelepah,\r\nfungisida padi,\r\nfungisida bawang merah,\r\nobat bercak daun,\r\nfungisida cabai,\r\nobat jamur tanaman,\r\nfungisida tebukonazol,\r\nobat daun menguning,\r\nobat penyakit daun,\r\nfungisida preventif,\r\nfungisida kuratif,\r\nobat jamur batang,\r\nobat penyakit padi,\r\nfungisida spektrum luas', 'Folicur 250 EC merupakan fungisida sistemik berbahan aktif tebukonazol yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman pangan dan hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat blas padi, fungisida karat daun, pengendali embun tepung, bercak daun, dan busuk pelepah.\r\n\r\nMampu memberikan perlindungan preventif sekaligus kuratif terhadap infeksi cendawan pada fase vegetatif maupun generatif.', '75.000', '6', '100 ml,', '', '', '', ''),
('127', 'Tilt 250 EC', 'Fungisida', 'Padi, Cabai, Jagung, Gandum, Sayuran', 'Vegetatif, Generatif', 'Karat Daun, Embun Tepung, Hawar Daun, Bercak Daun', 'Sawah, Lahan Terbuka', '0,5â€“1 ml/L air', 'fungisida karat daun,\r\nobat karat daun,\r\nobat embun tepung,\r\nfungisida padi,\r\nfungisida jagung,\r\nobat hawar daun,\r\nfungisida propikonazol,\r\nobat bercak daun,\r\nobat jamur daun,\r\nfungisida sistemik,\r\nobat daun menguning,\r\nfungisida cabai,\r\nobat penyakit daun,\r\nfungisida protektif,\r\nfungisida kuratif,\r\nobat penyakit padi,\r\nobat jamur tanaman,\r\nfungisida spektrum luas,\r\nobat karat tanaman,\r\nfungisida hortikultura', 'Tilt 250 EC merupakan fungisida sistemik berbahan aktif propikonazol yang digunakan untuk mengendalikan penyakit jamur seperti karat daun, embun tepung, hawar daun, dan bercak daun.\r\n\r\nProduk ini banyak digunakan pada tanaman padi, jagung, cabai, dan berbagai tanaman hortikultura untuk menjaga kesehatan daun dan meningkatkan produktivitas tanaman.\r\n\r\nMemiliki kemampuan protektif dan kuratif dengan daya sebar yang baik pada jaringan tanaman.', '80.000', '7', '100 ml', '', '', '', ''),
('128', 'Melody Duo 66.75 WP', 'Fungisida', 'Kentang, Tomat, Cabai, Mentimun, Semangka, Melon', 'Vegetatif, Generatif', 'Busuk Daun, Downy Mildew, Hawar Daun, Busuk Buah', 'Lahan Terbuka, Hortikultura', '2â€“3 g/L air', 'obat busuk daun,\r\nfungisida busuk daun,\r\nobat hawar daun,\r\nfungisida hawar daun,\r\nobat embun bulu,\r\nfungisida downy mildew,\r\nobat patek,\r\nfungisida tomat,\r\nfungisida kentang,\r\nfungisida cabai,\r\nobat daun menghitam,\r\nobat daun bercak,\r\nobat busuk buah,\r\nfungisida sistemik,\r\nfungisida kontak,\r\nobat jamur tanaman,\r\nobat penyakit musim hujan,\r\nfungisida sayuran,\r\nobat layu daun,\r\npengendali penyakit jamur', 'Melody Duo 66.75 WP merupakan fungisida kombinasi sistemik dan kontak yang digunakan untuk mengendalikan penyakit busuk daun, embun bulu, hawar daun, dan penyakit jamur penting lainnya pada tanaman hortikultura.\r\n\r\nProduk ini banyak digunakan sebagai obat busuk daun kentang, fungisida tomat, fungisida cabai, dan pengendali penyakit pada mentimun, melon, serta semangka.\r\n\r\nGejala yang dapat dikendalikan antara lain daun menghitam, daun bercak, busuk buah, dan kerusakan jaringan tanaman akibat infeksi cendawan.\r\n\r\nCocok digunakan pada musim hujan ketika tekanan penyakit meningkat.', '90.000', '5', '100 gr', '-', '', '', ''),
('129', 'Acrobat MZ 69 WP', 'Fungisida', 'Kentang, Tomat, Cabai, Mentimun, Semangka, Melon', 'Preventif, Vegetatif, Awal Generatif', 'Busuk Daun, Hawar Daun, Embun Bulu, Phytophthora, Downy Mildew', 'Tanah, Bedengan, Lahan Terbuka', '2â€“4 gram/L air atau Â± 500â€“750 gram/ha', 'fungisida busuk daun, obat busuk daun kentang, obat busuk daun tomat, fungisida phytophthora, obat hawar daun, fungisida embun bulu, obat daun menghitam, fungisida cabai, fungisida tomat, fungisida kentang, obat daun layu, obat daun bercak coklat, anti busuk daun, obat kresek daun, fungisida semangka, fungisida melon, obat penyakit daun tanaman, obat daun gosong', 'Acrobat MZ 69 WP merupakan fungisida kombinasi dimethomorph dan mancozeb yang bekerja secara sistemik lokal dan kontak untuk mengendalikan penyakit akibat kelompok Oomycetes. Produk ini banyak digunakan sebagai fungisida busuk daun kentang, obat hawar daun tomat, fungisida embun bulu mentimun, dan pengendali Phytophthora pada berbagai tanaman hortikultura. Gejala yang dapat dikendalikan antara lain daun menghitam, daun layu, bercak basah pada daun, busuk daun, serta kerusakan akibat serangan jamur patogen', '120.000', '5', '500 gr', '', '', '', ''),
('130', 'Equation Pro WG', 'Fungisida', 'Kentang, Tomat, Melon, Semangka', 'Preventif, Vegetatif, Generatif Awal', 'Busuk Daun, Embun Bulu, Downy Mildew, Phytophthora', 'Tanah, Bedengan, Lahan Terbuka', '0,5â€“1 gram/L air atau Â± 200â€“400 gram/ha', 'equation pro, fungisida busuk daun, obat phytophthora, obat embun bulu, fungisida kentang, fungisida tomat, obat daun layu, obat daun menghitam, fungisida melon, fungisida semangka, anti busuk daun, fungisida sistemik, obat penyakit daun, fungisida hawar daun, obat jamur tanaman', 'Equation Pro WG merupakan fungisida kombinasi famoxadone dan cymoxanil yang memiliki aktivitas preventif dan kuratif terhadap penyakit jamur penting pada tanaman hortikultura. Produk ini banyak digunakan sebagai fungisida busuk daun kentang, pengendali embun bulu mentimun dan melon, serta pengendali penyakit Phytophthora pada tomat dan semangka. Gejala yang dapat dikendalikan antara lain bercak daun, daun menghitam, embun putih pada daun, busuk batang, dan kerusakan jaringan akibat infeksi jamur.', '90.000', '7', '200 gr', '-', '', '', ''),
('131', 'Combi Plus 75 WP', 'Fungisida', 'Padi, Cabai, Tomat, Bawang Merah, Sayuran', 'Vegetatif, Generatif', 'Bercak Daun, Hawar Daun, Busuk Daun, Jamur Daun', 'Sawah, Tanah, Bedengan', '1â€“2 gram/L air', 'combi plus, fungisida padi, fungisida cabai, obat bercak daun, obat hawar daun, fungisida bawang merah, fungisida tomat, obat daun menguning, fungisida daun, obat jamur tanaman, fungisida sistemik, anti bercak daun, anti hawar daun, obat daun kering', 'Combi Plus 75 WP merupakan fungisida berbentuk tepung yang digunakan untuk mengendalikan berbagai penyakit daun pada tanaman pangan dan hortikultura. Produk ini banyak digunakan sebagai fungisida bercak daun, obat hawar daun, serta pengendali penyakit jamur yang menyebabkan kerusakan pada jaringan daun dan batang tanaman. Gejala yang dapat dikendalikan antara lain bercak coklat, daun menguning, daun mengering, serta penurunan pertumbuhan akibat serangan patogen jamur.', '20.000', '7', '100 gr', '', '', '', ''),
('132', 'Anvil 50 SC', 'Fungisida', 'Padi, Cabai, Tomat, Bawang Merah, Semangka, Kedelai, Kacang Tanah, Kopi, Karet', 'Vegetatif, Generatif', 'Bercak Daun, Karat Daun, Embun Tepung, Hawar Daun, Busuk Pangkal Batang', 'Sawah, Tanah, Bedengan, Perkebunan', '0,5â€“1 ml/L air', 'anvil 50 sc, fungisida sistemik, obat karat daun, fungisida padi, fungisida cabai, fungisida tomat, obat embun tepung, fungisida bawang merah, obat bercak daun, obat daun berkarat, fungisida semangka, fungisida kedelai, obat jamur daun, anti karat daun, fungisida tanaman perkebunan, obat penyakit tanaman', 'Anvil 50 SC merupakan fungisida sistemik berbahan aktif hexaconazole yang digunakan untuk mengendalikan berbagai penyakit jamur pada tanaman pangan, hortikultura, dan perkebunan. Produk ini efektif sebagai obat karat daun, fungisida embun tepung, pengendali bercak daun, serta pengendali busuk pangkal batang. Gejala yang dapat dikendalikan antara lain daun berkarat, bercak daun coklat, embun putih pada permukaan daun, daun mengering, dan kerusakan jaringan akibat infeksi jamur.', '65.000', '7', '250 ml', '', '', '', ''),
('133', 'Omite 570 EC', 'Akarisida', 'Cabai, Tomat, Jeruk, Apel, Anggur, Teh', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Tungau Laba-laba', 'Tanah, Lahan Terbuka, Greenhouse', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi tungau kuning,\npestisida tungau tanaman,\nobat kutu laba-laba tanaman,\nakarisida cabai,\nakarisida tomat,\nakarisida jeruk,\nomite 570 ec,\npengendali hama tungau,', 'Omite 570 EC merupakan pestisida akarisida yang digunakan untuk mengendalikan hama tungau merah, tungau kuning, dan tungau laba-laba pada tanaman cabai, tomat, jeruk, apel, anggur, dan teh. Produk ini berfungsi sebagai akarisida tungau tanaman, obat tungau merah, pembasmi tungau kuning, serta pengendali hama kutu laba-laba yang menyebabkan daun menguning, keriting, bercak, dan pertumbuhan tanaman terhambat.', '', '', '', '', '', '', ''),
('134', 'Kelthane 200 EC', 'Akarisida', 'Cabai, Jeruk, Apel, Teh, Anggur', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Tungau', 'Tanah, Lahan Terbuka', '1â€“2 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi tungau tanaman,\npestisida tungau,\nakarisida cabai,\nakarisida jeruk,\nkelthane 200 ec,\nobat kutu daun tungau,\npengendali tungau merah,\nobat daun keriting akibat tungau,', 'Kelthane 200 EC merupakan pestisida akarisida yang efektif mengendalikan tungau merah dan tungau kuning pada tanaman cabai, jeruk, apel, teh, dan anggur. Produk ini sering digunakan sebagai akarisida tungau tanaman, obat tungau merah, pembasmi hama tungau, dan pengendali kutu laba-laba yang menyebabkan daun keriting, bercak kuning, serta penurunan produktivitas tanaman.', '85.000', '8', '100 ml', '', '', '', ''),
('135', 'Vertimec 18 EC', 'Akarisida', 'Cabai, Tomat, Kentang, Bawang Merah', 'Vegetatif, Generatif', 'Tungau, Thrips, Lalat Pengorok Daun', 'Tanah, Greenhouse', '0,5 ml/L air', 'akarisida tungau,\nobat tungau tanaman,\npembasmi tungau merah,\npestisida thrips,\nobat lalat pengorok daun,\nvertimec 18 ec,\nakarisida cabai,\nakarisida tomat,\npengendali tungau tanaman,\nobat daun keriting,', 'Vertimec 18 EC merupakan pestisida akarisida dan insektisida yang digunakan untuk mengendalikan tungau merah, tungau tanaman, thrips, dan lalat pengorok daun pada cabai, tomat, kentang, dan bawang merah. Produk ini cocok digunakan sebagai akarisida tungau, obat tungau merah, pembasmi hama tungau, serta pengendali daun keriting dan kerusakan daun akibat serangan tungau dan serangga penghisap.', '250.000', '7', '100 ml', '', '', '', ''),
('136', 'Danitol 10 EC', 'Akarisida', 'Cabai, Jeruk, Apel, Tomat', 'Vegetatif, Generatif', 'Tungau Merah, Thrips, Aphid', 'Tungau Merah, Thrips, Aphid', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npestisida thrips,\nobat aphid,\npengendali tungau tanaman,\ndanitol 10 ec,\nakarisida cabai,\nakarisida tomat,\npembasmi tungau,\nobat daun keriting,\nDeskripsi Optimasi TF-I,', 'Danitol 10 EC merupakan pestisida akarisida yang digunakan untuk mengendalikan tungau merah, thrips, dan aphid pada tanaman cabai, tomat, jeruk, dan apel. Produk ini banyak dimanfaatkan sebagai akarisida tungau tanaman, obat tungau merah, pembasmi hama tungau, serta pengendali daun keriting, bercak kuning, dan kerusakan daun akibat serangan hama penghisap.', '165.000', '5', '100 ml', '', '', '', ''),
('137', 'Mitac 200 EC', 'Akarisida', 'Jeruk, Cabai, Apel, Teh', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Psylla', 'Tanah, Lahan Terbuka', '1â€“2 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi tungau kuning,\npestisida psylla,\npengendali tungau tanaman,\nmitac 200 ec,\nakarisida cabai,\nakarisida jeruk,\nobat daun keriting,\npembasmi hama tungau,', 'Mitac 200 EC merupakan pestisida akarisida yang digunakan untuk mengendalikan tungau merah, tungau kuning, dan psylla pada tanaman jeruk, cabai, apel, dan teh. Produk ini cocok digunakan sebagai akarisida tungau tanaman, obat tungau merah, pembasmi tungau kuning, serta pengendali hama yang menyebabkan daun keriting, bercak kuning, dan penurunan pertumbuhan tanaman.', '95.000', '7', '100 ml', '-', '', '', ''),
('138', 'Sanmite 200 SC', 'Akarisida', 'Cabai, Jeruk, Apel, Teh, Anggur', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Tungau Laba-laba', 'Tanah, Lahan Terbuka, Greenhouse', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi tungau kuning,\npestisida tungau tanaman,\nobat kutu laba-laba tanaman,\nakarisida cabai,\nakarisida jeruk,\nsanmite 200 sc,\npengendali hama tungau,\nobat daun keriting akibat tungau,', 'Sanmite 200 SC merupakan pestisida akarisida yang digunakan untuk mengendalikan hama tungau merah, tungau kuning, dan tungau laba-laba pada tanaman cabai, jeruk, apel, teh, dan anggur. Produk ini berfungsi sebagai akarisida tungau tanaman, obat tungau merah, pembasmi tungau kuning, serta pengendali hama kutu laba-laba yang menyebabkan daun menguning, daun keriting, bercak daun, dan pertumbuhan tanaman terhambat.', '165.000', '5', '100 ml', '', '', '', ''),
('139', 'Nissorun 10 WP', 'Akarisida', 'Cabai, Jeruk, Apel, Teh, Anggur', 'Vegetatif, Generatif', 'Telur Tungau, Nimfa Tungau, Tungau Merah', 'Tanah, Lahan Terbuka', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi telur tungau,\npestisida tungau tanaman,\npengendali nimfa tungau,\nnissorun 10 wp,\nakarisida cabai,\nakarisida jeruk,\npengendali hama tungau,\nobat daun keriting akibat tungau,', 'Nissorun 10 WP merupakan pestisida akarisida yang digunakan untuk mengendalikan telur tungau, nimfa tungau, dan tungau merah pada tanaman cabai, jeruk, apel, teh, dan anggur. Produk ini efektif sebagai akarisida tungau tanaman, obat tungau merah, pembasmi telur tungau, serta pengendali hama tungau yang menyebabkan daun menguning, daun keriting, bercak daun, dan penurunan pertumbuhan tanaman.', '', '', '', '', '', '', ''),
('140', 'Apollo 50 SC', 'Akarisida', 'Jeruk, Cabai, Apel, Anggur', 'Vegetatif, Generatif', 'Telur Tungau, Tungau Merah', 'Tanah, Lahan Terbuka', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi telur tungau,\npestisida tungau tanaman,\npengendali tungau merah,\napollo 50 sc,\nakarisida cabai,\nakarisida jeruk,\npembasmi hama tungau,\nobat daun keriting,', 'Apollo 50 SC merupakan pestisida akarisida yang digunakan untuk mengendalikan telur tungau dan tungau merah pada tanaman jeruk, cabai, apel, dan anggur. Produk ini banyak dimanfaatkan sebagai akarisida tungau tanaman, obat tungau merah, pembasmi telur tungau, serta pengendali hama tungau yang menyebabkan daun keriting, bercak kuning, daun menguning, dan gangguan pertumbuhan tanaman.', '150.000', '4', '100 ml', '-', '', '', ''),
('141', 'Fujimite 5 EC', 'Akarisida', 'Cabai, Jeruk, Tomat, Apel, Anggur', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Tungau Laba-laba', 'Tanah, Greenhouse, Lahan Terbuka', '0,5â€“1 ml/L air', 'akarisida tungau,\nobat tungau merah,\npembasmi tungau kuning,\npestisida tungau tanaman,\nobat kutu laba-laba tanaman,\nfujimite 5 ec,\nakarisida cabai,\nakarisida tomat,\npengendali hama tungau,\nobat daun keriting akibat tungau,', 'Fujimite 5 EC merupakan pestisida akarisida yang digunakan untuk mengendalikan hama tungau merah, tungau kuning, dan tungau laba-laba pada tanaman cabai, jeruk, tomat, apel, dan anggur. Produk ini efektif sebagai akarisida tungau tanaman, obat tungau merah, pembasmi tungau kuning, serta pengendali hama kutu laba-laba yang menyebabkan daun keriting, daun menguning, bercak daun, dan gangguan pertumbuhan tanaman.', '210.000', '5', '100 ml', '', '', '', '');
