INSERT INTO `dataproduk` (`COL 1`, `COL 2`, `COL 3`, `COL 4`, `COL 5`, `COL 6`, `COL 7`, `COL 8`, `COL 9`, `COL 10`, `COL 11`, `COL 12`, `COL 13`, `COL 14`, `COL 15`, `COL 16`, `COL 17`) VALUES
('189', 'Bactocyn 150 AL', 'Bakterisida', 'Cabai, Padi, Kubis, Tembakau', 'Vegetatif, Generatif', 'Layu Bakteri, Hawar Daun Bakteri, Bercak Daun Bakteri, Busuk Hitam', 'Tanah, Sawah, Lahan Terbuka', 'Cabai 1â€“2 ml/L air; Padi 0,8â€“1 ml/L air; Kubis 1,5â€“2 ml/L air', 'bakterisida tanaman\nobat hawar daun bakteri\nobat layu bakteri\npengendali bercak bakteri\npestisida bakteri tanaman\nbactocyn 150 al\nbakterisida cabai\nbakterisida padi\nobat penyakit bakteri tanaman\npengendali infeksi bakteri', 'Bactocyn 150 AL merupakan pestisida bakterisida sistemik berbahan aktif Copper Hydroxide 150 g/L yang digunakan untuk mengendalikan layu bakteri, hawar daun bakteri, bercak daun bakteri, dan busuk hitam pada tanaman cabai, padi, kubis, dan tembakau. Produk ini berfungsi sebagai bakterisida tanaman, obat hawar daun bakteri, obat layu bakteri, serta pengendali infeksi bakteri yang menyebabkan daun menguning, bercak daun, tanaman layu, dan penurunan hasil panen. Produk juga memiliki aktivitas sebagai fungisida sehingga mampu memberikan perlindungan yang lebih luas terhadap penyakit tanaman.', '55.000', '7', '100 ml', '', '', '', ''),
('190', 'Sanmite 15 SC', 'Akarisida', 'Cabai, Tomat, Jeruk, Apel, Anggur', 'Vegetatif, Generatif', 'Tungau Merah, Tungau Kuning, Tungau Laba-laba', 'Tanah, Lahan Terbuka, Greenhouse', '0,5â€“1 ml/L air', 'akarisida tungau\nobat tungau merah\npembasmi tungau kuning\npestisida tungau tanaman\npengendali hama tungau\nsanmite 15 sc\nakarisida cabai\nakarisida tomat\nobat daun keriting akibat tungau\npembasmi kutu laba-laba tanaman', 'Sanmite 15 SC merupakan pestisida akarisida berbentuk Suspension Concentrate (SC) yang digunakan untuk mengendalikan tungau merah, tungau kuning, dan tungau laba-laba pada tanaman cabai, tomat, jeruk, apel, dan anggur. Produk ini digunakan sebagai akarisida tungau tanaman, obat tungau merah, pembasmi tungau kuning, serta pengendali hama tungau yang menyebabkan daun keriting, daun menguning, bercak daun, dan penurunan pertumbuhan tanaman. Formulasi SC memberikan daya lekat yang baik sehingga cocok diaplikasikan pada fase vegetatif maupun generatif untuk pengendalian populasi tungau', '185.000', '5', '100 ml', '', '', '', '');
